/**
 * Destination Account Section Component
 * Handles payment method selection and conditional fields (Mobile Money, Wallet)
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import MobileMoneyFields from './MobileMoneyFields';
import WalletFields from './WalletFields';
import BankFields from './BankFields';
import RecipientNameFields from './RecipientNameFields';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';

const DestinationAccountSection = ({
  payoutData,
  handleInputChange,
  formErrors,
  isValidatingAccount,
  accountDetailsFetched,
  selectedCountry,
  onFetchMobileMoneyAccountDetails,
  onFetchBankAccountDetails,
  setPayoutData,
  setFormErrors,
  onWalletRecipientSelected, // Callback for wallet recipient selection
}) => {
  const { t } = useTranslation();

  return (
    <div className="disbursement-section" data-tour="disbursements-destination-account" style={{
      padding: '24px',
      backgroundColor: 'var(--card)',
      borderRadius: 'var(--radius-lg)',
      border: '1px solid var(--border-primary)'
    }}>
      <h4 className="section-title" style={{
        margin: '0 0 20px 0',
        fontSize: '16px',
        fontWeight: '600',
        color: 'var(--text-primary)',
        display: 'flex',
        alignItems: 'center',
        gap: '8px'
      }}>
        <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'var(--accent)' }}>
          send
        </span>
        {t('destinationAccount', { ns: 'disbursements', defaultValue: 'Destination Account' })}
      </h4>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        {/* Payment Method Selection - Horizontal Segmented Picker */}
        <div data-tour="disbursements-payment-method" style={{ marginBottom: '8px' }}>
          <label className="form-label" style={{
            marginBottom: '12px',
            display: 'block',
            fontSize: '14px',
            fontWeight: '600',
            color: 'var(--text-secondary)'
          }}>
            {t('paymentMethod', { ns: 'disbursements' })}
          </label>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(120px, 1fr))',
            gap: '12px',
            backgroundColor: 'var(--bg-secondary)',
            padding: '6px',
            borderRadius: 'var(--radius-lg)',
            border: '1px solid var(--border-secondary)'
          }}>
            {[
              { id: 'Mobile Money', label: t('mobileMoney', { ns: 'disbursements' }), icon: 'phone_iphone', color: '#007bff' },
              { id: 'Wallet', label: t('wallet', { ns: 'disbursements' }), icon: 'account_balance_wallet', color: '#28a745' },
              { id: 'Bank', label: t('bank', { ns: 'disbursements' }), icon: 'account_balance', color: '#6f42c1' }
            ].map((method) => {
              const isActive = payoutData.paymentMethod === method.id ||
                (method.id === 'Mobile Money' && payoutData.paymentMethod === 'MOMO') ||
                (method.id === 'Wallet' && payoutData.paymentMethod === 'WALLET') ||
                (method.id === 'Bank' && payoutData.paymentMethod === 'BANK');

              return (
                <button
                  key={method.id}
                  type="button"
                  onClick={() => handleInputChange({ target: { name: 'paymentMethod', value: method.id } })}
                  style={{
                    display: 'flex',
                    flexDirection: 'column',
                    alignItems: 'center',
                    justifyContent: 'center',
                    gap: '8px',
                    padding: '12px 8px',
                    border: 'none',
                    borderRadius: 'var(--radius-md)',
                    cursor: 'pointer',
                    transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                    backgroundColor: isActive ? 'var(--accent)' : 'transparent',
                    color: isActive ? 'white' : 'var(--text-muted)',
                    boxShadow: isActive ? '0 4px 12px rgba(0, 123, 255, 0.25)' : 'none',
                    transform: isActive ? 'translateY(-2px)' : 'translateY(0)',
                  }}
                  onMouseEnter={(e) => {
                    if (!isActive) {
                      e.currentTarget.style.backgroundColor = 'rgba(0, 0, 0, 0.02)';
                      e.currentTarget.style.color = 'var(--text-primary)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (!isActive) {
                      e.currentTarget.style.backgroundColor = 'transparent';
                      e.currentTarget.style.color = 'var(--text-muted)';
                    }
                  }}
                >
                  <span className="material-symbols-outlined" style={{
                    fontSize: '24px',
                    color: isActive ? 'white' : 'inherit',
                    transition: 'color 0.3s ease',
                    filter: isActive ? 'drop-shadow(0 2px 4px rgba(0, 0, 0, 0.2))' : 'none'
                  }}>
                    {method.icon}
                  </span>
                  <span style={{
                    fontSize: '13px',
                    fontWeight: isActive ? '700' : '500',
                    textAlign: 'center',
                    letterSpacing: isActive ? '0.3px' : 'normal'
                  }}>
                    {method.label}
                  </span>
                </button>
              );
            })}
          </div>
          {formErrors.paymentMethod && (
            <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '8px' }}>
              {formErrors.paymentMethod}
            </p>
          )}
        </div>

        {/* Mobile Money Fields */}
        {(payoutData.paymentMethod === 'Mobile Money' || payoutData.paymentMethod === 'MOMO') && (
          <MobileMoneyFields
            payoutData={payoutData}
            handleInputChange={handleInputChange}
            formErrors={formErrors}
            isValidatingAccount={isValidatingAccount}
            accountDetailsFetched={accountDetailsFetched}
            selectedCountry={selectedCountry}
            onFetchAccountDetails={onFetchMobileMoneyAccountDetails}
            setPayoutData={setPayoutData}
          />
        )}

        {/* Wallet Fields */}
        {(payoutData.paymentMethod === 'Wallet' || payoutData.paymentMethod === 'WALLET') && (
          <WalletFields
            payoutData={payoutData}
            handleInputChange={handleInputChange}
            formErrors={formErrors}
            setPayoutData={setPayoutData}
            setFormErrors={setFormErrors}
            onRecipientSelected={onWalletRecipientSelected}
          />
        )}

        {/* Bank Fields */}
        {(payoutData.paymentMethod === 'Bank' || payoutData.paymentMethod === 'BANK') && (
          <BankFields
            payoutData={payoutData}
            handleInputChange={handleInputChange}
            formErrors={formErrors}
            selectedCountry={selectedCountry}
            isValidatingAccount={isValidatingAccount}
            accountDetailsFetched={accountDetailsFetched}
            onFetchAccountDetails={onFetchBankAccountDetails}
          />
        )}

        {/* Recipient Name Fields - Only for Mobile Money (Bank has name fields in BankFields) */}
        {(payoutData.paymentMethod === 'Mobile Money' || payoutData.paymentMethod === 'MOMO') && (
          <RecipientNameFields
            payoutData={payoutData}
            handleInputChange={handleInputChange}
            formErrors={formErrors}
            accountDetailsFetched={accountDetailsFetched}
            isWalletPayment={false}
          />
        )}
      </div>
    </div>
  );
};

export default DestinationAccountSection;

