/**
 * Progress Indicator Component
 * Shows step number and completion status for form sections
 */

import React from 'react';

const ProgressIndicator = ({ stepNumber, isActive, isCompleted, label }) => {
  return (
    <div style={{
      display: 'flex',
      alignItems: 'center',
      gap: '12px',
      marginBottom: '16px'
    }}>
      <div
        style={{
          width: '32px',
          height: '32px',
          borderRadius: '50%',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          backgroundColor: isCompleted
            ? 'var(--success)'
            : isActive
            ? 'var(--accent)'
            : 'var(--bg-secondary)',
          color: isCompleted || isActive
            ? 'white'
            : 'var(--text-secondary)',
          fontSize: '14px',
          fontWeight: '600',
          transition: 'all 0.3s ease',
          border: isActive ? '2px solid var(--accent)' : 'none',
          boxShadow: isActive ? '0 0 0 3px rgba(0, 123, 255, 0.1)' : 'none'
        }}
      >
        {isCompleted ? (
          <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
            check
          </span>
        ) : (
          stepNumber
        )}
      </div>
      <span style={{
        fontSize: '16px',
        fontWeight: isActive ? '600' : '500',
        color: isActive || isCompleted
          ? 'var(--text-primary)'
          : 'var(--text-secondary)'
      }}>
        {label}
      </span>
    </div>
  );
};

export default ProgressIndicator;
