/**
 * Purpose Section Component
 * Handles purpose/narration input (shown at the end, hidden for wallet payments)
 */

import React from 'react';
import { useTranslation } from 'react-i18next';

const PurposeSection = ({
  payoutData,
  handleInputChange,
  formErrors,
}) => {
  const { t } = useTranslation();
  
  // Hide purpose field for wallet payments (same as TransferFundsModal)
  const isWalletPayment = payoutData.paymentMethod === 'Wallet' || payoutData.paymentMethod === 'WALLET';

  // Don't render at all for wallet payments
  if (isWalletPayment) {
    return null;
  }

  return (
    <div className="disbursement-section" data-tour="disbursements-purpose" style={{
      padding: '24px',
      backgroundColor: 'var(--card)',
      borderRadius: 'var(--radius-lg)',
      border: '1px solid var(--border-primary)'
    }}>
      <h4 className="section-title" style={{
        margin: '0 0 20px 0',
        fontSize: '16px',
        fontWeight: '600',
        color: 'var(--text-primary)',
        display: 'flex',
        alignItems: 'center',
        gap: '8px'
      }}>
        <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'var(--accent)' }}>
          description
        </span>
        {t('purposeNarration', { ns: 'disbursements' })}
      </h4>
      <div>
        <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
          {t('purposeNarration', { ns: 'disbursements' })}
        </label>
        <textarea
          name="purpose"
          value={payoutData.purpose || ''}
          onChange={handleInputChange}
          placeholder={t('enterPaymentPurpose', { ns: 'disbursements' })}
          rows={4}
          className="small-search input-large"
          style={{
            width: '100%',
            padding: '12px 16px',
            border: '1px solid var(--border-secondary)',
            borderRadius: 'var(--radius-md)',
            fontSize: '14px',
            backgroundColor: 'var(--bg-input)',
            color: 'var(--text-primary)',
            transition: 'all var(--transition-base)',
            fontFamily: 'inherit',
            resize: 'vertical',
            minHeight: '100px',
            lineHeight: '1.5'
          }}
          onFocus={(e) => e.target.style.borderColor = 'var(--accent)'}
          onBlur={(e) => e.target.style.borderColor = 'var(--border-secondary)'}
        />
        {formErrors.purpose && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
            {formErrors.purpose}
          </p>
        )}
      </div>
    </div>
  );
};

export default PurposeSection;

