/**
 * Bank Fields Component
 * Handles bank account details for bank disbursements
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import { FlagIcon } from '@/shared/components';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

import { GHANA_BANKS } from '@/features/payment-methods/constants';

const BankFields = ({
  payoutData,
  handleInputChange,
  formErrors,
  selectedCountry,
  isValidatingAccount,
  accountDetailsFetched,
  onFetchAccountDetails,
}) => {
  const { t } = useTranslation();

  const isFetchDisabled = isValidatingAccount || accountDetailsFetched || !payoutData.accountNumber?.trim() || !payoutData.bankCode;

  const handleBankChange = (e) => {
    const selectedBank = GHANA_BANKS.find(bank => bank.value === e.target.value);
    if (selectedBank) {
      // Update both bankCode and bankName in the parent state
      handleInputChange({ target: { name: 'bankCode', value: selectedBank.value } });
      handleInputChange({ target: { name: 'bankName', value: selectedBank.label } });
    } else {
      handleInputChange({ target: { name: 'bankCode', value: '' } });
      handleInputChange({ target: { name: 'bankName', value: '' } });
    }
  };

  return (
    <>
      {/* Bank Selection */}
      <div data-tour="disbursements-bank-selection" style={{ marginBottom: '16px' }}>
        <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
          {t('selectBank', { ns: 'disbursements', defaultValue: 'Select Bank' })}
        </label>
        <CustomSelect
          name="bankCode"
          value={payoutData.bankCode || ''}
          onChange={handleBankChange}
          options={GHANA_BANKS.map(bank => ({
            value: bank.value,
            label: (
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <div style={{
                  width: '24px',
                  height: '24px',
                  borderRadius: '4px',
                  overflow: 'hidden',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  backgroundColor: '#fff',
                  border: '1px solid var(--border-secondary)',
                  flexShrink: 0
                }}>
                  <img
                    src={`/banklogos/${bank.value.toLowerCase()}.svg`}
                    alt={bank.label}
                    style={{
                      width: '100%',
                      height: '100%',
                      objectFit: 'contain'
                    }}
                    onError={(e) => {
                      const currentSrc = e.target.src;
                      if (currentSrc.endsWith('.svg')) {
                        e.target.src = currentSrc.replace('.svg', '.png');
                      } else if (currentSrc.endsWith('.png')) {
                        e.target.src = currentSrc.replace('.png', '.ico');
                      } else {
                        e.target.style.display = 'none';
                        const parent = e.target.parentElement;
                        if (parent) {
                          parent.innerHTML = '<span class="material-symbols-outlined" style="font-size: 16px; color: var(--text-muted)">account_balance</span>';
                        }
                      }
                    }}
                  />
                </div>
                <span>{bank.label}</span>
              </div>
            )
          }))}
          placeholder={t('chooseBank', { ns: 'disbursements', defaultValue: 'Choose a bank' })}
          error={formErrors.bankCode}
          showCheckmark={false}
        />
      </div>

      {/* Account Number (Now at the top) */}
      <div data-tour="disbursements-account-number">
        <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
          {t('accountNumber', { ns: 'disbursements', defaultValue: 'Bank Account Number' })}
        </label>
        <input
          type="text"
          name="accountNumber"
          value={payoutData.accountNumber || ''}
          onChange={handleInputChange}
          placeholder={t('enterBankAccountNumber', { ns: 'disbursements', defaultValue: 'Enter bank account number' })}
          className="small-search input-large"
          style={{
            width: '100%',
            padding: '12px 16px',
            border: '1px solid var(--border-secondary)',
            borderRadius: 'var(--radius-md)',
            fontSize: '14px',
            backgroundColor: 'var(--bg-input)',
            color: 'var(--text-primary)',
            transition: 'all var(--transition-base)'
          }}
          onFocus={(e) => e.target.style.borderColor = 'var(--accent)'}
          onBlur={(e) => e.target.style.borderColor = 'var(--border-secondary)'}
        />
        {formErrors.accountNumber && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
            {formErrors.accountNumber}
          </p>
        )}
      </div>

      {/* Fetch Account Details Button */}
      <div style={{ marginTop: '16px', marginBottom: '8px' }}>
        <button
          type="button"
          onClick={onFetchAccountDetails}
          disabled={isFetchDisabled}
          className="fetch-button"
          style={{
            padding: '10px 16px',
            borderRadius: 'var(--radius-md)',
            border: '1px solid var(--border-secondary)',
            backgroundColor: isFetchDisabled ? 'var(--bg-tertiary)' : 'var(--accent)',
            color: isFetchDisabled ? 'var(--text-muted)' : 'var(--text-inverse)',
            fontSize: '13px',
            fontWeight: 600,
            cursor: isFetchDisabled ? 'not-allowed' : 'pointer',
            transition: 'all var(--transition-base)',
            display: 'inline-flex',
            alignItems: 'center',
            gap: '6px',
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
            {isValidatingAccount ? 'hourglass_top' : accountDetailsFetched ? 'check_circle' : 'badge'}
          </span>
          {isValidatingAccount
            ? t('fetching', { ns: 'disbursements', defaultValue: 'Fetching...' })
            : accountDetailsFetched
              ? t('detailsFetched', { ns: 'disbursements', defaultValue: 'Details Fetched' })
              : t('fetchAccountDetails', {
                ns: 'disbursements',
                defaultValue: 'Fetch Account Details',
              })}
        </button>
      </div>

      {/* Fetched Details Section */}
      {(accountDetailsFetched || payoutData.accountName || payoutData.firstName) && (
        <div 
          id="verified-details-box"
          style={{
            marginTop: '24px',
            padding: '24px',
            backgroundColor: 'rgba(0, 123, 255, 0.04)',
            borderRadius: 'var(--radius-xl)',
            border: '1px solid var(--accent)',
            borderLeft: '4px solid var(--accent)',
            animation: 'fadeIn 0.4s ease-out',
            display: 'block', // Force display
            visibility: 'visible',
            opacity: 1
          }}
        >
          <h5 style={{
            margin: '0 0 16px 0',
            fontSize: '14px',
            fontWeight: '700',
            color: 'var(--accent)',
            display: 'flex',
            alignItems: 'center',
            gap: '8px',
            textTransform: 'uppercase',
            letterSpacing: '0.5px'
          }}>
            <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>
              verified_user
            </span>
            {t('verifiedAccountDetails', { ns: 'disbursements', defaultValue: 'Verified Account Details' })}
          </h5>

          {/* Bank Name */}
          <div>
            <label className="form-label" style={{ marginBottom: '6px', display: 'block', fontSize: '12px', color: 'var(--text-muted)' }}>
              {t('bankName', { ns: 'disbursements', defaultValue: 'Bank Name' })}
            </label>
            <div style={{
              padding: '10px 14px',
              backgroundColor: 'var(--bg-card)',
              borderRadius: 'var(--radius-md)',
              border: '1px solid var(--border-primary)',
              fontSize: '14px',
              fontWeight: 500,
              color: 'var(--text-primary)'
            }}>
              {payoutData.bankName}
            </div>
          </div>

          {/* Account Holder Name */}
          <div className="name-fields-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px' }}>
            <div>
              <label className="form-label" style={{ marginBottom: '6px', display: 'block', fontSize: '12px', color: 'var(--text-muted)' }}>
                {t('firstName', { ns: 'disbursements' })}
              </label>
              <div style={{
                padding: '10px 14px',
                backgroundColor: 'var(--bg-card)',
                borderRadius: 'var(--radius-md)',
                border: '1px solid var(--border-primary)',
                fontSize: '14px',
                fontWeight: 500,
                color: 'var(--text-primary)'
              }}>
                {payoutData.firstName}
              </div>
            </div>
            <div>
              <label className="form-label" style={{ marginBottom: '6px', display: 'block', fontSize: '12px', color: 'var(--text-muted)' }}>
                {t('surname', { ns: 'disbursements' })}
              </label>
              <div style={{
                padding: '10px 14px',
                backgroundColor: 'var(--bg-card)',
                borderRadius: 'var(--radius-md)',
                border: '1px solid var(--border-primary)',
                fontSize: '14px',
                fontWeight: 500,
                color: 'var(--text-primary)'
              }}>
                {payoutData.surname}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Recipient Phone Number (Moved below fetch to prioritize account number) */}
      <div data-tour="disbursements-phone-number" style={{ marginTop: '24px' }}>
        <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
          {t('recipientPhoneNumber', { ns: 'disbursements', defaultValue: 'Recipient Phone Number' })}
        </label>
        <div className="phone-input phone-input-row" style={{ display: 'flex', gap: '12px', alignItems: 'stretch' }}>
          <div className="phone-input-country" style={{ flex: '0 0 auto', width: '160px', minWidth: '160px', position: 'relative' }}>
            <span style={{
              position: 'absolute',
              left: '14px',
              top: '50%',
              transform: 'translateY(-50%)',
              pointerEvents: 'none',
              zIndex: 1,
              display: 'flex',
              alignItems: 'center'
            }}>
              <FlagIcon countryCode={selectedCountry?.code} size="1.2em" />
            </span>
            <CustomSelect
              name="countryCode"
              value={payoutData.countryCode}
              onChange={handleInputChange}
              options={countries.map((country) => ({
                value: country.dialCode,
                label: country.dialCode,
                name: country.name,
                countryCode: country.code,
              }))}
              searchable
              showCheckmark={false}
              style={{ width: '100%' }}
            />
          </div>
          <input
            type="tel"
            name="phoneNumber"
            value={payoutData.phoneNumber || ''}
            onChange={(e) => {
              // Only allow numeric characters
              const numericValue = e.target.value.replace(/[^\d]/g, '');
              // Directly update the event target's value property
              e.target.value = numericValue;
              handleInputChange(e);
            }}
            placeholder={t('phoneNumberPlaceholder', { ns: 'disbursements' })}
            className="small-search input-flex"
            style={{
              flex: 1,
              minWidth: '200px',
              padding: '12px 16px',
              border: '1px solid var(--border-secondary)',
              borderRadius: 'var(--radius-md)',
              fontSize: '14px',
              backgroundColor: 'var(--bg-input)',
              color: 'var(--text-primary)',
              transition: 'all var(--transition-base)',
              height: 'auto'
            }}
            onFocus={(e) => e.target.style.borderColor = 'var(--accent)'}
            onBlur={(e) => e.target.style.borderColor = 'var(--border-secondary)'}
            inputMode="numeric"
            pattern="[0-9]*"
          />
        </div>
        {(formErrors.countryCode || formErrors.phoneNumber) && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
            {formErrors.phoneNumber || formErrors.countryCode}
          </p>
        )}
      </div>

      {/* Hidden Fields for form consistency */}
      <input type="hidden" name="bankbranchCode" value={payoutData.bankbranchCode || ''} />
    </>
  );
};

export default BankFields;
