/**
 * Disbursement Utility Functions
 * 
 * Shared utilities for disbursement-related operations across the application.
 */

/**
 * Normalize channel name to standard format
 * 
 * Converts various channel name formats (e.g., "Mobile Money", "MOBILE_MONEY")
 * to the canonical uppercase format used across all iSmartPay services.
 * The canonical value for mobile money is "MOMO".
 *
 * @param {string} channel - Raw channel value (can be string, null, or undefined)
 * @returns {string} Normalized channel value
 *
 * @example
 * normalizeChannel('Mobile Money') // Returns 'MOMO'
 * normalizeChannel('MOBILE_MONEY') // Returns 'MOMO'
 * normalizeChannel('bank') // Returns 'BANK'
 * normalizeChannel(null) // Returns 'MOMO'
 */
export const normalizeChannel = (channel) => {
  if (!channel) { return 'MOBILE_MONEY'; }

  const normalized = channel.toString().toUpperCase().trim();

  if (normalized === 'MOBILE MONEY' || normalized === 'MOBILE_MONEY' || normalized === 'MOMO') {
    return 'MOBILE_MONEY';
  }

  if (normalized === 'BANK') {
    return 'BANK';
  }

  if (normalized === 'WALLET') {
    return 'WALLET';
  }

  return normalized;
};

