/**
 * Bulk Disbursement Upload Section Component
 * 
 * Handles file upload UI including template download, drag-and-drop,
 * and file format instructions.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import { LoadingSpinner } from '@/shared/components';
import '/styles/components/disbursements/BulkDisbursementEnhanced.css';

const BulkDisbursementUploadSection = ({ 
  isUploading, 
  onFileUpload, 
  onDownloadTemplate,
  isMobile,
  isTablet 
}) => {
  const { t } = useTranslation();

  return (
    <div className="bulk-disbursement-enhanced">
      {/* Header Section */}
      <div className="bulk-disbursement-header">
        <h2 className="bulk-disbursement-title">Bulk Disbursement</h2>
        <p className="bulk-disbursement-subtitle">Upload multiple transactions at once for faster processing</p>
      </div>

      {/* Template Download Section */}
      <div className="bulk-template-section">
        <div className="bulk-template-card" onClick={onDownloadTemplate}>
          <div className="bulk-template-icon">
            <span className="material-symbols-outlined">description</span>
          </div>
          <div className="bulk-template-content">
            <div className="bulk-template-title">Download CSV Template</div>
            <div className="bulk-template-description">Get the required format for your bulk upload</div>
          </div>
        </div>
      </div>

      {/* Upload Area */}
      <div className="bulk-upload-area">
        <div
          className={`bulk-upload-zone ${isUploading ? 'bulk-upload-loading' : ''}`}
          onDragOver={(e) => {
            e.preventDefault();
            e.stopPropagation();
            if (!isUploading) {
              e.currentTarget.classList.add('drag-over');
            }
          }}
          onDragEnter={(e) => {
            e.preventDefault();
            e.stopPropagation();
            if (!isUploading) {
              e.currentTarget.classList.add('drag-over');
            }
          }}
          onDragLeave={(e) => {
            e.preventDefault();
            e.stopPropagation();
            e.currentTarget.classList.remove('drag-over');
          }}
          onDrop={(e) => {
            e.preventDefault();
            e.stopPropagation();
            e.currentTarget.classList.remove('drag-over');
            if (!isUploading) {
              const files = e.dataTransfer.files;
              if (files.length > 0) {
                onFileUpload({ target: { files: [files[0]] } });
              }
            }
          }}
        >
          <input
            type="file"
            id="bulk-disbursement-file"
            accept=".csv,.xlsx,.xls,text/csv,application/vnd.ms-excel,application/vnd.openxmlformats-officedocument.spreadsheetml.sheet"
            onChange={onFileUpload}
            style={{ display: 'none' }}
            disabled={isUploading}
          />
          <label htmlFor="bulk-disbursement-file" style={{ cursor: isUploading ? 'not-allowed' : 'pointer', display: 'block' }}>
            <div className="bulk-upload-icon-wrapper">
              <span className="material-symbols-outlined bulk-upload-icon">
                {isUploading ? 'refresh' : 'cloud_upload'}
              </span>
            </div>
            
            <h3 className="bulk-upload-title">
              {isUploading ? 'Processing File...' : 'Upload Your File'}
            </h3>
            
            <p className="bulk-upload-description">
              {isUploading 
                ? 'Please wait while we process your file'
                : 'Drag and drop your CSV file here, or click to browse'
              }
            </p>
            
            {!isUploading && (
              <button className="bulk-upload-button" onClick={() => document.getElementById('bulk-disbursement-file').click()}>
                <span className="material-symbols-outlined">folder_open</span>
                Choose File
              </button>
            )}
          </label>
        </div>
      </div>

      {/* Instructions Section */}
      <div className="bulk-instructions-section">
        <div className="bulk-instructions-header">
          <div className="bulk-instructions-icon">
            <span className="material-symbols-outlined">info</span>
          </div>
          File Requirements
        </div>
        
        <div className="bulk-instructions-grid">
          <div className="bulk-instruction-item">
            <div className="bulk-instruction-bullet">1</div>
            <div className="bulk-instruction-text">
              Include recipient name, phone number, and amount for each payment
            </div>
          </div>
          
          <div className="bulk-instruction-item">
            <div className="bulk-instruction-bullet">2</div>
            <div className="bulk-instruction-text">
              Use Ghana phone numbers (e.g., 0201234567 or +233201234567)
            </div>
          </div>
          
          <div className="bulk-instruction-item">
            <div className="bulk-instruction-bullet">3</div>
            <div className="bulk-instruction-text">
              Amount should be in GHS (e.g., 50.00 for 50 Ghana Cedis)
            </div>
          </div>
          
          <div className="bulk-instruction-item">
            <div className="bulk-instruction-bullet">4</div>
            <div className="bulk-instruction-text">
              Maximum 1000 transactions per file
            </div>
          </div>
          
          <div className="bulk-instruction-item">
            <div className="bulk-instruction-bullet">5</div>
            <div className="bulk-instruction-text">
              File must be in CSV format (.csv)
            </div>
          </div>
          
          <div className="bulk-instruction-item">
            <div className="bulk-instruction-bullet">6</div>
            <div className="bulk-instruction-text">
              Double-check all information before uploading
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BulkDisbursementUploadSection;

