/**
 * Custom hook for account validation logic
 */

import { useState, useEffect, useCallback } from 'react';
import { disbursementService } from '@/features/disbursements/services';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { mapProviderToApiValue, mapProviderToIVerifyOperator, extractAccountName, parseAccountName, isSuccessResponse } from '@/features/disbursements/utils/helpers.js';
import { createTokenSnapshot, restoreTokensIfNeeded, ensureTokensPreserved } from '@/shared/utils/token-protection.js';
import logger from '@/shared/utils/logger.js';

export const useAccountValidation = (payoutData, paymentMethod, setPayoutData, setFormErrors, showError, success, t) => {
  const [isValidatingAccount, setIsValidatingAccount] = useState(false);
  const [accountDetailsFetched, setAccountDetailsFetched] = useState(false);

  // Auto-fetch disabled - account details will only be fetched manually via button click
  // after all required fields (payment method, amount, purpose, phone number, provider) are filled

  // Manual fetch mobile money account details
  const fetchMobileMoneyAccountDetails = useCallback(async () => {
    if (paymentMethod !== 'Mobile Money' && paymentMethod !== 'MOMO') {
      return;
    }

    // Validate all required fields before fetching
    if (!payoutData.phoneNumber.trim()) {
      setFormErrors((prev) => ({
        ...prev,
        phoneNumber: t('enterMobileMoneyNumber', { ns: 'disbursements' }),
      }));
      showError(t('enterMobileMoneyNumber', { ns: 'disbursements' }));
      return;
    }

    if (!payoutData.provider) {
      setFormErrors((prev) => ({
        ...prev,
        provider: t('selectProvider', { ns: 'disbursements' }),
      }));
      showError(t('selectProvider', { ns: 'disbursements' }));
      return;
    }

    if (!payoutData.paymentMethod || payoutData.paymentMethod.trim() === '') {
      showError(t('selectPaymentMethodFirst', { ns: 'disbursements', defaultValue: 'Please select payment method first' }));
      return;
    }

    if (!payoutData.amount || payoutData.amount.toString().trim() === '' || parseFloat(payoutData.amount) <= 0) {
      setFormErrors((prev) => ({
        ...prev,
        amount: t('fillAmountFirst', { ns: 'disbursements', defaultValue: 'Please fill in amount first' }),
      }));
      showError(t('fillAmountFirst', { ns: 'disbursements', defaultValue: 'Please fill in amount first' }));
      return;
    }

    setIsValidatingAccount(true);
    // Create token snapshot before API call to protect against accidental clearing
    const tokenSnapshot = createTokenSnapshot();

    try {
      // Format phone number for iVerify API (remove country code, ensure starts with 0)
      let mobileNumber = payoutData.phoneNumber.trim();

      // Remove country code if present
      if (mobileNumber.startsWith('+233')) {
        mobileNumber = mobileNumber.substring(4); // Remove "+233"
      } else if (mobileNumber.startsWith('233')) {
        mobileNumber = mobileNumber.substring(3); // Remove "233"
      }

      // Remove leading zero if it exists, then add it back to ensure format is "0XXXXXXXXX"
      if (mobileNumber.startsWith('0')) {
        mobileNumber = mobileNumber.substring(1);
      }

      // Add zero at the beginning
      mobileNumber = '0' + mobileNumber;

      // Map provider to iVerify operator (Telecel -> vodafone, MTN -> mtn)
      const operator = mapProviderToIVerifyOperator(payoutData.provider);

      // Call iVerify API
      const response = await disbursementService.verifyMobileMoneyIdentity({
        mobileNumber,
        operator,
      });

      // Ensure tokens are still present after successful API call
      ensureTokensPreserved(() => {
        logger.warn('Tokens missing after verifyMobileMoneyIdentity - attempting restore');
        restoreTokensIfNeeded(tokenSnapshot);
      });

      // Check if response is successful
      if (response?.status === 'success' && response?.name) {
        // Parse the name into firstName and surname
        const verifiedName = response.name;
        const { firstName, surname } = parseAccountName(verifiedName);

        logger.info('Mobile Money validation successful, updating payoutData', {
          verifiedName,
          firstName,
          surname
        });

        setPayoutData((prev) => ({
          ...prev,
          firstName: firstName || prev.firstName,
          surname: surname || prev.surname,
          accountName: verifiedName,
        }));
        setAccountDetailsFetched(true);
        setFormErrors((prev) => {
          const next = { ...prev };
          delete next.phoneNumber;
          delete next.provider;
          return next;
        });
        success(
          t('accountValidated', {
            ns: 'disbursements',
            defaultValue: 'Account details fetched successfully.',
          })
        );
        return;
      }

      setAccountDetailsFetched(false);
      setPayoutData((prev) => ({
        ...prev,
        firstName: '',
        surname: '',
      }));

      showError(
        t('accountValidationFailed', {
          ns: 'disbursements',
          defaultValue: 'Unable to validate account details.',
        })
      );
    } catch (error) {
      logger.error('Failed to verify mobile money identity', { error });
      setAccountDetailsFetched(false);
      setPayoutData((prev) => ({
        ...prev,
        firstName: '',
        surname: '',
      }));

      showError(
        error?.message ||
        t('accountValidationFailed', {
          ns: 'disbursements',
          defaultValue: 'Unable to validate account details.',
        })
      );
    } finally {
      setIsValidatingAccount(false);
    }
  }, [payoutData, paymentMethod, setPayoutData, setFormErrors, showError, success, t]);

  // Manual fetch bank account details
  const fetchBankAccountDetails = useCallback(async () => {
    if (paymentMethod !== 'Bank' && paymentMethod !== 'BANK') {
      return;
    }

    if (!payoutData.bankCode) {
      setFormErrors((prev) => ({
        ...prev,
        bankCode: t('selectBankFirst', { ns: 'disbursements', defaultValue: 'Please select a bank first' }),
      }));
      showError(t('selectBankFirst', { ns: 'disbursements', defaultValue: 'Please select a bank first' }));
      return;
    }

    if (!payoutData.accountNumber?.trim()) {
      setFormErrors((prev) => ({
        ...prev,
        accountNumber: t('enterBankAccountNumber', { ns: 'disbursements', defaultValue: 'Please enter bank account number' }),
      }));
      showError(t('enterBankAccountNumber', { ns: 'disbursements', defaultValue: 'Please enter bank account number' }));
      return;
    }

    setIsValidatingAccount(true);
    // Create token snapshot before API call
    const tokenSnapshot = createTokenSnapshot();

    try {
      const response = await disbursementService.verifyBankIdentity({
        accountNumber: payoutData.accountNumber.trim(),
        bankCode: payoutData.bankCode,
      });

      // Ensure tokens are preserved
      ensureTokensPreserved(() => {
        logger.warn('Tokens missing after verifyBankIdentity - attempting restore');
        restoreTokensIfNeeded(tokenSnapshot);
      });

      if (response?.status === 'success') {
        const verifiedName = response.name || '';
        const { firstName, surname } = parseAccountName(verifiedName);
        const verifiedBankName = response.bank_name || payoutData.bankName;

        logger.info('Bank validation successful, updating payoutData', {
          verifiedName,
          verifiedBankName,
          firstName,
          surname
        });

        setPayoutData((prev) => ({
          ...prev,
          bankName: verifiedBankName,
          firstName: firstName || prev.firstName,
          surname: surname || prev.surname,
          accountName: verifiedName, // Required for bank validation schema
          accountHolderName: verifiedName, // For compatibility
        }));
        setAccountDetailsFetched(true);
        setFormErrors((prev) => {
          const next = { ...prev };
          delete next.accountNumber;
          return next;
        });

        success(
          t('accountValidated', {
            ns: 'disbursements',
            defaultValue: 'Bank account details fetched successfully.',
          })
        );
        return;
      }

      setAccountDetailsFetched(false);
      setPayoutData((prev) => ({
        ...prev,
        firstName: '',
        surname: '',
        bankName: '',
      }));

      showError(
        t('accountValidationFailed', {
          ns: 'disbursements',
          defaultValue: 'Unable to validate bank account details.',
        })
      );
    } catch (error) {
      logger.error('Failed to verify bank identity', { error });
      setAccountDetailsFetched(false);
      setPayoutData((prev) => ({
        ...prev,
        firstName: '',
        surname: '',
        bankName: '',
      }));

      showError(
        error?.message ||
        t('accountValidationFailed', {
          ns: 'disbursements',
          defaultValue: 'Unable to validate bank account details.',
        })
      );
    } finally {
      setIsValidatingAccount(false);
    }
  }, [payoutData, paymentMethod, setPayoutData, setFormErrors, showError, success, t]);

  return {
    isValidatingAccount,
    accountDetailsFetched,
    setAccountDetailsFetched,
    fetchMobileMoneyAccountDetails,
    fetchBankAccountDetails,
  };
};

