/**
 * Common Validation Schemas
 * 
 * Reusable Zod schemas for common validation patterns across the application.
 * These schemas ensure consistency and can be shared between client and server.
 */

import { z } from 'zod';
import { trimAndRequire, phoneNumberSchema, numericString } from './helpers.js';

/**
 * Common field schemas that can be reused across forms
 */

/**
 * Email schema with validation
 */
export const createEmailSchema = (t, options = {}) => {
  const { required = true, namespace = 'common' } = options;
  let schema = z.string().trim();
  
  if (required) {
    schema = schema.min(1, t('emailRequired', { ns: namespace, defaultValue: 'Email is required' }));
  }
  
  return schema.email(t('invalidEmail', { ns: namespace, defaultValue: 'Please enter a valid email address' }));
};

/**
 * Phone number schema
 */
export const createPhoneSchema = (t, options = {}) => {
  const { namespace = 'common' } = options;
  return phoneNumberSchema(
    t('invalidPhoneNumber', { ns: namespace, defaultValue: 'Please enter a valid phone number' }),
    t('phoneNumberLength', { ns: namespace, defaultValue: 'Phone number must be between 7 and 15 digits' })
  );
};

/**
 * Country code schema
 */
export const createCountryCodeSchema = (t, options = {}) => {
  const { namespace = 'common' } = options;
  return trimAndRequire(
    t('countryCodeRequired', { ns: namespace, defaultValue: 'Select a country code' })
  );
};

/**
 * Amount schema with min/max validation
 */
export const createAmountSchema = (t, options = {}) => {
  const {
    min = 0,
    max = 1_000_000,
    namespace = 'common',
    allowZero = false,
  } = options;

  return z
    .string()
    .trim()
    .transform((val) => (val === '' ? NaN : Number(val)))
    .refine((val) => !Number.isNaN(val), {
      message: t('invalidAmount', {
        ns: namespace,
        defaultValue: 'Please enter a valid amount',
      }),
    })
    .refine((val) => allowZero ? val >= 0 : val > 0, {
      message: t('amountPositive', {
        ns: namespace,
        defaultValue: 'Amount must be greater than zero',
      }),
    })
    .refine((val) => val <= max, {
      message: t('amountTooLarge', {
        ns: namespace,
        defaultValue: `Amount cannot exceed ${max.toLocaleString()}`,
      }),
    });
};

/**
 * Password schema with strength requirements
 */
export const createPasswordSchema = (t, options = {}) => {
  const {
    minLength = 8,
    requireUppercase = true,
    requireLowercase = true,
    requireNumber = true,
    requireSpecial = true,
    namespace = 'auth',
  } = options;

  let schema = z.string().min(minLength, t('passwordTooShort', {
    ns: namespace,
    defaultValue: `Password must be at least ${minLength} characters`,
  }));

  if (requireUppercase || requireLowercase || requireNumber || requireSpecial) {
    schema = schema.superRefine((val, ctx) => {
      if (requireUppercase && !/[A-Z]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainUppercase', {
            ns: namespace,
            defaultValue: 'Password must contain at least one uppercase letter',
          }),
        });
      }
      if (requireLowercase && !/[a-z]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainLowercase', {
            ns: namespace,
            defaultValue: 'Password must contain at least one lowercase letter',
          }),
        });
      }
      if (requireNumber && !/[0-9]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainNumber', {
            ns: namespace,
            defaultValue: 'Password must contain at least one number',
          }),
        });
      }
      if (requireSpecial && !/[^a-zA-Z0-9\s]/.test(val)) {
        ctx.addIssue({
          code: z.ZodIssueCode.custom,
          message: t('passwordMustContainSpecial', {
            ns: namespace,
            defaultValue: 'Password must contain at least one special character',
          }),
        });
      }
    });
  }

  return schema;
};

/**
 * Name schema (first name, last name, etc.)
 */
export const createNameSchema = (t, options = {}) => {
  const {
    fieldName = 'name',
    maxLength = 50,
    required = true,
    namespace = 'common',
  } = options;

  let schema = z.string().trim();

  if (required) {
    schema = schema.min(1, t(`${fieldName}Required`, {
      ns: namespace,
      defaultValue: `${fieldName} is required`,
    }));
  }

  return schema.max(maxLength, t(`${fieldName}TooLong`, {
    ns: namespace,
    defaultValue: `${fieldName} cannot exceed ${maxLength} characters`,
  }));
};

/**
 * OTP schema (6-digit code)
 */
export const createOtpSchema = (t, options = {}) => {
  const { namespace = 'auth', length = 6 } = options;
  return numericString(
    t('pleaseEnterValidOTP', { ns: namespace, defaultValue: 'Please enter a valid OTP' })
  ).refine(
    (val) => val.length === length,
    {
      message: t('pleaseEnterValidOTP', {
        ns: namespace,
        defaultValue: `OTP must be ${length} digits`,
      }),
    }
  );
};

/**
 * URL schema
 */
export const createUrlSchema = (t, options = {}) => {
  const { required = true, namespace = 'common' } = options;
  let schema = z.string().trim();

  if (required) {
    schema = schema.min(1, t('urlRequired', { ns: namespace, defaultValue: 'URL is required' }));
  }

  return schema.url(t('invalidUrl', { ns: namespace, defaultValue: 'Please enter a valid URL' }));
};

/**
 * Date schema
 */
export const createDateSchema = (t, options = {}) => {
  const {
    required = true,
    minDate,
    maxDate,
    namespace = 'common',
  } = options;

  let schema = z.coerce.date();

  if (required) {
    schema = schema.refine((val) => val instanceof Date && !isNaN(val.getTime()), {
      message: t('dateRequired', { ns: namespace, defaultValue: 'Date is required' }),
    });
  }

  if (minDate) {
    schema = schema.refine((val) => val >= minDate, {
      message: t('dateTooEarly', {
        ns: namespace,
        defaultValue: `Date must be after ${minDate.toLocaleDateString()}`,
      }),
    });
  }

  if (maxDate) {
    schema = schema.refine((val) => val <= maxDate, {
      message: t('dateTooLate', {
        ns: namespace,
        defaultValue: `Date must be before ${maxDate.toLocaleDateString()}`,
      }),
    });
  }

  return schema;
};

/**
 * Positive integer schema
 */
export const createPositiveIntegerSchema = (t, options = {}) => {
  const {
    min = 1,
    max = Number.MAX_SAFE_INTEGER,
    namespace = 'common',
  } = options;

  return z
    .number()
    .int(t('mustBeInteger', { ns: namespace, defaultValue: 'Must be a whole number' }))
    .min(min, t('mustBePositive', { ns: namespace, defaultValue: 'Must be a positive number' }))
    .max(max, t('valueTooLarge', { ns: namespace, defaultValue: 'Value is too large' }));
};

/**
 * Confirm password schema (validates password match)
 */
export const createConfirmPasswordSchema = (t, passwordValue, options = {}) => {
  const { namespace = 'auth' } = options;
  return z
    .string()
    .min(1, t('confirmPasswordRequired', {
      ns: namespace,
      defaultValue: 'Confirm password is required',
    }))
    .refine((val) => val === passwordValue, {
      message: t('passwordsDoNotMatch', {
        ns: namespace,
        defaultValue: 'Passwords do not match',
      }),
    });
};

/**
 * Optional string schema
 */
export const createOptionalStringSchema = (t, options = {}) => {
  const { maxLength = 255, namespace = 'common' } = options;
  return z
    .string()
    .trim()
    .max(maxLength, t('stringTooLong', {
      ns: namespace,
      defaultValue: `Text cannot exceed ${maxLength} characters`,
    }))
    .optional()
    .or(z.literal(''));
};

/**
 * Reference field schema (1-20 characters: alphanumeric, spaces, word characters, plus sign)
 * Pattern: ^[0-9a-zA-Z \w+]{1,20}$
 * Note: In Java, \w inside [] is word character class. In JS, we use [0-9a-zA-Z_\s+] to match the same.
 */
export const createReferenceSchema = (t, options = {}) => {
  const { required = true, namespace = 'common' } = options;
  // Matches: alphanumeric, underscore, spaces, plus sign (equivalent to Java [0-9a-zA-Z \w+])
  const referencePattern = /^[0-9a-zA-Z_\s+]{1,20}$/;
  
  let schema = z.string().trim();
  
  if (required) {
    schema = schema.min(1, t('referenceRequired', {
      ns: namespace,
      defaultValue: 'Reference is required',
    }));
  }
  
  return schema
    .max(20, t('referenceTooLong', {
      ns: namespace,
      defaultValue: 'Reference cannot exceed 20 characters',
    }))
    .refine((val) => !val || referencePattern.test(val), {
      message: t('referenceInvalid', {
        ns: namespace,
        defaultValue: 'Reference can only contain letters, numbers, spaces, underscores, and plus signs',
      }),
    });
};

/**
 * Narration field schema (1-256 characters: alphanumeric, spaces, word characters, plus sign)
 * Pattern: ^[0-9a-zA-Z \w+]{1,256}$
 * Note: In Java, \w inside [] is word character class. In JS, we use [0-9a-zA-Z_\s+] to match the same.
 */
export const createNarrationSchema = (t, options = {}) => {
  const { required = true, namespace = 'common' } = options;
  // Matches: alphanumeric, underscore, spaces, plus sign (equivalent to Java [0-9a-zA-Z \w+])
  const narrationPattern = /^[0-9a-zA-Z_\s+]{1,256}$/;
  
  let schema = z.string().trim();
  
  if (required) {
    schema = schema.min(1, t('narrationRequired', {
      ns: namespace,
      defaultValue: 'Narration is required',
    }));
  }
  
  return schema
    .max(256, t('narrationTooLong', {
      ns: namespace,
      defaultValue: 'Narration cannot exceed 256 characters',
    }))
    .refine((val) => !val || narrationPattern.test(val), {
      message: t('narrationInvalid', {
        ns: namespace,
        defaultValue: 'Narration can only contain letters, numbers, spaces, underscores, and plus signs',
      }),
    });
};

/**
 * Currency field schema (1-3 letters only, e.g., USD, GHS, EUR)
 * Pattern: ^[a-zA-Z]{1,3}$
 */
export const createCurrencySchema = (t, options = {}) => {
  const { required = true, namespace = 'common', allowedCurrencies } = options;
  const currencyPattern = /^[a-zA-Z]{1,3}$/;
  
  let schema = z.string().trim();
  
  if (required) {
    schema = schema.min(1, t('currencyRequired', {
      ns: namespace,
      defaultValue: 'Currency is required',
    }));
  }
  
  schema = schema
    .max(3, t('currencyTooLong', {
      ns: namespace,
      defaultValue: 'Currency code must be 1-3 letters',
    }))
    .refine((val) => !val || currencyPattern.test(val), {
      message: t('currencyInvalid', {
        ns: namespace,
        defaultValue: 'Currency must be 1-3 letters only (e.g., USD, GHS, EUR)',
      }),
    });
  
  if (allowedCurrencies && Array.isArray(allowedCurrencies)) {
    schema = schema.refine((val) => !val || allowedCurrencies.includes(val.toUpperCase()), {
      message: t('currencyNotAllowed', {
        ns: namespace,
        defaultValue: `Currency must be one of: ${allowedCurrencies.join(', ')}`,
      }),
    });
  }
  
  return schema;
};

/**
 * Amount field schema (numeric with optional decimal point)
 * Pattern: ^\d*\.?\d+$
 */
export const createAmountPatternSchema = (t, options = {}) => {
  const {
    required = true,
    namespace = 'common',
    min = 0,
    max = 1_000_000_000,
    allowZero = false,
  } = options;
  
  const amountPattern = /^\d+(\.\d+)?$/;
  
  let schema = z.string().trim();
  
  if (required) {
    schema = schema.min(1, t('amountRequired', {
      ns: namespace,
      defaultValue: 'Amount is required',
    }));
  }
  
  return schema
    .transform((val) => val.replace(/,/g, ''))
    .refine((val) => !val || amountPattern.test(val), {
      message: t('amountInvalidFormat', {
        ns: namespace,
        defaultValue: 'Amount must be a valid number (e.g., 100 or 100.50)',
      }),
    })
    .transform((val) => (val === '' ? NaN : Number(val)))
    .refine((val) => !Number.isNaN(val), {
      message: t('amountInvalid', {
        ns: namespace,
        defaultValue: 'Enter a valid amount',
      }),
    })
    .refine((val) => allowZero ? val >= 0 : val > 0, {
      message: t('amountPositive', {
        ns: namespace,
        defaultValue: 'Amount must be greater than zero',
      }),
    })
    .refine((val) => val <= max, {
      message: t('amountTooLarge', {
        ns: namespace,
        defaultValue: `Amount cannot exceed ${max.toLocaleString()}`,
      }),
    });
};

