/**
 * Disbursement Preview Modal Component
 * 
 * Modal dialog displaying a preview of disbursement transaction details
 * before submission. Shows recipient information, amount, fees, and allows
 * final confirmation before processing the payment.
 */

import React from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';

const DisbursementPreviewModal = ({
  open,
  onClose,
  payoutData,
  useDifferentNumber,
  onSubmit,
  feeData,
  isCheckingFee
}) => {
  const { t } = useTranslation();
  if (!open) {return null;}

  return createPortal(
    <>
      <div style={{
        position: 'fixed',
        inset: 0,
        backgroundColor: 'rgba(0,0,0,0.5)',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        zIndex: 10000,
        backdropFilter: 'blur(4px)'
      }}>
        <div style={{
          backgroundColor: 'var(--card)',
          borderRadius: 16,
          padding: 32,
          width: '100%',
          maxWidth: 600,
          maxHeight: '90vh',
          overflowY: 'auto',
          boxShadow: 'var(--shadow-xl)',
          animation: 'slideIn 0.3s ease-out'
        }}>
          <div style={{
            display: 'flex',
            justifyContent: 'space-between',
            alignItems: 'center',
            marginBottom: 24,
            paddingBottom: 16,
            borderBottom: '1px solid var(--border-primary)'
          }}>
            <h3 style={{
              margin: 0,
              color: 'var(--text-primary)',
              fontSize: '24px',
              fontWeight: 700,
              display: 'flex',
              alignItems: 'center',
              gap: '12px'
            }}>
              <span className="material-symbols-outlined" style={{ fontSize: '28px', color: 'var(--accent)' }}>
                visibility
              </span>
              {t('disbursementPreview', { ns: 'disbursements' })}
            </h3>
            <button
              type="button"
              onClick={onClose}
              style={{
                background: 'none',
                border: 'none',
                color: 'var(--text-muted)',
                cursor: 'pointer',
                padding: '8px',
                borderRadius: '8px',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                transition: 'all var(--transition-base)'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.backgroundColor = 'var(--bg-hover)';
                e.currentTarget.style.color = 'var(--text-primary)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.backgroundColor = 'transparent';
                e.currentTarget.style.color = 'var(--text-muted)';
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '24px' }}>
                close
              </span>
            </button>
          </div>

          {/* Preview Content */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {/* Personal Information */}
            <div style={{
              padding: '20px',
              backgroundColor: 'var(--bg-tertiary)',
              borderRadius: 'var(--radius-md)',
              border: '1px solid var(--border-primary)'
            }}>
              <h4 style={{
                margin: '0 0 16px 0',
                fontSize: '16px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'var(--accent)' }}>
                  person
                </span>
                {t('personalInformation', { ns: 'disbursements' })}
              </h4>
              {/* Show fullName for wallet payments, firstName/surname for mobile money */}
              {(payoutData?.paymentMethod === 'Wallet' || payoutData?.paymentMethod === 'WALLET') ? (
                <div>
                  <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('fullName', { ns: 'disbursements', defaultValue: 'Full Name' })}</p>
                  <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                    {payoutData?.fullName || '—'}
                  </p>
                </div>
              ) : (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px' }}>
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('firstName', { ns: 'disbursements' })}</p>
                    <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                      {payoutData?.firstName || '—'}
                    </p>
                  </div>
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('surname', { ns: 'disbursements' })}</p>
                    <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                      {payoutData?.surname || '—'}
                    </p>
                  </div>
                </div>
              )}
            </div>

            {/* Contact Information */}
            <div style={{
              padding: '20px',
              backgroundColor: 'var(--bg-tertiary)',
              borderRadius: 'var(--radius-md)',
              border: '1px solid var(--border-primary)'
            }}>
              <h4 style={{
                margin: '0 0 16px 0',
                fontSize: '16px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'var(--accent)' }}>
                  phone
                </span>
                {t('contactInformation', { ns: 'disbursements' })}
              </h4>
              <div>
                <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('phoneNumber', { ns: 'disbursements' })}</p>
                <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                  {payoutData?.countryCode || ''}{payoutData?.phoneNumber || '—'}
                </p>
              </div>
            </div>

            {/* Payment Details */}
            <div style={{
              padding: '20px',
              backgroundColor: 'var(--bg-tertiary)',
              borderRadius: 'var(--radius-md)',
              border: '1px solid var(--border-primary)',
              overflow: 'hidden',
              wordWrap: 'break-word'
            }}>
              <h4 style={{
                margin: '0 0 16px 0',
                fontSize: '16px',
                fontWeight: '600',
                color: 'var(--text-primary)',
                display: 'flex',
                alignItems: 'center',
                gap: '8px'
              }}>
                <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'var(--accent)' }}>
                  payment
                </span>
                {t('paymentDetails', { ns: 'disbursements' })}
              </h4>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px' }}>
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('amount', { ns: 'disbursements' })}</p>
                    <p style={{ margin: '8px 0 0 0', fontSize: '24px', fontWeight: '700', color: 'var(--accent)' }}>
                      GHS {payoutData?.amount ? parseFloat(payoutData.amount).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) : '0.00'}
                    </p>
                  </div>
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>
                      {t('charge', { ns: 'disbursements' })}
                      {isCheckingFee && <span style={{ marginLeft: '8px', fontSize: '10px' }}>({t('calculating', { ns: 'common', defaultValue: 'Calculating...' })})</span>}
                    </p>
                    <p style={{ margin: '8px 0 0 0', fontSize: '24px', fontWeight: '700', color: 'var(--warning)' }}>
                      {feeData?.feeApplied || feeData?.fee
                        ? `GHS ${parseFloat(feeData.feeApplied || feeData.fee).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`
                        : isCheckingFee
                          ? t('calculating', { ns: 'common', defaultValue: 'Calculating...' })
                          : '—'}
                    </p>
                  </div>
                  {(feeData?.total || feeData?.totalPayable) && (
                    <div>
                      <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('totalPayable', { ns: 'disbursements', defaultValue: 'Total Payable' })}</p>
                      <p style={{ margin: '8px 0 0 0', fontSize: '24px', fontWeight: '700', color: 'var(--success)' }}>
                        GHS {parseFloat(feeData.total || feeData.totalPayable).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                      </p>
                    </div>
                  )}
                </div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '16px' }}>
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('referenceNumber', { ns: 'disbursements', defaultValue: 'Reference Number' })}</p>
                    <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)', fontFamily: 'monospace' }}>
                      {payoutData?.reference || '—'}
                    </p>
                  </div>
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('paymentMethod', { ns: 'disbursements' })}</p>
                    <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                      {payoutData?.paymentMethod || '—'}
                    </p>
                  </div>
                  {(payoutData?.paymentMethod === 'MOMO' || payoutData?.paymentMethod === 'Mobile Money') && (
                    <div>
                      <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('mobileNetwork', { ns: 'disbursements' })}</p>
                      <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                        {payoutData?.provider || '—'}
                      </p>
                    </div>
                  )}
                  {(payoutData?.paymentMethod === 'Wallet' || payoutData?.paymentMethod === 'WALLET') && (
                    <div>
                      <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('wallet', { ns: 'disbursements', defaultValue: 'Wallet' })}</p>
                      <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                        {t('walletTransfer', { ns: 'disbursements', defaultValue: 'Wallet Transfer' })}
                      </p>
                    </div>
                  )}
                  {(payoutData?.paymentMethod === 'Bank' || payoutData?.paymentMethod === 'BANK') && (
                    <>
                      <div>
                        <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('accountNumber', { ns: 'disbursements', defaultValue: 'Account Number' })}</p>
                        <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                          {payoutData?.accountNumber || '—'}
                        </p>
                      </div>
                      <div>
                        <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('accountName', { ns: 'disbursements', defaultValue: 'Account Name' })}</p>
                        <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                          {payoutData?.accountName || '—'}
                        </p>
                      </div>
                      <div>
                        <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('bankName', { ns: 'disbursements', defaultValue: 'Bank Name' })}</p>
                        <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                          {payoutData?.bankName || '—'}
                        </p>
                      </div>
                      {payoutData?.bankbranchCode && payoutData.bankbranchCode.trim() && (
                        <div>
                          <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('bankBranchCode', { ns: 'disbursements', defaultValue: 'Bank Branch Code' })}</p>
                          <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                            {payoutData.bankbranchCode}
                          </p>
                        </div>
                      )}
                    </>
                  )}
                </div>
                {/* Show purpose if provided (optional for wallet payments) */}
                {payoutData?.purpose && payoutData.purpose.trim() && (
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>
                      {t('purposeNarration', { ns: 'disbursements' })}
                      {(payoutData?.paymentMethod === 'Wallet' || payoutData?.paymentMethod === 'WALLET') && (
                        <span style={{ 
                          marginLeft: '8px', 
                          fontSize: '11px', 
                          color: 'var(--text-muted)',
                          fontStyle: 'italic',
                          fontWeight: 'normal'
                        }}>
                          ({t('optional', { ns: 'common', defaultValue: 'Optional' })})
                        </span>
                      )}
                    </p>
                    <p style={{
                      margin: '8px 0 0 0',
                      fontSize: '16px',
                      fontWeight: '500',
                      color: 'var(--text-primary)',
                      wordWrap: 'break-word',
                      wordBreak: 'break-word',
                      overflowWrap: 'break-word',
                      whiteSpace: 'pre-wrap',
                      maxWidth: '100%'
                    }}>
                      {payoutData.purpose}
                    </p>
                  </div>
                )}
                {useDifferentNumber && payoutData?.differentMomoNumber && (
                  <div>
                    <p style={{ margin: 0, fontSize: '12px', color: 'var(--text-muted)', fontWeight: '500' }}>{t('momoNumberForDisbursement', { ns: 'disbursements' })}</p>
                    <p style={{ margin: '8px 0 0 0', fontSize: '16px', fontWeight: '600', color: 'var(--text-primary)' }}>
                      {payoutData?.differentMomoCountryCode || ''}{payoutData.differentMomoNumber}
                    </p>
                  </div>
                )}
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div style={{
            display: 'flex',
            gap: 12,
            marginTop: 24,
            paddingTop: 24,
            borderTop: '1px solid var(--border-primary)'
          }}>
            <button
              type="button"
              onClick={onClose}
              style={{
                flex: 1,
                padding: '14px 20px',
                borderRadius: 10,
                border: '2px solid var(--border-primary)',
                background: 'var(--bg-input)',
                color: 'var(--text-secondary)',
                cursor: 'pointer',
                fontSize: '15px',
                fontWeight: 600,
                transition: 'all 0.2s ease'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.borderColor = 'var(--border-secondary)';
                e.currentTarget.style.background = 'var(--bg-hover)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.borderColor = 'var(--border-primary)';
                e.currentTarget.style.background = 'var(--bg-input)';
              }}
            >
              {t('cancel', { ns: 'disbursements' })}
            </button>
            <button
              type="button"
              onClick={onSubmit}
              style={{
                flex: 1,
                padding: '14px 20px',
                borderRadius: 10,
                border: 'none',
                background: 'var(--accent)',
                color: 'var(--text-inverse)',
                cursor: 'pointer',
                fontSize: '15px',
                fontWeight: 600,
                transition: 'all 0.2s ease',
                boxShadow: 'var(--shadow-md)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '8px'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.background = 'var(--accent-hover)';
                e.currentTarget.style.boxShadow = 'var(--shadow-lg)';
                e.currentTarget.style.transform = 'translateY(-1px)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.background = 'var(--accent)';
                e.currentTarget.style.boxShadow = 'var(--shadow-md)';
                e.currentTarget.style.transform = 'translateY(0)';
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
                check_circle
              </span>
              {t('pay', { ns: 'disbursements', defaultValue: 'Pay' })}
            </button>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes slideIn {
          from {
            opacity: 0;
            transform: translateY(-20px) scale(0.95);
          }
          to {
            opacity: 1;
            transform: translateY(0) scale(1);
          }
        }

        @media (max-width: 1024px) {
          div[style*="maxWidth: 600"] {
            max-width: min(90vw, 560px) !important;
          }
          div[style*="padding: 32"] {
            padding: 24px !important;
          }
        }

        @media (max-width: 768px) {
          div[style*="maxWidth: 600"] {
            max-width: min(95vw, 500px) !important;
          }
          div[style*="padding: 32"] {
            padding: 20px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 20px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 18px !important;
          }
          div[style*="padding: '20px'"] {
            padding: 16px !important;
          }
          div[style*="gap: '20px'"] {
            gap: 16px !important;
          }
        }

        @media (max-width: 480px) {
          div[style*="maxWidth: 600"] {
            max-width: calc(100vw - 16px) !important;
          }
          div[style*="padding: 32"] {
            padding: 16px !important;
          }
          h3[style*="fontSize: '24px'"] {
            font-size: 18px !important;
          }
          h4[style*="fontSize: '16px'"] {
            font-size: 14px !important;
          }
          div[style*="marginBottom: 24"] {
            margin-bottom: 16px !important;
          }
          div[style*="padding: '20px'"] {
            padding: 14px !important;
          }
          div[style*="gap: '20px'"] {
            gap: 14px !important;
          }
          div[style*="gap: '16px'"] {
            gap: 12px !important;
          }
          p[style*="fontSize: '24px'"] {
            font-size: 20px !important;
          }
          p[style*="fontSize: '16px'"] {
            font-size: 14px !important;
          }
          button[style*="padding: '14px 20px'"] {
            padding: 10px 14px !important;
            font-size: 13px !important;
          }
        }
      `}</style>
    </>,
    document.body
  );
};

export default DisbursementPreviewModal;