/**
 * Mobile Money Fields Component
 * Handles phone number, country code, and network provider inputs
 */

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from "@/app/providers/ToastContext.jsx";
import { FlagIcon } from '@/shared/components';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import CustomSelect from '@/shared/components/CustomSelect.jsx';

const MobileMoneyFields = ({
  payoutData,
  handleInputChange,
  formErrors,
  isValidatingAccount,
  accountDetailsFetched,
  selectedCountry,
  onFetchAccountDetails,
  setPayoutData,
}) => {
  const { t } = useTranslation();
  const { info } = useToast();
  const [hasShownMTNWarning, setHasShownMTNWarning] = useState(false);

  // Show MTN notification when provider is selected
  useEffect(() => {
    if (payoutData.provider === 'MTN' && !hasShownMTNWarning) {
      info(
        t('mtnTransferUnavailable', { 
          ns: 'disbursements', 
          defaultValue: 'Transfers to MTN numbers are currently unavailable but will be coming soon!' 
        })
      );
      setHasShownMTNWarning(true);
    } else if (payoutData.provider !== 'MTN') {
      // Reset warning if provider changes from MTN
      setHasShownMTNWarning(false);
    }
  }, [payoutData.provider, hasShownMTNWarning, info, t]);

  // Check if all required fields are filled before allowing account fetch
  const canFetchAccountDetails = () => {
    // Check if phone number is filled
    if (!payoutData.phoneNumber || !payoutData.phoneNumber.trim()) {
      return false;
    }
    
    // Check if payment method is selected
    if (!payoutData.paymentMethod || payoutData.paymentMethod.trim() === '') {
      return false;
    }
    
    // Check if amount is filled
    if (!payoutData.amount || payoutData.amount.toString().trim() === '' || parseFloat(payoutData.amount) <= 0) {
      return false;
    }
    
    // Check if provider is selected (for Mobile Money)
    if ((payoutData.paymentMethod === 'Mobile Money' || payoutData.paymentMethod === 'MOMO') && 
        (!payoutData.provider || !payoutData.provider.trim())) {
      return false;
    }
    
    // Prevent fetching for MTN
    if (payoutData.provider === 'MTN') {
      return false;
    }
    
    return true;
  };

  const isFetchDisabled = isValidatingAccount || accountDetailsFetched || !canFetchAccountDetails();
  
  const getFetchButtonTooltip = () => {
    if (isValidatingAccount) {
      return t('fetching', { ns: 'disbursements', defaultValue: 'Fetching...' });
    }
    if (accountDetailsFetched) {
      return t('detailsFetched', { ns: 'disbursements', defaultValue: 'Details Fetched' });
    }
    if (payoutData.provider === 'MTN') {
      return t('mtnUnavailableTooltip', { 
        ns: 'disbursements', 
        defaultValue: 'MTN transfers are currently unavailable' 
      });
    }
    if (!payoutData.phoneNumber || !payoutData.phoneNumber.trim()) {
      return t('fillPhoneNumberFirst', { ns: 'disbursements', defaultValue: 'Please fill in phone number first' });
    }
    if (!payoutData.paymentMethod || payoutData.paymentMethod.trim() === '') {
      return t('selectPaymentMethodFirst', { ns: 'disbursements', defaultValue: 'Please select payment method first' });
    }
    if (!payoutData.amount || payoutData.amount.toString().trim() === '' || parseFloat(payoutData.amount) <= 0) {
      return t('fillAmountFirst', { ns: 'disbursements', defaultValue: 'Please fill in amount first' });
    }
    if ((payoutData.paymentMethod === 'Mobile Money' || payoutData.paymentMethod === 'MOMO') && 
        (!payoutData.provider || !payoutData.provider.trim())) {
      return t('selectProviderFirst', { ns: 'disbursements', defaultValue: 'Please select provider first' });
    }
    return t('fetchAccountDetails', { ns: 'disbursements', defaultValue: 'Fetch Account Details' });
  };

  return (
    <>
      <div data-tour="disbursements-phone-number">
        <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
          {t('recipientPhoneNumber', { ns: 'disbursements', defaultValue: 'Recipient Phone Number' })}
        </label>
        <div className="phone-input phone-input-row" style={{ display: 'flex', gap: '12px', alignItems: 'stretch' }}>
          <div className="phone-input-country" style={{ flex: '0 0 auto', width: '160px', minWidth: '160px', position: 'relative' }}>
            <span style={{
              position: 'absolute',
              left: '14px',
              top: '50%',
              transform: 'translateY(-50%)',
              pointerEvents: 'none',
              zIndex: 1,
              display: 'flex',
              alignItems: 'center'
            }}>
              <FlagIcon countryCode={selectedCountry?.code} size="1.2em" />
            </span>
            <CustomSelect
              name="countryCode"
              value={payoutData.countryCode}
              onChange={handleInputChange}
              options={countries.map((country) => ({
                value: country.dialCode,
                label: country.dialCode,
                name: country.name,
                countryCode: country.code,
              }))}
              searchable
              showCheckmark={false}
              style={{ width: '100%' }}
            />
          </div>
          <input
            type="tel"
            name="phoneNumber"
            value={payoutData.phoneNumber}
            onChange={(e) => {
              // Only allow numeric characters
              const numericValue = e.target.value.replace(/[^\d]/g, '');
              // Directly update the event target's value property
              e.target.value = numericValue;
              handleInputChange(e);
            }}
            placeholder={t('phoneNumberPlaceholder', { ns: 'disbursements' })}
            className="small-search input-flex"
            style={{
              flex: 1,
              minWidth: '200px',
              padding: '12px 16px',
              border: '1px solid var(--border-secondary)',
              borderRadius: 'var(--radius-md)',
              fontSize: '14px',
              backgroundColor: 'var(--bg-input)',
              color: 'var(--text-primary)',
              transition: 'all var(--transition-base)',
              height: 'auto'
            }}
            onFocus={(e) => e.target.style.borderColor = 'var(--accent)'}
            onBlur={(e) => e.target.style.borderColor = 'var(--border-secondary)'}
            inputMode="numeric"
            pattern="[0-9]*"
          />
          <CustomSelect
            name="provider"
            value={payoutData.provider || ''}
            onChange={handleInputChange}
            options={[
              { value: 'MTN', label: `${t('mtn', { ns: 'disbursements' })} - ${t('unavailable', { ns: 'disbursements', defaultValue: 'Unavailable' })}` },
              { value: 'Telecel', label: t('telecel', { ns: 'disbursements' }) }
            ]}
            placeholder={t('selectNetwork', { ns: 'disbursements' })}
            style={{ flex: '0 0 auto', width: '160px' }}
          />
        </div>
        
        {/* MTN Warning Message */}
        {payoutData.provider === 'MTN' && (
          <div style={{
            padding: '16px 20px',
            backgroundColor: 'var(--warning-bg, rgba(255, 193, 7, 0.2))',
            border: '2px solid var(--warning, #ffc107)',
            borderRadius: 'var(--radius-md)',
            marginTop: '16px',
            display: 'flex',
            alignItems: 'center',
            gap: '12px',
            boxShadow: '0 2px 8px rgba(255, 193, 7, 0.25)'
          }}>
            <span className="material-symbols-outlined" style={{ 
              fontSize: '24px', 
              color: 'var(--warning, #ffc107)',
              flexShrink: 0,
              fontWeight: 'bold'
            }}>
              warning
            </span>
            <div style={{ fontSize: '15px', color: 'var(--warning-text, #856404)', lineHeight: '1.5', fontWeight: '500' }}>
              <strong style={{ fontSize: '16px', color: '#d63384' }}>{t('mtnTransfers', { ns: 'disbursements', defaultValue: 'MTN Transfers' })}:</strong> {t('mtnTransferUnavailable', { 
                ns: 'disbursements', 
                defaultValue: 'Transfers to MTN numbers are currently unavailable but will be coming soon!' 
              })}
            </div>
          </div>
        )}
        
        {(formErrors.countryCode || formErrors.phoneNumber || formErrors.provider) && (
          <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
            {formErrors.phoneNumber || formErrors.countryCode || formErrors.provider}
          </p>
        )}

        {/* Country Field - Hidden from user but functionality preserved */}
        <input
          type="hidden"
          name="country"
          value="GHA"
          readOnly
        />
        {isValidatingAccount && (
          <p style={{ color: 'var(--text-muted)', fontSize: '12px', marginTop: '6px', display: 'flex', alignItems: 'center', gap: '6px' }}>
            <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>hourglass_top</span>
            {t('fetchingAccountDetails', { ns: 'disbursements', defaultValue: 'Fetching account details...' })}
          </p>
        )}
      </div>

      <div style={{ marginTop: '16px' }}>
        <button
          type="button"
          onClick={onFetchAccountDetails}
          disabled={isFetchDisabled}
          className="fetch-button"
          title={getFetchButtonTooltip()}
          style={{
            padding: '10px 16px',
            borderRadius: 'var(--radius-md)',
            border: '1px solid var(--border-secondary)',
            backgroundColor: isFetchDisabled ? 'var(--bg-tertiary)' : 'var(--accent)',
            color: isFetchDisabled ? 'var(--text-muted)' : 'var(--text-inverse)',
            fontSize: '13px',
            fontWeight: 600,
            cursor: isFetchDisabled ? 'not-allowed' : 'pointer',
            transition: 'all var(--transition-base)',
            display: 'inline-flex',
            alignItems: 'center',
            gap: '6px',
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>
            {isValidatingAccount ? 'hourglass_top' : accountDetailsFetched ? 'check_circle' : 'badge'}
          </span>
          {isValidatingAccount
            ? t('fetching', { ns: 'disbursements', defaultValue: 'Fetching...' })
            : accountDetailsFetched
            ? t('detailsFetched', { ns: 'disbursements', defaultValue: 'Details Fetched' })
            : t('fetchAccountDetails', {
                ns: 'disbursements',
                defaultValue: 'Fetch Account Details',
              })}
        </button>
        {!canFetchAccountDetails() && !isValidatingAccount && !accountDetailsFetched && (
          <p style={{ 
            color: 'var(--text-muted)', 
            fontSize: '11px', 
            marginTop: '8px',
            fontStyle: 'italic'
          }}>
            {t('fillAllFieldsBeforeFetch', { 
              ns: 'disbursements', 
              defaultValue: 'Please fill in payment method, amount, and phone number before fetching account details' 
            })}
          </p>
        )}
      </div>
    </>
  );
};

export default MobileMoneyFields;

