/**
 * Wallet Fields Component
 * Handles wallet recipient search with user lookup
 * Uses the same implementation as TransferFundsModal for consistency
 */

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { FlagIcon } from '@/shared/components';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import { formatRecipientLabel, extractRecipientId, splitPhoneNumber, DEFAULT_COUNTRY_CODE } from '@/features/wallet/utils/transferUtils.js';
import { useTransferRecipientSearch } from '@/features/wallet/hooks/useTransferRecipientSearch.js';
import logger from '@/shared/utils/logger.js';

const WalletFields = ({
  payoutData,
  handleInputChange,
  formErrors,
  setPayoutData,
  setFormErrors,
  onRecipientSelected, // Callback to notify parent of selected recipient
}) => {
  const { t } = useTranslation();
  const [recipientQuery, setRecipientQuery] = useState('');
  const [phoneCountryCode, setPhoneCountryCode] = useState(payoutData.countryCode || DEFAULT_COUNTRY_CODE);
  const [selectedRecipient, setSelectedRecipient] = useState(null);
  
  // Use the same hook as TransferFundsModal for consistency
  const {
    searchResults,
    isSearching,
    showResults,
    setShowResults,
    searchContainerRef,
    debouncedSearch,
    clearSearch: clearSearchResults,
  } = useTransferRecipientSearch();

  const handleSelectRecipient = useCallback((recipient) => {
    setSelectedRecipient(recipient);

    const { countryCode, nationalNumber } = splitPhoneNumber(recipient?.phoneNumber || recipient?.phone, countries);
    
    setPhoneCountryCode(countryCode);
    setRecipientQuery(nationalNumber);
    setShowResults(false);

    // Extract name information from recipient (like TransferFundsModal)
    // Handle nested user object from API response
    const user = recipient.user || recipient;
    
    // Get full name - prioritize full_name field, then construct from parts
    let fullName = user.full_name || user.fullName || recipient.full_name || recipient.fullName || '';
    
    // If no full_name, try to construct from first_name and last_name
    if (!fullName && (user.first_name || user.last_name)) {
      fullName = [user.first_name, user.last_name].filter(Boolean).join(' ').trim();
    }
    
    // If still no full_name, try displayName
    if (!fullName) {
      fullName = formatRecipientLabel(recipient) || '';
    }
    
    // Update payout data with recipient information
    // Use full_name only (no firstName or surname for wallet payments)
    setPayoutData((prev) => ({
      ...prev,
      countryCode: countryCode,
      phoneNumber: nationalNumber,
      fullName: fullName, // Use fullName only for wallet payments
      firstName: '', // Clear firstName for wallet payments
      surname: '', // Clear surname for wallet payments
    }));

    // Clear errors
    setFormErrors((prev) => {
      const next = { ...prev };
      delete next.phoneNumber;
      delete next.countryCode;
      delete next.firstName;
      delete next.surname;
      delete next.fullName;
      return next;
    });

    // Notify parent component of selected recipient
    if (onRecipientSelected) {
      onRecipientSelected(recipient);
    }
  }, [setPayoutData, setFormErrors, onRecipientSelected]);

  // Smart Auto-select: Only select if the typed number EXACTLY matches the result (exact same as TransferFundsModal)
  useEffect(() => {
    if (searchResults.length === 1 && !selectedRecipient && !isSearching) {
      const recipient = searchResults[0];

      // Construct full typed number
      const typedCountryCode = phoneCountryCode.replace(/[^0-9]/g, '');
      const typedNationalNumber = recipientQuery.replace(/[^0-9]/g, '');
      const fullTypedNumber = `${typedCountryCode}${typedNationalNumber}`;

      // Clean result number
      const resultNumber = (recipient.phoneNumber || '').replace(/[^0-9]/g, '');

      // Check for exact match
      if (fullTypedNumber === resultNumber) {
        logger.debug('Smart Auto-select: Exact match found', { fullTypedNumber });
        handleSelectRecipient(recipient);
      }
    }
  }, [searchResults, selectedRecipient, isSearching, phoneCountryCode, recipientQuery, handleSelectRecipient]);

  // Initialize recipient query from phone number if exists
  useEffect(() => {
    if (payoutData.phoneNumber && !recipientQuery) {
      const { nationalNumber } = splitPhoneNumber(`${payoutData.countryCode}${payoutData.phoneNumber}`);
      setRecipientQuery(nationalNumber);
    }
  }, []);

  // Add responsive styles for mobile
  useEffect(() => {
    const styleId = 'wallet-fields-responsive-styles';
    if (document.getElementById(styleId)) {return;}

    const style = document.createElement('style');
    style.id = styleId;
    style.textContent = `
      @media (max-width: 768px) {
        .wallet-country-code-selector {
          width: 90px !important;
        }
        .wallet-country-code-selector select {
          padding: 12px 8px 12px 36px !important;
          font-size: 13px !important;
        }
        .wallet-country-code-selector span {
          left: 10px !important;
        }
      }
      @media (max-width: 480px) {
        .wallet-country-code-selector {
          width: 80px !important;
        }
        .wallet-country-code-selector select {
          padding: 12px 6px 12px 32px !important;
          font-size: 12px !important;
        }
      }
    `;
    document.head.appendChild(style);

    return () => {
      const existingStyle = document.getElementById(styleId);
      if (existingStyle) {
        existingStyle.remove();
      }
    };
  }, []);

  // Use the same debounced search as TransferFundsModal
  useEffect(() => {
    debouncedSearch(recipientQuery, phoneCountryCode);
  }, [recipientQuery, phoneCountryCode, debouncedSearch]);

  const handleQueryChange = (e) => {
    const value = e.target.value;
    setRecipientQuery(value);
    setSelectedRecipient(null);
    setShowResults(true);

    // Update phone number in payout data (exact same as TransferFundsModal)
    const { nationalNumber } = splitPhoneNumber(`${phoneCountryCode}${value}`);
    setPayoutData((prev) => ({
      ...prev,
      phoneNumber: nationalNumber,
      countryCode: phoneCountryCode,
    }));
  };

  const handleCountryCodeChange = (e) => {
    const value = e.target.value;
    setPhoneCountryCode(value);
    setSelectedRecipient(null);
    
    setPayoutData((prev) => ({
      ...prev,
      countryCode: value,
    }));
  };

  const clearSearch = () => {
    setRecipientQuery('');
    setSelectedRecipient(null);
    clearSearchResults(); // Use the hook's clearSearch
    setPayoutData((prev) => ({
      ...prev,
      phoneNumber: '',
      firstName: '',
      surname: '',
      fullName: '',
    }));
    setFormErrors((prev) => {
      const next = { ...prev };
      delete next.phoneNumber;
      delete next.firstName;
      delete next.surname;
      delete next.fullName;
      return next;
    });
  };

  const selectedCountry = countries.find((c) => c.dialCode === phoneCountryCode) || countries.find((c) => c.code === 'GH');
  
  // Check if recipient is selected (exact same logic as TransferFundsModal)
  const hasSelectedRecipient = useMemo(
    () => !!(selectedRecipient && extractRecipientId(selectedRecipient)),
    [selectedRecipient]
  );

  return (
    <div style={{ position: 'relative' }} ref={searchContainerRef}>
      <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
        {t('searchRecipient', { ns: 'wallet', defaultValue: 'Search Recipient' })}
      </label>
      <div style={{ display: 'flex', gap: '8px', alignItems: 'stretch' }}>
        <div 
          className="wallet-country-code-selector"
          style={{ 
            position: 'relative', 
            width: '160px', 
            minWidth: '160px',
            flexShrink: 0,
          }}
        >
          <span
            style={{
              position: 'absolute',
              left: '14px',
              top: '50%',
              transform: 'translateY(-50%)',
              pointerEvents: 'none',
              zIndex: 1,
              display: 'flex',
              alignItems: 'center',
            }}
          >
            <FlagIcon countryCode={selectedCountry?.code} size="1.2em" />
          </span>
          <CustomSelect
            name="phoneCountryCode"
            value={phoneCountryCode}
            onChange={handleCountryCodeChange}
            options={countries.map((country) => ({
              value: country.dialCode,
              label: country.dialCode,
              name: country.name,
              countryCode: country.code,
            }))}
            searchable
            showCheckmark={false}
            style={{ width: '100%' }}
          />
        </div>

        <div style={{ position: 'relative', flex: 1 }}>
          <input
            type="tel"
            name="recipientQuery"
            value={recipientQuery}
            onChange={handleQueryChange}
            placeholder={t('enterPhoneNumber', { ns: 'wallet', defaultValue: 'Enter phone number' })}
            autoComplete="off"
            inputMode="numeric"
            pattern="[0-9]*"
            className="small-search input-flex"
            style={{
              flex: 1,
              padding: '12px 44px 12px 16px',
              border: `1px solid ${selectedRecipient ? 'var(--success, #16a34a)' : 'var(--border-secondary)'}`,
              borderRadius: 'var(--radius-md)',
              fontSize: '14px',
              backgroundColor: 'var(--bg-input)',
              color: 'var(--text-primary)',
              transition: 'all var(--transition-base)',
            }}
            onFocus={(e) => {
              setShowResults(true);
              e.target.style.borderColor = 'var(--accent)';
            }}
            onBlur={(e) => {
              if (!showResults) {
                e.target.style.borderColor = 'var(--border-secondary)';
              }
            }}
          />
          {recipientQuery && (
            <button
              type="button"
              onClick={clearSearch}
              style={{
                position: 'absolute',
                right: 12,
                top: '50%',
                transform: 'translateY(-50%)',
                border: 'none',
                background: 'transparent',
                color: 'var(--text-muted)',
                cursor: 'pointer',
                padding: 4,
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: 18 }}>
                close
              </span>
            </button>
          )}
        </div>
      </div>

      {(formErrors.phoneNumber || formErrors.countryCode) && (
        <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
          {formErrors.phoneNumber || formErrors.countryCode}
        </p>
      )}

      {isSearching && (
        <p style={{ color: 'var(--text-muted)', fontSize: '12px', marginTop: '6px', display: 'flex', alignItems: 'center', gap: '6px' }}>
          <span className="material-symbols-outlined" style={{ fontSize: '16px' }}>hourglass_top</span>
          {t('searchingRecipients', { ns: 'wallet', defaultValue: 'Searching recipients...' })}
        </p>
      )}

      {showResults && recipientQuery.trim().length >= 3 && (
        <div
          style={{
            position: 'absolute',
            top: 'calc(100% + 8px)',
            left: 0,
            right: 0,
            background: 'var(--card)',
            borderRadius: 'var(--radius-md)',
            boxShadow: 'var(--shadow-lg)',
            maxHeight: 280,
            overflowY: 'auto',
            zIndex: 1000,
            border: '1px solid var(--border-secondary)',
          }}
        >
          {isSearching ? (
            <div
              style={{
                padding: '16px',
                color: 'var(--text-muted)',
                fontSize: '14px',
                textAlign: 'center',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '8px',
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>hourglass_top</span>
              {t('searchingRecipients', { ns: 'wallet', defaultValue: 'Searching recipients...' })}
            </div>
          ) : searchResults.length === 0 ? (
            <div
              style={{
                padding: '16px',
                color: 'var(--text-muted)',
                fontSize: '14px',
                textAlign: 'center',
              }}
            >
              {t('noRecipientsFound', { ns: 'wallet', defaultValue: 'No recipients found' })}
            </div>
          ) : (
            searchResults.map((recipient) => {
              const id = extractRecipientId(recipient);
              const isActive = selectedRecipient && id === extractRecipientId(selectedRecipient);
              return (
                <button
                  key={id || JSON.stringify(recipient)}
                  type="button"
                  onMouseDown={(event) => {
                    event.preventDefault();
                    handleSelectRecipient(recipient);
                  }}
                  style={{
                    width: '100%',
                    textAlign: 'left',
                    border: 'none',
                    background: isActive ? 'var(--success-bg, rgba(22, 163, 74, 0.12))' : 'transparent',
                    padding: '12px 16px',
                    cursor: 'pointer',
                    display: 'block',
                    transition: 'background-color var(--transition-base)',
                  }}
                  onMouseEnter={(e) => {
                    if (!isActive) {
                      e.currentTarget.style.background = 'var(--bg-hover)';
                    }
                  }}
                  onMouseLeave={(e) => {
                    if (!isActive) {
                      e.currentTarget.style.background = 'transparent';
                    }
                  }}
                >
                  <div
                    style={{
                      fontSize: '15px',
                      fontWeight: 600,
                      color: 'var(--text-primary)',
                    }}
                  >
                    {formatRecipientLabel(recipient) || t('unknownRecipient', { ns: 'wallet', defaultValue: 'Unknown Recipient' })}
                  </div>
                </button>
              );
            })
          )}
        </div>
      )}

      {/* Show recipient info card when there are search results or a recipient is selected (exact same as TransferFundsModal) */}
      {(hasSelectedRecipient || (searchResults.length > 0 && recipientQuery.trim().length >= 3)) && (
        <div
          style={{
            marginTop: 10,
            padding: '10px 14px',
            backgroundColor: 'var(--success-bg, rgba(22, 163, 74, 0.12))',
            borderRadius: 8,
            border: '1px solid var(--success, #16a34a)',
            display: 'flex',
            alignItems: 'center',
            gap: 8,
          }}
        >
          <span className="material-symbols-outlined" style={{ fontSize: 18, color: 'var(--success, #16a34a)' }}>
            person
          </span>
          <div style={{ flex: 1 }}>
            <div
              style={{
                fontSize: '14px',
                fontWeight: 600,
                color: 'var(--text-primary)',
              }}
            >
              {hasSelectedRecipient
                ? (formatRecipientLabel(selectedRecipient) || t('unknownRecipient', { ns: 'wallet', defaultValue: 'Unknown Recipient' }))
                : (searchResults.length > 0
                  ? (formatRecipientLabel(searchResults[0]) || t('searchingRecipient', { ns: 'wallet', defaultValue: 'Searching...' }))
                  : t('searchingRecipient', { ns: 'wallet', defaultValue: 'Searching...' })
                )
              }
            </div>
            <div
              style={{
                fontSize: '12px',
                color: 'var(--text-muted)',
                marginTop: 2,
              }}
            >
              {hasSelectedRecipient
                ? (selectedRecipient.phoneNumber || selectedRecipient.phone || t('recipientSelected', { ns: 'wallet', defaultValue: 'Recipient selected' }))
                : (searchResults.length > 0 && searchResults[0].phoneNumber
                  ? searchResults[0].phoneNumber
                  : t('typeToSearch', { ns: 'wallet', defaultValue: 'Keep typing...' })
                )
              }
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default WalletFields;

