/**
 * Bulk Disbursement Actions Component
 * 
 * Submit and cancel buttons for bulk disbursement.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import { LoadingSpinner } from '@/shared/components';

const BulkDisbursementActions = ({
  onCancel,
  onSubmit,
  isProcessing,
  isDisabled,
  isMobile
}) => {
  const { t } = useTranslation();

  return (
    <div 
      data-tour="disbursements-bulk-actions"
      style={{ 
      display: 'flex', 
      flexDirection: isMobile ? 'column-reverse' : 'row',
      gap: isMobile ? '12px' : '16px', 
      justifyContent: 'flex-end',
      marginTop: isMobile ? '16px' : '24px'
      }}
    >
      <button
        type="button"
        onClick={onCancel}
        style={{
          padding: isMobile ? '12px 20px' : '14px 28px',
          backgroundColor: 'transparent',
          color: 'var(--text-primary)',
          border: '1px solid var(--border-secondary)',
          borderRadius: 'var(--radius-md)',
          cursor: 'pointer',
          fontSize: isMobile ? '14px' : '16px',
          fontWeight: '600',
          transition: 'all var(--transition-base)',
          width: isMobile ? '100%' : 'auto'
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.borderColor = 'var(--error)';
          e.currentTarget.style.color = 'var(--error)';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.borderColor = 'var(--border-secondary)';
          e.currentTarget.style.color = 'var(--text-primary)';
        }}
      >
        Cancel
      </button>
      <button
        type="button"
        onClick={onSubmit}
        disabled={isDisabled}
        style={{
          padding: isMobile ? '12px 20px' : '14px 28px',
          backgroundColor: isDisabled ? 'var(--muted)' : 'var(--accent)',
          color: 'var(--text-inverse)',
          border: 'none',
          borderRadius: 'var(--radius-md)',
          cursor: isDisabled ? 'not-allowed' : 'pointer',
          fontSize: isMobile ? '14px' : '16px',
          fontWeight: '600',
          transition: 'all var(--transition-base)',
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '8px',
          width: isMobile ? '100%' : 'auto'
        }}
        onMouseEnter={(e) => {
          if (!isDisabled) {
            e.currentTarget.style.backgroundColor = '#003d7a';
            e.currentTarget.style.transform = 'translateY(-1px)';
          }
        }}
        onMouseLeave={(e) => {
          if (!isDisabled) {
            e.currentTarget.style.backgroundColor = 'var(--accent)';
            e.currentTarget.style.transform = 'translateY(0)';
          }
        }}
      >
        {isProcessing ? (
          <>
            <LoadingSpinner size="small" />
            Processing...
          </>
        ) : (
          <>
            <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
              send
            </span>
            Submit Bulk Disbursement
          </>
        )}
      </button>
    </div>
  );
};

export default BulkDisbursementActions;

