/**
 * Recipient Name Fields Component
 * Displays firstName and surname fields (read-only after account fetch)
 */

import React from 'react';
import { useTranslation } from 'react-i18next';

const RecipientNameFields = ({
  payoutData,
  handleInputChange,
  formErrors,
  accountDetailsFetched,
  isWalletPayment = false,
}) => {
  const { t } = useTranslation();

  // Fields should be uneditable if account details were fetched OR if it's a wallet payment OR if we have names
  const isReadOnly = accountDetailsFetched || isWalletPayment || !!(payoutData.firstName || payoutData.fullName);

  // Only show fields if details are fetched OR if it's a wallet payment OR if names are already present
  if (!accountDetailsFetched && !isWalletPayment && !payoutData.firstName && !payoutData.fullName) {
    return null;
  }

  return (
    <div className="name-fields-grid" data-tour="disbursements-recipient-name" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px' }}>
      {isWalletPayment ? (
        <div style={{ gridColumn: '1 / -1' }}>
          <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
            {t('fullName', { ns: 'disbursements', defaultValue: 'Full Name' })}
          </label>
          <input
            type="text"
            name="fullName"
            value={payoutData.fullName || ''}
            onChange={handleInputChange}
            placeholder={t('enterFullName', { ns: 'disbursements', defaultValue: 'Enter full name' })}
            readOnly={isReadOnly}
            disabled={isReadOnly}
            className="small-search input-large"
            style={{
              width: '100%',
              padding: '12px 16px',
              border: '1px solid var(--border-secondary)',
              borderRadius: 'var(--radius-md)',
              fontSize: '14px',
              backgroundColor: isReadOnly ? 'var(--bg-tertiary)' : 'var(--bg-input)',
              color: 'var(--text-primary)',
              cursor: isReadOnly ? 'not-allowed' : 'text',
              transition: 'all var(--transition-base)',
              opacity: isReadOnly ? 0.8 : 1
            }}
            onFocus={(e) => {
              if (isReadOnly) {
                e.target.blur();
              }
            }}
            onKeyDown={(e) => {
              if (isReadOnly) {
                e.preventDefault();
                e.stopPropagation();
              }
            }}
          />
          {formErrors.fullName && (
            <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
              {formErrors.fullName}
            </p>
          )}
        </div>
      ) : (
        <>
          <div>
            <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
              {t('firstName', { ns: 'disbursements' })}
            </label>
            <input
              type="text"
              name="firstName"
              value={payoutData.firstName}
              onChange={handleInputChange}
              placeholder={t('enterFirstName', { ns: 'disbursements' })}
              readOnly={isReadOnly}
              disabled={isReadOnly}
              className="small-search input-large"
              style={{
                width: '100%',
                padding: '12px 16px',
                border: '1px solid var(--border-secondary)',
                borderRadius: 'var(--radius-md)',
                fontSize: '14px',
                backgroundColor: isReadOnly ? 'var(--bg-tertiary)' : 'var(--bg-input)',
                color: 'var(--text-primary)',
                cursor: isReadOnly ? 'not-allowed' : 'text',
                transition: 'all var(--transition-base)',
                opacity: isReadOnly ? 0.8 : 1
              }}
              onFocus={(e) => {
                if (isReadOnly) {
                  e.target.blur();
                }
              }}
              onKeyDown={(e) => {
                if (isReadOnly) {
                  e.preventDefault();
                  e.stopPropagation();
                }
              }}
            />
            {formErrors.firstName && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                {formErrors.firstName}
              </p>
            )}
          </div>

          <div>
            <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
              {t('surname', { ns: 'disbursements' })}
            </label>
            <input
              type="text"
              name="surname"
              value={payoutData.surname}
              onChange={handleInputChange}
              placeholder={t('enterSurname', { ns: 'disbursements' })}
              readOnly={isReadOnly}
              disabled={isReadOnly}
              className="small-search input-large"
              style={{
                width: '100%',
                padding: '12px 16px',
                border: '1px solid var(--border-secondary)',
                borderRadius: 'var(--radius-md)',
                fontSize: '14px',
                backgroundColor: isReadOnly ? 'var(--bg-tertiary)' : 'var(--bg-input)',
                color: 'var(--text-primary)',
                cursor: isReadOnly ? 'not-allowed' : 'text',
                transition: 'all var(--transition-base)',
                opacity: isReadOnly ? 0.8 : 1
              }}
              onFocus={(e) => {
                if (isReadOnly) {
                  e.target.blur();
                }
              }}
              onKeyDown={(e) => {
                if (isReadOnly) {
                  e.preventDefault();
                  e.stopPropagation();
                }
              }}
            />
            {formErrors.surname && (
              <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
                {formErrors.surname}
              </p>
            )}
          </div>
        </>
      )}
    </div>
  );
};

export default RecipientNameFields;

