/**
 * Custom hook for single disbursement form state management
 */

import { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { createSingleDisbursementSchema } from '@/shared/utils/validation/disbursementSchemas.js';
import logger from '@/shared/utils/logger.js';

const initialPayoutData = {
  firstName: '',
  surname: '',
  fullName: '', // Added for wallet payments
  countryCode: '+233',
  phoneNumber: '',
  amount: '',
  paymentMethod: 'Mobile Money',
  purpose: '',
  provider: '',
  bankName: '',
  accountNumber: '',
  differentMomoNumber: '',
  differentMomoCountryCode: '+233',
  // Bank fields
  accountName: '',
  bankCode: '',
  bankbranchCode: '',
};

const initialSourceAccount = {
  accountType: 'wallet', // wallet, bank, momo
  accountId: '',
};

export const useSingleDisbursementForm = () => {
  const { t } = useTranslation();
  const [useDifferentNumber, setUseDifferentNumber] = useState(false);
  const [payoutData, setPayoutData] = useState(initialPayoutData);
  const [sourceAccount, setSourceAccount] = useState(initialSourceAccount);
  const [formErrors, setFormErrors] = useState({});
  const [accountDetailsFetched, setAccountDetailsFetched] = useState(false);

  const validationSchema = useMemo(
    () => createSingleDisbursementSchema(t),
    [t]
  );

  // Ensure source account is always wallet and set accountId
  useEffect(() => {
    const setWalletAccountId = () => {
      try {
        const userData = JSON.parse(localStorage.getItem('userData') || '{}');

        // For business accounts, use business_id; for individual, use user.id
        const userType = userData.usertype?.toLowerCase();
        const isBusinessAccount = userType === 'business_contact';

        let walletId = null;
        if (isBusinessAccount) {
          walletId =
            userData?.businesses?.[0]?.id ||
            userData?.business?.id ||
            userData?.business_id ||
            userData?.businessId;
        } else {
          walletId = userData.id || userData.userId || userData.user_id;
        }

        setSourceAccount(prev => ({
          ...prev,
          accountType: 'wallet',
          accountId: walletId || prev.accountId, // Only update if we found a wallet ID
        }));
      } catch (error) {
        logger.error('Failed to set wallet account ID:', { error });
        setSourceAccount(prev => ({
          ...prev,
          accountType: 'wallet',
        }));
      }
    };

    setWalletAccountId();
  }, []);

  const handleInputChange = (e) => {
    const { name, value } = e.target;

    // Prevent editing firstName, surname, or fullName if account details were fetched
    if ((name === 'firstName' || name === 'surname' || name === 'fullName') && accountDetailsFetched) {
      return;
    }

    // Remove leading zero from phone numbers
    if ((name === 'phoneNumber' || name === 'differentMomoNumber') && value && value.startsWith('0')) {
      setPayoutData(prev => ({
        ...prev,
        [name]: value.substring(1)
      }));
    }

    // Only reset fetched state if the identifying value actually changes
    if (name === 'phoneNumber' || name === 'differentMomoNumber') {
      const isActuallyChanging = payoutData[name] !== value.substring(value.startsWith('0') ? 1 : 0);
      if (isActuallyChanging && name === 'phoneNumber') {
        setAccountDetailsFetched(false);
        setPayoutData(prev => ({
          ...prev,
          firstName: '',
          surname: '',
          fullName: '',
        }));
      }
    }

    if (name === 'accountNumber' || name === 'bankCode') {
      const isActuallyChanging = payoutData[name] !== value;
      if (isActuallyChanging) {
        setAccountDetailsFetched(false);
        setPayoutData(prev => ({
          ...prev,
          firstName: '',
          surname: '',
          fullName: '',
          accountName: '',
        }));
      }
    }

    setPayoutData(prev => ({
      ...prev,
      [name]: value
    }));

    // Reset fetched state when provider changes
    if (name === 'provider') {
      const isActuallyChanging = payoutData.provider !== value;
      if (isActuallyChanging) {
        setAccountDetailsFetched(false);
        setPayoutData(prev => ({
          ...prev,
          firstName: '',
          surname: '',
          fullName: '',
          accountName: '',
        }));
      }
    }

    // Reset fetched state when payment method changes
    if (name === 'paymentMethod') {
      const isWallet = value === 'Wallet' || value === 'WALLET';
      const isBank = value === 'Bank' || value === 'BANK';
      setAccountDetailsFetched(false);
      setPayoutData(prev => ({
        ...prev,
        // Clear name fields based on payment method
        firstName: isWallet ? '' : (isBank ? prev.firstName : prev.firstName), // Keep for bank and mobile money
        surname: isWallet ? '' : (isBank ? prev.surname : prev.surname), // Keep for bank and mobile money
        fullName: isWallet ? prev.fullName : '', // Keep for wallet, clear for others
        // Don't clear purpose - let user keep it if they want (it's optional for wallet)
        provider: isBank ? '' : prev.provider, // Clear provider for bank
        bankName: '',
        accountNumber: isBank ? prev.accountNumber : '',
        phoneNumber: isWallet ? prev.phoneNumber : '',
        // Clear bank fields when switching away from bank
        accountName: isBank ? prev.accountName : '',
        bankCode: isBank ? prev.bankCode : '',
        bankbranchCode: isBank ? prev.bankbranchCode : '',
      }));
    }

    // Clear field error when user starts typing
    if (formErrors[name]) {
      setFormErrors((prev) => {
        const next = { ...prev };
        delete next[name];
        return next;
      });
    }
  };

  const resetForm = () => {
    setPayoutData(initialPayoutData);
    setSourceAccount(initialSourceAccount);
    setFormErrors({});
    setAccountDetailsFetched(false);
    setUseDifferentNumber(false);
  };

  return {
    payoutData,
    setPayoutData,
    sourceAccount,
    setSourceAccount,
    formErrors,
    setFormErrors,
    useDifferentNumber,
    setUseDifferentNumber,
    accountDetailsFetched,
    setAccountDetailsFetched,
    validationSchema,
    handleInputChange,
    resetForm,
  };
};

