/**
 * CSV Parser for Bulk Disbursement
 * 
 * Parses CSV files for bulk disbursement uploads, validates data,
 * and returns structured records ready for API submission.
 */

import { read, utils } from 'xlsx';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { normalizeChannel } from '@/shared/utils/disbursementUtils.js';
import { generateReference, mapProviderToApiValue, validateReference, mapBankNameToCode } from './helpers';
import logger from '@/shared/utils/logger.js';

// Re-export normalizeChannel for backward compatibility
export { normalizeChannel };

// Expected headers (case-insensitive mapping with variations)
const HEADER_MAP = {
  'reference': 'reference',
  'ref': 'reference',
  'reference number': 'reference',
  'reference_number': 'reference',
  'disburse type': 'disburseType',
  'disburse_type': 'disburseType',
  'disbursetype': 'disburseType',
  'type': 'disburseType',
  'first name': 'firstName',
  'first_name': 'firstName',
  'firstname': 'firstName',
  'fname': 'firstName',
  'last name': 'lastName',
  'last_name': 'lastName',
  'lastname': 'lastName',
  'lname': 'lastName',
  'surname': 'lastName',
  'phone number': 'phoneNumber',
  'phone_number': 'phoneNumber',
  'phonenumber': 'phoneNumber',
  'phone': 'phoneNumber',
  'mobile': 'phoneNumber',
  'provider': 'provider',
  'narration': 'narration',
  'description': 'narration',
  'note': 'narration',
  'channel': 'channel',
  'amount': 'amount',
  'amt': 'amount',
  'value': 'amount',
  'currency': 'currency',
  'curr': 'currency',
  'momo number': 'momoNumber',
  'momo_number': 'momoNumber',
  'momonumber': 'momoNumber',
  'momo': 'momoNumber',
  'mobile money number': 'momoNumber',
  'mobile_money_number': 'momoNumber',
  // Bank-related fields
  'account number': 'accountNumber',
  'account_number': 'accountNumber',
  'accountnumber': 'accountNumber',
  'account no': 'accountNumber',
  'account_no': 'accountNumber',
  'account name': 'accountName',
  'account_name': 'accountName',
  'accountname': 'accountName',
  'bank': 'bankName',
  'bank name': 'bankName',
  'bank_name': 'bankName',
  'bank code': 'bankCode',
  'bank_code': 'bankCode',
  'bankcode': 'bankCode',
  'bank branch code': 'bankbranchCode',
  'bank_branch_code': 'bankbranchCode',
  'bankbranchcode': 'bankbranchCode',
  'branch code': 'bankbranchCode',
  'payment mode': 'paymentMode',
  'payment_mode': 'paymentMode',
  'paymentmode': 'paymentMode',
  'country': 'country'
};

/**
 * Process a single row of data
 */
const processRow = (values, headerIndexes, rowIndex) => {
  // Extract values using header indexes
  // Reference is auto-generated, not read from CSV
  const disburseType = (values[headerIndexes.disburseType]?.toString().trim() || 'deposit').toLowerCase();
  const firstName = values[headerIndexes.firstName]?.toString().trim();
  const lastName = values[headerIndexes.lastName]?.toString().trim();

  // Handle phone number - convert scientific notation to full number
  let phoneNumberRaw = values[headerIndexes.phoneNumber]?.toString().trim() || '';
  if (phoneNumberRaw.includes('E+') || phoneNumberRaw.includes('e+') || phoneNumberRaw.includes('E-') || phoneNumberRaw.includes('e-')) {
    // Convert scientific notation to full number (same logic as momoNumber)
    try {
      const num = parseFloat(phoneNumberRaw);
      if (!isNaN(num)) {
        let numStr = num.toString();
        if (numStr.includes('e') || numStr.includes('E')) {
          try {
            const rounded = Math.round(num);
            numStr = BigInt(rounded).toString();
          } catch {
            const match = phoneNumberRaw.match(/^(\d+\.?\d*)[Ee][+-]?(\d+)$/);
            if (match) {
              const baseStr = match[1];
              const exp = parseInt(match[2]);
              const [integerPart, decimalPart = ''] = baseStr.split('.');
              let fullNumber = integerPart + decimalPart;
              const totalDigitsNeeded = integerPart.length + exp;
              const currentDigits = fullNumber.length;
              if (currentDigits < totalDigitsNeeded) {
                fullNumber = fullNumber.padEnd(totalDigitsNeeded, '0');
              } else if (currentDigits > totalDigitsNeeded) {
                fullNumber = fullNumber.substring(0, totalDigitsNeeded);
              }
              numStr = fullNumber;
            } else {
              numStr = num.toFixed(0);
            }
          }
        }
        phoneNumberRaw = numStr;
      }
    } catch (error) {
      logger.warn('Error converting phone number scientific notation:', { error, phoneNumberRaw });
    }
  }
  // Normalize phone number
  let phoneNumber = cleanNumberForBackend(phoneNumberRaw);

  // Handle local format (e.g., 244123456 -> 233244123456)
  if (phoneNumber && !phoneNumber.startsWith('233')) {
    if (phoneNumber.length === 9) {
      phoneNumber = '233' + phoneNumber;
    } else if (phoneNumber.length === 10 && phoneNumber.startsWith('0')) {
      phoneNumber = '233' + phoneNumber.substring(1);
    }
  }

  // Validate phone number format - should be 9 to 15 digits starting with 233
  if (phoneNumber && !/^233\d{6,12}$/.test(phoneNumber)) {
    const originalValue = values[headerIndexes.phoneNumber]?.toString().trim() || '';
    const isScientificNotation = originalValue.includes('E+') || originalValue.includes('e+') || originalValue.includes('E-') || originalValue.includes('e-');

    let errorMsg;
    if (isScientificNotation) {
      errorMsg = `Row ${rowIndex + 2}: Data Loss Detected. The phone number "${originalValue}" is truncated in your file. This happens when Excel saves large numbers in CSV format. Please use the original Excel (.xlsx) file with the full number, or ensure the cell is formatted as Text.`;
    } else {
      errorMsg = `Row ${rowIndex + 2}: Invalid Phone Number format. Must be a valid Ghana number (e.g., 024XXXXXXX or 23324XXXXXXX). Got: ${phoneNumber}`;
    }
    throw new Error(errorMsg);
  }

  const providerRaw = values[headerIndexes.provider]?.toString().trim();
  const provider = mapProviderToApiValue(providerRaw);
  const narration = values[headerIndexes.narration]?.toString().trim();

  // Extract bank fields
  const accountNumber = values[headerIndexes.accountNumber]?.toString().trim() || '';
  const accountName = values[headerIndexes.accountName]?.toString().trim() || '';
  const bankName = values[headerIndexes.bankName]?.toString().trim() || '';
  let bankCode = values[headerIndexes.bankCode]?.toString().trim() || '';
  
  // If bank code is missing but bank name is present, try to map it
  if (!bankCode && bankName) {
    bankCode = mapBankNameToCode(bankName);
  }

  const bankbranchCode = values[headerIndexes.bankbranchCode]?.toString().trim() || '';
  let paymentMode = values[headerIndexes.paymentMode]?.toString().trim() || '';

  // Detect if this is a bank transaction
  const isBankTransaction = !!(accountNumber || accountName || bankName || bankCode);

  // Default payment mode for bank transactions if not provided
  if (isBankTransaction && !paymentMode) {
    paymentMode = 'Other Bank (GIP-instant)';
  }

  // Auto-detect channel if not provided
  let channelRaw = values[headerIndexes.channel]?.toString().trim() || '';
  if (!channelRaw) {
    channelRaw = isBankTransaction ? 'Bank' : 'Mobile Money';
  }

  // Normalize channel: Mobile Money -> MOBILE_MONEY, Bank -> BANK (for bulk API)
  const channel = normalizeChannel(channelRaw);
  const amountStr = values[headerIndexes.amount]?.toString().trim().replace(/[^\d.-]/g, '');
  const amount = parseFloat(amountStr);

  // Currency handling
  const currencyCSV = values[headerIndexes.currency]?.toString().trim().toUpperCase();
  const currency = currencyCSV || 'GHS';

  // Country handling
  const countryCSV = values[headerIndexes.country]?.toString().trim().toUpperCase();
  const country = countryCSV || 'GHA';

  // Generate reference automatically for each record (always generate new, ignore CSV reference if present)
  // This ensures a unique reference is generated every time the CSV is uploaded
  let reference = generateReference(provider || 'BANK');

  // Validate the generated reference matches the required pattern: ^[0-9a-zA-Z _+]{1,20}$
  // If validation fails, regenerate until valid (shouldn't happen, but safety check)
  let attempts = 0;
  while (!validateReference(reference) && attempts < 10) {
    reference = generateReference(provider || 'BANK');
    attempts++;
  }

  if (!validateReference(reference)) {
    throw new Error(`Row ${rowIndex + 2}: Failed to generate valid reference. Generated: ${reference}`);
  }

  // Handle momo number - convert scientific notation to full number
  let momoNumberRaw = values[headerIndexes.momoNumber]?.toString().trim() || '';
  if (momoNumberRaw.includes('E+') || momoNumberRaw.includes('e+') || momoNumberRaw.includes('E-') || momoNumberRaw.includes('e-')) {
    // Convert scientific notation to full number, preserving all digits
    // Use a more reliable method to avoid precision loss
    try {
      // Parse the scientific notation
      const num = parseFloat(momoNumberRaw);
      if (!isNaN(num)) {
        // Convert to string without scientific notation
        // For very large numbers, use toLocaleString with fullwide to avoid scientific notation
        let numStr = num.toString();

        // If still in scientific notation, use BigInt for integers
        if (numStr.includes('e') || numStr.includes('E')) {
          // Try to use BigInt for better precision
          try {
            // Round to integer first
            const rounded = Math.round(num);
            numStr = BigInt(rounded).toString();
          } catch {
            // Fallback: manually convert
            const match = momoNumberRaw.match(/^(\d+\.?\d*)[Ee][+-]?(\d+)$/);
            if (match) {
              const baseStr = match[1];
              const exp = parseInt(match[2]);
              const [integerPart, decimalPart = ''] = baseStr.split('.');

              // Combine integer and decimal parts
              let fullNumber = integerPart + decimalPart;

              // Calculate total digits needed
              const totalDigitsNeeded = integerPart.length + exp;
              const currentDigits = fullNumber.length;

              if (currentDigits < totalDigitsNeeded) {
                // Pad with zeros
                fullNumber = fullNumber.padEnd(totalDigitsNeeded, '0');
              } else if (currentDigits > totalDigitsNeeded) {
                // Truncate if too many
                fullNumber = fullNumber.substring(0, totalDigitsNeeded);
              }

              numStr = fullNumber;
            } else {
              numStr = num.toFixed(0);
            }
          }
        }
        momoNumberRaw = numStr;
      }
    } catch (error) {
      logger.warn('Error converting scientific notation:', { error, momoNumberRaw });
      // Keep original if conversion fails
    }
  }

  // Remove any non-digit characters only (spaces, dashes, etc.)
  let momoNumber = momoNumberRaw.replace(/[^\d]/g, '');

  // Normalize Mobile Money number
  if (momoNumber) {
    // Remove leading + if present (though regex above removed it, just in case)
    momoNumber = momoNumber.replace(/^\+/, '');

    // Handle local format starting with 0 (e.g., 0244123456 -> 233244123456)
    if (momoNumber.startsWith('0') && momoNumber.length === 10) {
      momoNumber = '233' + momoNumber.substring(1);
    }
    // Handle 9 digit format (e.g., 244123456 -> 233244123456)
    else if (momoNumber.length === 9) {
      momoNumber = '233' + momoNumber;
    }
  }

  // Validate momoNumber format - should be 12 digits starting with 233 (233 + 9 digits)
  // Only validate mopmoNumber if it's not a bank transaction or if it was provided
  if (!isBankTransaction && momoNumber && !/^233\d{9}$/.test(momoNumber)) {
    const originalValue = values[headerIndexes.momoNumber]?.toString().trim() || '';
    const isScientificNotation = originalValue.includes('E+') || originalValue.includes('e+') || originalValue.includes('E-') || originalValue.includes('e-');

    let errorMsg;
    if (isScientificNotation) {
      errorMsg = `Row ${rowIndex + 2}: Data Loss Detected. The number "${originalValue}" is truncated in your file. This happens when Excel saves large numbers in CSV format. Please use the original Excel (.xlsx) file with the full number, or ensure the cell is formatted as Text.`;
    } else {
      errorMsg = `Row ${rowIndex + 2}: Invalid Mobile Money Number format. Must be a valid Ghana mobile money number (e.g., 024XXXXXXX or 23324XXXXXXX). Got: ${momoNumber}`;
    }
    throw new Error(errorMsg);
  }

  // Validation
  if (!firstName) {throw new Error(`Row ${rowIndex + 2}: First Name is required`);}
  if (!lastName) {throw new Error(`Row ${rowIndex + 2}: Last Name is required`);}
  if (!phoneNumber) {throw new Error(`Row ${rowIndex + 2}: Phone Number is required`);}
  if (!narration) {throw new Error(`Row ${rowIndex + 2}: Narration is required`);}
  if (isNaN(amount) || amount <= 0) {throw new Error(`Row ${rowIndex + 2}: Valid Amount is required`);}

  if (isBankTransaction) {
    if (!accountNumber) {throw new Error(`Row ${rowIndex + 2}: Account Number is required for bank transfers`);}
    if (!accountName) {throw new Error(`Row ${rowIndex + 2}: Account Name is required for bank transfers`);}
    if (!bankName && !bankCode) {throw new Error(`Row ${rowIndex + 2}: Bank Name or Bank Code is required for bank transfers`);}
  } else {
    if (!provider) {throw new Error(`Row ${rowIndex + 2}: Provider is required for mobile money transfers`);}
    if (!momoNumber) {throw new Error(`Row ${rowIndex + 2}: Mobile Money Number is required for mobile money transfers`);}
  }

  const record = {
    reference,
    disburseType,
    customer: {
      firstName,
      lastName,
      phoneNumber
    },
    narration,
    channel,
    amount,
    currency,
  };

  if (isBankTransaction) {
    record.provider = provider || 'BANK';
    record.paymentDetails = {
      accountNumber,
      accountName,
      paymentMode,
      bankCode,
      bankbranchCode
    };
  } else {
    record.provider = provider;
    record.paymentDetails = {
      momoNumber: String(momoNumber),
      country: country
    };
  }

  return record;
};

/**
 * Parse Excel file content into disbursement records
 * @param {ArrayBuffer} buffer - Excel file content
 * @param {Function} showError - Error callback function
 * @param {Function} t - Translation function
 * @returns {Array} Array of parsed and validated records
 */
export const parseExcelFile = (buffer, showError, t) => {
  try {
    const workbook = read(buffer, { type: 'array' });
    const firstSheetName = workbook.SheetNames[0];
    const worksheet = workbook.Sheets[firstSheetName];

    // Convert to array of arrays to match CSV structure logic
    // raw: true ensures we get the underlying values (numbers) not formatted strings
    const rows = utils.sheet_to_json(worksheet, { header: 1, raw: true, defval: '' });

    if (rows.length < 2) {
      throw new Error('File must contain at least a header row and one data row');
    }

    const headers = rows[0].map(h => String(h).trim());

    // Map headers to standardized keys
    const headerIndexes = {};
    headers.forEach((header, index) => {
      const normalizedHeader = header.toLowerCase().trim();
      if (HEADER_MAP[normalizedHeader]) {
        headerIndexes[HEADER_MAP[normalizedHeader]] = index;
      }
    });

    // Check required fields (common to all transactions)
    const requiredFields = ['firstName', 'lastName', 'phoneNumber', 'narration', 'amount'];
    const missingFields = requiredFields.filter(field => headerIndexes[field] === undefined);

    if (missingFields.length > 0) {
      const foundHeaders = Object.keys(headerIndexes).join(', ');
      throw new Error(
        `Missing required columns: ${missingFields.join(', ')}\n` +
        `Found columns: ${headers.join(', ')}\n` +
        `Mapped columns: ${foundHeaders || 'none'}`
      );
    }

    const records = [];
    const errors = [];

    rows.slice(1).forEach((row, rowIndex) => {
      // Skip empty rows
      if (!row || row.length === 0 || row.every(cell => !cell)) {return;}

      try {
        const record = processRow(row, headerIndexes, rowIndex);
        records.push(record);
      } catch (error) {
        errors.push({ row: rowIndex + 2, error: error.message });
      }
    });

    if (errors.length > 0) {
      const errorMsg = t
        ? t('errorsInRows', { ns: 'disbursements', count: errors.length, errors: errors.slice(0, 3).map(e => e.error).join('; ') })
        : `Errors in ${errors.length} row(s): ${errors.slice(0, 3).map(e => e.error).join('; ')}`;
      throw new Error(errorMsg);
    }

    return records;
  } catch (error) {
    logger.error('Error parsing Excel file:', { error });
    throw error;
  }
};

/**
 * Parse CSV file content into disbursement records
 * @param {string} text - CSV file content
 * @param {Function} showError - Error callback function
 * @param {Function} t - Translation function
 * @returns {Array} Array of parsed and validated records
 */
export const parseBulkDisbursementCSV = (text, showError, t) => {
  // Remove BOM (Byte Order Mark) if present
  const textWithoutBOM = text.charCodeAt(0) === 0xFEFF ? text.slice(1) : text;

  // Split by lines and filter empty lines
  const lines = textWithoutBOM.split(/\r?\n/).filter(line => line.trim());
  if (lines.length < 2) {
    throw new Error('File must contain at least a header row and one data row');
  }

  // Parse header row with better CSV parsing (handles quoted fields)
  const headerLine = lines[0];
  const headerValues = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < headerLine.length; i++) {
    const char = headerLine[i];
    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      headerValues.push(current.trim().replace(/^"|"$/g, '')); // Remove surrounding quotes
      current = '';
    } else {
      current += char;
    }
  }
  headerValues.push(current.trim().replace(/^"|"$/g, '')); // Add last field

  const headers = headerValues.map(h => h.trim().replace(/"/g, ''));

  // Map headers to standardized keys
  const headerIndexes = {};
  headers.forEach((header, index) => {
    const normalizedHeader = header.toLowerCase().trim();
    if (HEADER_MAP[normalizedHeader]) {
      headerIndexes[HEADER_MAP[normalizedHeader]] = index;
    }
  });

  // Debug: Log headers found
  logger.debug('Parsed headers:', { headers, headerIndexes });

  // Required fields (reference is auto-generated, currency is always GHS, so they're not required in CSV)
  // Required fields
  const requiredFields = ['firstName', 'lastName', 'phoneNumber', 'narration', 'amount'];
  const missingFields = requiredFields.filter(field => headerIndexes[field] === undefined);

  if (missingFields.length > 0) {
    const foundHeaders = Object.keys(headerIndexes).join(', ');
    throw new Error(
      `Missing required columns: ${missingFields.join(', ')}\n` +
      `Found columns: ${headers.join(', ')}\n` +
      `Mapped columns: ${foundHeaders || 'none'}`
    );
  }

  // Parse data rows
  const records = [];
  const errors = [];

  lines.slice(1).forEach((line, rowIndex) => {
    if (!line.trim()) {return;}

    // Parse CSV line handling quoted fields
    const values = [];
    current = '';
    inQuotes = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      if (char === '"') {
        inQuotes = !inQuotes;
      } else if (char === ',' && !inQuotes) {
        values.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }
    values.push(current.trim());

    try {
      const record = processRow(values, headerIndexes, rowIndex);
      records.push(record);
    } catch (error) {
      errors.push({ row: rowIndex + 2, error: error.message });
    }
  });

  if (errors.length > 0) {
    const errorMsg = t
      ? t('errorsInRows', { ns: 'disbursements', count: errors.length, errors: errors.slice(0, 3).map(e => e.error).join('; ') })
      : `Errors in ${errors.length} row(s): ${errors.slice(0, 3).map(e => e.error).join('; ')}`;
    throw new Error(errorMsg);
  }

  return records;
};

