/**
 * Payment Details Section Component
 * Handles amount and purpose/narration inputs
 */

import React from 'react';
import { useTranslation } from 'react-i18next';

const PaymentDetailsSection = ({
  payoutData,
  handleInputChange,
  formErrors,
}) => {
  const { t } = useTranslation();

  return (
    <div className="disbursement-section" data-tour="disbursements-payment-details" style={{
      padding: '24px',
      backgroundColor: 'var(--card)',
      borderRadius: 'var(--radius-lg)',
      border: '1px solid var(--border-primary)'
    }}>
      <h4 className="section-title" style={{
        margin: '0 0 20px 0',
        fontSize: '16px',
        fontWeight: '600',
        color: 'var(--text-primary)',
        display: 'flex',
        alignItems: 'center',
        gap: '8px'
      }}>
        <span className="material-symbols-outlined" style={{ fontSize: '20px', color: 'var(--accent)' }}>
          payment
        </span>
        {t('paymentDetails', { ns: 'disbursements' })}
      </h4>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
        <div data-tour="disbursements-amount">
          <label className="form-label" style={{ marginBottom: '8px', display: 'block' }}>
            {t('amountGh', { ns: 'disbursements' })}
          </label>
          <input
            type="text"
            name="amount"
            value={payoutData.amount}
            onChange={handleInputChange}
            placeholder="0.00"
            inputMode="decimal"
            className="small-search input-large"
            style={{
              width: '100%',
              padding: '12px 16px',
              border: '1px solid var(--border-secondary)',
              borderRadius: 'var(--radius-md)',
              fontSize: '14px',
              backgroundColor: 'var(--bg-input)',
              color: 'var(--text-primary)',
              transition: 'all var(--transition-base)'
            }}
            onFocus={(e) => e.target.style.borderColor = 'var(--accent)'}
            onBlur={(e) => e.target.style.borderColor = 'var(--border-secondary)'}
          />
          {formErrors.amount && (
            <p style={{ color: 'var(--error)', fontSize: '12px', marginTop: '6px' }}>
              {formErrors.amount}
            </p>
          )}
        </div>
      </div>
    </div>
  );
};

export default PaymentDetailsSection;

