/**
 * Bulk Disbursement Batch Input Component
 * 
 * Input field for batch number (required field).
 */

import React from 'react';

const BulkDisbursementBatchInput = ({ 
  batchNumber, 
  onBatchNumberChange,
  isMobile 
}) => {
  return (
    <div 
      data-tour="disbursements-bulk-batch"
      style={{ 
      marginTop: isMobile ? '16px' : '24px',
      padding: isMobile ? '16px' : '20px',
      backgroundColor: 'var(--bg-tertiary)',
      borderRadius: 'var(--radius-md)',
      border: '1px solid var(--border-primary)'
      }}
    >
      <label style={{
        display: 'block',
        marginBottom: isMobile ? '8px' : '10px',
        fontSize: isMobile ? '13px' : '14px',
        fontWeight: '600',
        color: 'var(--text-primary)'
      }}>
        Batch Number
      </label>
      <input
        type="text"
        value={batchNumber}
        onChange={(e) => onBatchNumberChange(e.target.value)}
        placeholder="Enter batch number (required)"
        required
        style={{
          width: '100%',
          padding: isMobile ? '10px 14px' : '12px 16px',
          fontSize: isMobile ? '14px' : '16px',
          border: '1px solid var(--border-secondary)',
          borderRadius: 'var(--radius-md)',
          backgroundColor: 'var(--bg)',
          color: 'var(--text-primary)',
          fontFamily: 'inherit',
          transition: 'all var(--transition-base)',
          boxSizing: 'border-box'
        }}
        onFocus={(e) => {
          e.target.style.borderColor = 'var(--accent)';
          e.target.style.outline = 'none';
        }}
        onBlur={(e) => {
          e.target.style.borderColor = 'var(--border-secondary)';
        }}
      />
      <p style={{
        marginTop: '8px',
        fontSize: isMobile ? '11px' : '12px',
        color: 'var(--text-muted)',
        lineHeight: '1.4'
      }}>
        Batch number is required. Please enter a unique batch number for this disbursement.
      </p>
    </div>
  );
};

export default BulkDisbursementBatchInput;

