/**
 * Disbursement Tabs Component
 * 
 * Tab navigation component for switching between single and bulk
 * disbursement forms. Displays active state and handles tab selection.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';

const DisbursementTabs = ({ activeTab, setActiveTab }) => {
  const { t } = useTranslation();
  return (
    <div 
      data-tour="disbursements-tabs"
      style={{ display: 'flex', gap: '12px', marginBottom: '24px', justifyContent: 'center' }}
    >
      <button
        type="button"
        onClick={() => setActiveTab('single')}
        style={{
          padding: '14px 28px',
          backgroundColor: activeTab === 'single' ? 'var(--accent)' : 'transparent',
          color: activeTab === 'single' ? 'var(--text-inverse)' : 'var(--text-primary)',
          border: `2px solid ${activeTab === 'single' ? 'var(--accent)' : 'var(--border-secondary)'}`,
          borderRadius: 'var(--radius-md)',
          cursor: 'pointer',
          fontSize: '16px',
          fontWeight: '600',
          transition: 'all var(--transition-base)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '10px',
          minWidth: '140px',
          width: '140px'
        }}
        onMouseEnter={(e) => {
          if (activeTab !== 'single') {
            e.currentTarget.style.borderColor = 'var(--accent)';
            e.currentTarget.style.backgroundColor = 'var(--bg-hover)';
          }
        }}
        onMouseLeave={(e) => {
          if (activeTab !== 'single') {
            e.currentTarget.style.borderColor = 'var(--border-secondary)';
            e.currentTarget.style.backgroundColor = 'transparent';
          }
        }}
      >
        <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
          person
        </span>
        {t('single', { ns: 'disbursements' })}
      </button>
      <button
        type="button"
        onClick={() => setActiveTab('bulk')}
        style={{
          padding: '14px 28px',
          backgroundColor: activeTab === 'bulk' ? 'var(--accent)' : 'transparent',
          color: activeTab === 'bulk' ? 'var(--text-inverse)' : 'var(--text-primary)',
          border: `2px solid ${activeTab === 'bulk' ? 'var(--accent)' : 'var(--border-secondary)'}`,
          borderRadius: 'var(--radius-md)',
          cursor: 'pointer',
          fontSize: '16px',
          fontWeight: '600',
          transition: 'all var(--transition-base)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: '10px',
          minWidth: '140px',
          width: '140px'
        }}
        onMouseEnter={(e) => {
          if (activeTab !== 'bulk') {
            e.currentTarget.style.borderColor = 'var(--accent)';
            e.currentTarget.style.backgroundColor = 'var(--bg-hover)';
          }
        }}
        onMouseLeave={(e) => {
          if (activeTab !== 'bulk') {
            e.currentTarget.style.borderColor = 'var(--border-secondary)';
            e.currentTarget.style.backgroundColor = 'transparent';
          }
        }}
      >
        <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>
          upload_file
        </span>
        {t('bulk', { ns: 'disbursements' })}
      </button>
    </div>
  );
};

export default DisbursementTabs;
