/**
 * Custom hook for handling disbursement submission logic
 */

import { useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { securityService } from '@/features/settings/services';
import { disbursementService } from '@/features/disbursements/services';
import { cleanNumberForBackend } from '@/shared/utils/format-utils.js';
import { getChannelFromPaymentMethod, mapProviderToApiValue, validateReference, generateReference } from '@/features/disbursements/utils/helpers.js';
import { useMutation } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { useTransferSender } from '@/features/wallet/hooks/useTransferSender.js';
import { extractRecipientId } from '@/features/wallet/utils/transferUtils.js';
import logger from '@/shared/utils/logger.js';

export const useDisbursementSubmission = ({
  payoutData,
  useDifferentNumber,
  sourceAccount,
  feeData,
  resetForm,
  setShowAmountPreview,
  showAmountPreview,
  isCheckingFee,
  disbursementServiceId,
  selectedRecipient, // Add selectedRecipient for wallet payments
}) => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const [pinModalOpen, setPinModalOpen] = useState(false);
  const [setPinPromptOpen, setSetPinPromptOpen] = useState(false);
  const [checkingPin, setCheckingPin] = useState(false);

  // Get sender ID for wallet transfers (same as TransferFundsModal)
  const { senderId } = useTransferSender();

  // Determine if user is business account
  const isBusiness = useMemo(() => {
    try {
      const userData = JSON.parse(localStorage.getItem('userData') || '{}');
      return userData?.usertype?.toLowerCase() === 'business_contact';
    } catch {
      return false;
    }
  }, []);

  // Use React Query mutation for disbursement creation with automatic cache invalidation
  const createDisbursementMutation = useMutation({
    mutationFn: async (payload) => {
      return await disbursementService.createB2CDeposit(payload, disbursementServiceId);
    },
    invalidateQueries: [
      queryKeys.disbursements.all(), // Invalidate all disbursement queries
      queryKeys.dashboard.all(), // Invalidate dashboard to refresh stats
      queryKeys.wallet.all(), // Invalidate wallet if balance changed
    ],
    onSuccess: (response) => {
      const status = (response?.code || response?.status || '').toString().toUpperCase();
      if (status && status !== '00' && status !== 'SUCCESS') {
        throw new Error(response?.message || t('failedToSubmitDisbursement', { ns: 'disbursements' }));
      }
      success(
        t('processingDisbursement', { ns: 'disbursements', defaultValue: 'Processing disbursement' })
      );
      resetForm();
      if (setShowAmountPreview) {
        setShowAmountPreview(false);
      }
    },
    onError: (err) => {
      // Extract error code from various possible locations
      const errorCode = err?.code ||
        err?.response?.data?.code ||
        err?.data?.code;

      // Extract error message
      const errorMessage = err?.message || '';
      const responseMessage = err?.response?.data?.message ||
        err?.data?.message ||
        err?.response?.message || '';
      const fullMessage = (errorMessage || responseMessage).toLowerCase();

      // Check if this is an insufficient balance error (Code 07 for B2C)
      const isInsufficientBalance =
        errorCode === '07' ||
        fullMessage.includes('insufficient wallet balance') ||
        fullMessage.includes('insufficient balance');

      if (isInsufficientBalance) {
        showError(t('insufficientBalance', { ns: 'wallet', defaultValue: 'Insufficient wallet balance' }));
      } else {
        showError(errorMessage || responseMessage || t('failedToSubmitDisbursement', { ns: 'disbursements' }));
      }
    },
  });

  // Use React Query mutation for wallet-to-wallet transfer (same as TransferFundsModal)
  const walletTransferMutation = useMutation({
    mutationFn: async (payload) => {
      return await disbursementService.transferWalletToWallet(payload);
    },
    invalidateQueries: [
      queryKeys.wallet.all(), // Invalidate all wallet queries
      queryKeys.dashboard.metrics(), // Invalidate dashboard to show updated balance and transactions
      queryKeys.disbursements.all(), // Also invalidate disbursements
    ],
    onSuccess: (response) => {
      if (response?.code === '00' || response?.success || response?.status === 'success') {
        success(t('processingDisbursement', { ns: 'disbursements', defaultValue: 'Processing disbursement' }));
        resetForm();
        if (setShowAmountPreview) {
          setShowAmountPreview(false);
        }
      } else {
        throw new Error(response?.message || t('transferFailed', { ns: 'wallet', defaultValue: 'Transfer failed' }));
      }
    },
    onError: (err) => {
      // Extract error code from various possible locations
      const errorCode = err?.code ||
        err?.response?.data?.code ||
        err?.data?.code;

      // Extract error message
      const errorMessage = err?.message || '';
      const responseMessage = err?.response?.data?.message ||
        err?.data?.message ||
        err?.response?.message || '';
      const fullMessage = errorMessage || responseMessage;

      // Check if this is an insufficient balance error
      const isInsufficientBalance =
        errorCode === '07' ||
        fullMessage.toLowerCase().includes('insufficient wallet balance') ||
        fullMessage.toLowerCase().includes('insufficient balance') ||
        (errorCode === '07' && fullMessage.toLowerCase().includes('user not found'));

      if (isInsufficientBalance) {
        showError(t('insufficientBalance', { ns: 'wallet', defaultValue: 'Insufficient wallet balance' }));
      } else {
        showError(fullMessage || t('transferFailed', { ns: 'wallet', defaultValue: 'Transfer failed' }));
      }
    },
  });

  const handleProceedFromPreview = async () => {
    const channel = getChannelFromPaymentMethod(payoutData.paymentMethod);
    const isWalletPayment = channel === 'WALLET';

    // For wallet payments, skip fee validation (wallet transfers don't use fee calculation)
    if (!isWalletPayment) {
      if (isCheckingFee) {
        showError(
          t('feeCalculationInProgress', {
            ns: 'disbursements',
            defaultValue: 'Please wait for the fees to finish calculating.',
          })
        );
        return;
      }

      if (!feeData) {
        showError(
          t('feeCalculationFailed', {
            ns: 'disbursements',
            defaultValue: 'Unable to calculate fees. Please try again.',
          })
        );
        return;
      }
    }

    // Close preview modal
    setShowAmountPreview(false);

    // Check if PIN is set before opening verify PIN modal

    // First check cache to skip API call if we already know PIN is set
    const cachedPinStatus = sessionStorage.getItem('hasPinSet');
    if (cachedPinStatus === 'true') {
      setPinModalOpen(true);
      return;
    }

    setCheckingPin(true);
    try {
      const resp = await securityService.getAccountSecurity();
      const sec = resp?.data || {};
      const isPinSet = !!(sec.pinSet || sec.hasPin || sec.has_pin || (sec.pin && sec.pin !== null && sec.pin !== 'null'));

      if (!isPinSet) {
        setSetPinPromptOpen(true);
        return;
      }

      // PIN is set, cache the result so we don't need to check again this session
      sessionStorage.setItem('hasPinSet', 'true');

      // PIN is set, open verify PIN modal
      setPinModalOpen(true);
    } catch (error) {
      logger.error('Error checking PIN status:', { error });
      showError(t('unableToVerifyPin', { ns: 'disbursements' }));
    } finally {
      setCheckingPin(false);
    }
  };

  const confirmSubmitAfterPin = async () => {
    setPinModalOpen(false);

    const cleanedCountryCode = cleanNumberForBackend(payoutData.countryCode);
    const cleanedPhoneNumber = cleanNumberForBackend(payoutData.phoneNumber);
    const cleanedDifferentMomoCountryCode = useDifferentNumber ? cleanNumberForBackend(payoutData.differentMomoCountryCode) : '';
    const cleanedDifferentMomoNumber = useDifferentNumber ? cleanNumberForBackend(payoutData.differentMomoNumber) : '';

    const channel = getChannelFromPaymentMethod(payoutData.paymentMethod);
    const amountValue = Number(payoutData.amount);

    if (Number.isNaN(amountValue) || amountValue <= 0) {
      showError(
        t('amountInvalid', {
          ns: 'disbursements',
          defaultValue: 'Enter a valid amount.',
        })
      );
      return;
    }

    // Transaction limit validation removed - users can now make transactions without verification level restrictions

    // Generate and validate reference before building payload
    const reference = generateReference(payoutData.provider || channel);
    if (!validateReference(reference)) {
      showError(
        t('invalidReference', {
          ns: 'disbursements',
          defaultValue: 'Invalid reference format. Reference must be 1-20 characters and contain only alphanumeric characters, spaces, underscores, or plus signs.',
        })
      );
      return;
    }

    // Build payload based on channel type
    // For wallet payments, narration is not used (wallet transfer API doesn't need it)
    const narration = channel === 'WALLET'
      ? '' // Wallet transfers don't use narration
      : (payoutData.purpose?.trim() || t('disbursementNarrationDefault', {
        ns: 'disbursements',
        defaultValue: 'Disbursement payout',
      }));

    let payload = {
      reference: reference,
      disburseType: 'deposit',
      narration,
      channel,
      amount: amountValue,
      currency: feeData?.currency || 'GHS',
    };

    // Handle MOMO channel
    if (channel === 'MOBILE_MONEY' || channel === 'MOMO') {
      if (!payoutData.provider) {
        showError(
          t('selectProvider', { ns: 'disbursements', defaultValue: 'Please select a provider.' })
        );
        return;
      }

      const recipientNumber = `${cleanedCountryCode}${cleanedPhoneNumber}`;
      const provider = mapProviderToApiValue(payoutData.provider);

      // Use the same phone number that the user enters for the recipient
      // This ensures paymentDetails.momoNumber matches customer.phoneNumber
      const momoNumberForPayment = recipientNumber;

      // Build paymentDetails - don't include useDifferentNumber (API doesn't accept it)
      const paymentDetails = {
        momoNumber: momoNumberForPayment,
      };

      // Telecel requires country field in paymentDetails
      if (provider === 'TELECEL') {
        paymentDetails.country = 'GHA';
      }

      payload = {
        ...payload,
        source: 'dashboard', // Add source to track origin of disbursement
        provider,
        customer: {
          firstName: payoutData.firstName?.trim() || '',
          lastName: payoutData.surname?.trim() || '',
          phoneNumber: recipientNumber,
        },
        paymentDetails,
      };
    }
    // Handle BANK channel
    else if (channel === 'BANK') {
      if (!payoutData.accountNumber?.trim()) {
        showError(
          t('enterBankAccountNumber', { ns: 'disbursements', defaultValue: 'Please enter bank account number.' })
        );
        return;
      }

      if (!payoutData.accountName?.trim()) {
        showError(
          t('enterBankAccountName', { ns: 'disbursements', defaultValue: 'Please enter bank account name.' })
        );
        return;
      }

      if (!payoutData.bankName?.trim()) {
        showError(
          t('enterBankName', { ns: 'disbursements', defaultValue: 'Please enter bank name.' })
        );
        return;
      }

      const recipientNumber = `${cleanedCountryCode}${cleanedPhoneNumber}`;

      payload = {
        ...payload,
        source: 'dashboard', // Add source to track origin of disbursement
        provider: 'CAL', // Fixed provider for bank payments
        currency: 'GHS', // Fixed currency for bank payments
        customer: {
          firstName: payoutData.firstName?.trim() || '',
          lastName: payoutData.surname?.trim() || '',
          phoneNumber: recipientNumber,
        },
        paymentDetails: {
          accountNumber: payoutData.accountNumber.trim(),
          accountName: payoutData.accountName.trim(),
          paymentMode: 'Other Bank (GIP-instant)', // Fixed payment mode (hidden from user)
          bankCode: payoutData.bankName.trim(),
          bankbranchCode: payoutData.bankbranchCode?.trim() || '',
        },
      };
    }
    // Handle WALLET channel - use wallet-to-wallet transfer API (same as TransferFundsModal)
    else if (channel === 'WALLET') {
      if (!senderId) {
        showError(
          t('transferSenderRequired', {
            ns: 'wallet',
            defaultValue: 'Unable to determine your wallet account. Please sign in again or contact support.',
          })
        );
        return;
      }

      // Extract recipient ID from selected recipient (same as TransferFundsModal)
      const recipientId = selectedRecipient ? extractRecipientId(selectedRecipient) : null;

      if (!recipientId) {
        showError(
          t('transferRecipientRequired', {
            ns: 'wallet',
            defaultValue: 'Please select a recipient.',
          })
        );
        return;
      }

      // Use the exact amount the user typed (same as TransferFundsModal)
      const amountToSend = payoutData.amount.trim();

      // Build wallet transfer payload (same structure as TransferFundsModal)
      const walletTransferPayload = {
        'x-user-id': senderId, // Use x-user-id as property name to match header name
        amount: amountToSend, // Use the exact string value the user typed
        recipientId,
        serviceId: disbursementServiceId || undefined,
        currency: 'GHS',
        source: 'dashboard', // Add source to track origin of transfer
      };

      logger.debug('Submitting wallet transfer payload:', { walletTransferPayload });

      // Execute wallet transfer mutation - onSuccess and onError are handled in mutation config
      walletTransferMutation.mutate(walletTransferPayload);
      return; // Exit early - don't use the disbursement API
    }
    else {
      showError(
        t('unsupportedChannel', {
          ns: 'disbursements',
          defaultValue: 'This payout method is not yet supported.',
        })
      );
      return;
    }

    // Log payload for debugging
    logger.debug('Submitting disbursement payload:', {
      channel: payload.channel,
      amount: payload.amount,
      customer: payload.customer,
      paymentDetails: payload.paymentDetails,
    });

    // Execute mutation - onSuccess and onError are handled in mutation config
    createDisbursementMutation.mutate(payload);
  };

  return {
    isLoading: createDisbursementMutation.isPending || walletTransferMutation.isPending,
    pinModalOpen,
    setPinModalOpen,
    setPinPromptOpen,
    checkingPin,
    handleProceedFromPreview,
    confirmSubmitAfterPin,
  };
};

