/**
 * Bulk Disbursement Preview Section Component
 * 
 * Displays file preview with summary cards, records table/cards,
 * and pagination controls.
 */

import React from 'react';
import { useTranslation } from 'react-i18next';
import { LoadingSpinner, Pagination } from '@/shared/components';
import '/styles/components/disbursements/BulkDisbursementPreviewEnhanced.css';

const BulkDisbursementPreviewSection = ({
  filePreview,
  isCalculatingFees,
  onRemoveFile,
  parsedRecords,
  paginatedParsedRecords,
  bulkPreviewStartIndex,
  bulkPreviewPage,
  bulkPreviewItemsPerPage,
  onPageChange,
  isMobile,
  isTablet
}) => {
  const { t } = useTranslation();

  return (
    <div className="bulk-preview-enhanced">
      {/* Success Header */}
      <div className="bulk-preview-success-header">
        <div className="bulk-preview-success-content">
          <div className="bulk-preview-success-info">
            <div className="bulk-preview-success-title">
              <div className="bulk-preview-success-icon">
                <span className="material-symbols-outlined">check_circle</span>
              </div>
              File Uploaded Successfully
            </div>
            <div className="bulk-preview-success-details">
              {filePreview.filename} ({filePreview.size})
            </div>
            {isCalculatingFees && (
              <div className="bulk-preview-success-loading">
                <LoadingSpinner size="small" />
                Calculating fees for all transactions...
              </div>
            )}
          </div>
          <button className="bulk-preview-remove-btn" onClick={onRemoveFile}>
            <span className="material-symbols-outlined" style={{ fontSize: '16px', marginRight: '4px' }}>
              close
            </span>
            Remove File
          </button>
        </div>
      </div>

      {/* Summary Cards Section */}
      <div className="bulk-preview-summary-section">
        <div className="bulk-preview-summary-grid">
          <div className="bulk-preview-summary-card">
            <div className="bulk-preview-summary-icon">
              <span className="material-symbols-outlined">format_list_numbered</span>
            </div>
            <div className="bulk-preview-summary-label">Total Records</div>
            <div className="bulk-preview-summary-value">{filePreview.recordCount}</div>
          </div>
          
          <div className="bulk-preview-summary-card">
            <div className="bulk-preview-summary-icon">
              <span className="material-symbols-outlined">payments</span>
            </div>
            <div className="bulk-preview-summary-label">Total Amount</div>
            <div className="bulk-preview-summary-value">
              {filePreview.currency} {parseFloat(filePreview.totalAmount || 0).toLocaleString()}
            </div>
          </div>
          
          {filePreview.totalFees !== undefined && (
            <div className="bulk-preview-summary-card">
              <div className="bulk-preview-summary-icon">
                <span className="material-symbols-outlined">receipt_long</span>
              </div>
              <div className="bulk-preview-summary-label">Total Fees</div>
              <div className="bulk-preview-summary-value">
                {filePreview.currency} {parseFloat(filePreview.totalFees || 0).toLocaleString()}
              </div>
            </div>
          )}
          
          {filePreview.totalPayable !== undefined && (
            <div className="bulk-preview-summary-card highlight">
              <div className="bulk-preview-summary-icon">
                <span className="material-symbols-outlined">account_balance_wallet</span>
              </div>
              <div className="bulk-preview-summary-label">Total Payable</div>
              <div className="bulk-preview-summary-value">
                {filePreview.currency} {parseFloat(filePreview.totalPayable || 0).toLocaleString()}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Data Table Section */}
      <div className="bulk-preview-data-section">
        {isMobile ? (
          // Mobile Card View
          <div className="bulk-preview-mobile-grid">
            {paginatedParsedRecords.length > 0 ? (
              paginatedParsedRecords.map((record, index) => (
                <div key={bulkPreviewStartIndex + index} className="bulk-preview-mobile-card">
                  <div className="bulk-preview-mobile-header">
                    <div className="bulk-preview-mobile-reference">Reference</div>
                    <div className="bulk-preview-mobile-amount">
                      {record.currency} {record.amount.toLocaleString()}
                    </div>
                  </div>
                  <div className="bulk-preview-mobile-body">
                    <div className="bulk-preview-mobile-row">
                      <div>
                        <div className="bulk-preview-mobile-label">Customer</div>
                        <div className="bulk-preview-mobile-value">
                          {record.customer.firstName} {record.customer.lastName}
                        </div>
                        <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '2px' }}>
                          {record.customer.phoneNumber}
                        </div>
                      </div>
                      <div style={{ textAlign: 'right' }}>
                        <div className="bulk-preview-mobile-label">Provider</div>
                        <div className="bulk-preview-mobile-value">{record.provider}</div>
                        <div className="bulk-preview-provider-badge">
                          {record.paymentDetails.momoNumber}
                        </div>
                      </div>
                    </div>
                    {record.feeData && (
                      <div className="bulk-preview-mobile-row">
                        <div>
                          <div className="bulk-preview-mobile-label">Processing Fee</div>
                          <div className="bulk-preview-mobile-value">
                            {parseFloat(record.feeData.feeApplied || 0).toLocaleString()}
                          </div>
                        </div>
                      </div>
                    )}
                  </div>
                </div>
              ))
            ) : (
              <div className="bulk-preview-empty-state">
                <div className="bulk-preview-empty-icon">
                  <span className="material-symbols-outlined">inbox</span>
                </div>
                <div className="bulk-preview-empty-title">No Records to Display</div>
                <div className="bulk-preview-empty-description">
                  Your file appears to be empty or the format is not supported.
                </div>
              </div>
            )}
          </div>
        ) : (
          // Desktop/Tablet Table View
          <div className="bulk-preview-table-container">
            <table className="bulk-preview-table">
              <thead>
                <tr>
                  <th>Reference</th>
                  <th>First Name</th>
                  <th>Last Name</th>
                  <th>Phone Number</th>
                  <th>Provider</th>
                  <th>Amount</th>
                  <th>Currency</th>
                  <th>Mobile Money Number</th>
                  <th>Description</th>
                  {paginatedParsedRecords[0]?.feeData && <th>Processing Fee</th>}
                </tr>
              </thead>
              <tbody>
                {paginatedParsedRecords.length > 0 ? (
                  paginatedParsedRecords.map((record, index) => (
                    <tr key={bulkPreviewStartIndex + index}>
                      <td>{record.reference}</td>
                      <td>{record.customer?.firstName || 'N/A'}</td>
                      <td>{record.customer?.lastName || 'N/A'}</td>
                      <td>{record.customer?.phoneNumber || 'N/A'}</td>
                      <td>
                        <div className="bulk-preview-provider-cell">
                          <span>{record.provider}</span>
                        </div>
                      </td>
                      <td>
                        <div className="bulk-preview-amount-cell">
                          {record.amount.toLocaleString()}
                        </div>
                      </td>
                      <td>{record.currency}</td>
                      <td>{record.paymentDetails?.momoNumber || 'N/A'}</td>
                      <td>{record.description || 'N/A'}</td>
                      {record.feeData && (
                        <td>
                          <div className="bulk-preview-fee-info">
                            {parseFloat(record.feeData.feeApplied || 0).toLocaleString()}
                          </div>
                        </td>
                      )}
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan="10">
                      <div className="bulk-preview-empty-state">
                        <div className="bulk-preview-empty-icon">
                          <span className="material-symbols-outlined">inbox</span>
                        </div>
                        <div className="bulk-preview-empty-title">No Records to Display</div>
                        <div className="bulk-preview-empty-description">
                          Your file appears to be empty or the format is not supported.
                        </div>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination Section */}
      {parsedRecords.length > 0 && (
        <div className="bulk-preview-pagination-section">
          <div className="bulk-preview-pagination">
            <div className="bulk-preview-pagination-info">
              Showing {bulkPreviewStartIndex + 1}-{Math.min(bulkPreviewStartIndex + paginatedParsedRecords.length, parsedRecords.length)} of {parsedRecords.length} records
            </div>
            <div className="bulk-preview-pagination-controls">
              <Pagination
                currentPage={bulkPreviewPage}
                totalItems={parsedRecords.length}
                itemsPerPage={bulkPreviewItemsPerPage}
                onPageChange={onPageChange}
                showInfo={false}
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BulkDisbursementPreviewSection;

