/**
 * Token Protection Utilities
 * 
 * Provides safeguards to prevent accidental token loss and ensures
 * tokens persist correctly after successful API operations.
 */

import logger from './logger';

/**
 * Safely gets the auth token from localStorage
 * @returns {string|null} The auth token or null if not found
 */
export const getProtectedToken = () => {
  try {
    if (typeof localStorage === 'undefined') {
      return null;
    }
    return localStorage.getItem('authToken');
  } catch (error) {
    logger.error('Error reading auth token', { error });
    return null;
  }
};

/**
 * Safely gets the refresh token from localStorage
 * @returns {string|null} The refresh token or null if not found
 */
export const getProtectedRefreshToken = () => {
  try {
    if (typeof localStorage === 'undefined') {
      return null;
    }
    return localStorage.getItem('refreshToken');
  } catch (error) {
    logger.error('Error reading refresh token', { error });
    return null;
  }
};

/**
 * Verifies that tokens exist before making an API call
 * Throws an error if tokens are missing to prevent API calls without auth
 * @throws {Error} If tokens are missing
 */
export const verifyTokensBeforeRequest = () => {
  const token = getProtectedToken();
  const refreshToken = getProtectedRefreshToken();
  const isAuthenticated = localStorage.getItem('isAuthenticated');
  
  if (isAuthenticated === 'true' && !token && !refreshToken) {
    logger.warn('Tokens missing but user marked as authenticated - this may cause issues', {
      isAuthenticated,
      hasToken: !!token,
      hasRefreshToken: !!refreshToken
    });
  }
  
  return { token, refreshToken, isAuthenticated };
};

/**
 * Ensures tokens are preserved after an API operation
 * Can be called after successful API calls to verify tokens still exist
 * @param {Function} onTokenMissing - Callback if tokens are missing (optional)
 */
export const ensureTokensPreserved = (onTokenMissing = null) => {
  const token = getProtectedToken();
  const refreshToken = getProtectedRefreshToken();
  const isAuthenticated = localStorage.getItem('isAuthenticated');
  
  // If user was authenticated but tokens are now missing, something went wrong
  if (isAuthenticated === 'true' && !token && !refreshToken) {
    logger.error('CRITICAL: Tokens were cleared after API operation', {
      isAuthenticated,
      hadToken: false,
      hadRefreshToken: false
    });
    if (onTokenMissing) {
      onTokenMissing();
    }
    return false;
  }
  
  return true;
};

/**
 * Creates a token snapshot before an operation
 * @returns {Object} Snapshot of current token state
 */
export const createTokenSnapshot = () => {
  return {
    authToken: getProtectedToken(),
    refreshToken: getProtectedRefreshToken(),
    isAuthenticated: localStorage.getItem('isAuthenticated'),
    timestamp: Date.now(),
  };
};

/**
 * Restores tokens from a snapshot if they were accidentally cleared
 * @param {Object} snapshot - Token snapshot created before operation
 * @returns {boolean} True if restoration was needed and performed
 */
export const restoreTokensIfNeeded = (snapshot) => {
  const currentToken = getProtectedToken();
  const currentRefreshToken = getProtectedRefreshToken();
  const currentAuth = localStorage.getItem('isAuthenticated');
  
  // If tokens were cleared but snapshot has them, restore
  if (snapshot.isAuthenticated === 'true' && 
      snapshot.authToken && 
      !currentToken && 
      snapshot.refreshToken &&
      !currentRefreshToken) {
    logger.warn('Restoring tokens from snapshot - tokens were accidentally cleared', {
      snapshotTimestamp: snapshot.timestamp,
      currentTime: Date.now()
    });
    try {
      if (snapshot.authToken) {
        localStorage.setItem('authToken', snapshot.authToken);
      }
      if (snapshot.refreshToken) {
        localStorage.setItem('refreshToken', snapshot.refreshToken);
      }
      if (snapshot.isAuthenticated) {
        localStorage.setItem('isAuthenticated', snapshot.isAuthenticated);
      }
      return true;
    } catch (error) {
      logger.error('Failed to restore tokens from snapshot', { error, snapshot });
      return false;
    }
  }
  
  return false;
};





