/**
 * Amount Preview Section Component
 * Displays the amount to be disbursed
 */

import React from 'react';
import { useTranslation } from 'react-i18next';

const AmountPreviewSection = ({ amount }) => {
  const { t } = useTranslation();

  if (!amount || parseFloat(amount) <= 0) {
    return null;
  }

  return (
    <div className="amount-preview-section" style={{
      padding: '20px',
      backgroundColor: 'var(--info-bg)',
      borderRadius: 'var(--radius-lg)',
      border: '1px solid var(--info)',
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center',
      flexWrap: 'wrap',
      gap: '16px'
    }}>
      <div>
        <p style={{ margin: 0, fontSize: '14px', color: 'var(--text-muted)' }}>
          {t('amountToDisburse', { ns: 'disbursements' })}
        </p>
        <p style={{ margin: '8px 0 0 0', fontSize: '24px', fontWeight: '700', color: 'var(--accent)' }}>
          GHS {parseFloat(amount).toLocaleString('en-US', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
        </p>
      </div>
      <div style={{ textAlign: 'right', maxWidth: '320px' }}>
        <p style={{ margin: 0, fontSize: '13px', color: 'var(--text-muted)' }}>
          {t('feeInfoNote', {
            ns: 'disbursements',
            defaultValue: 'Fees will be calculated when you proceed to confirmation.',
          })}
        </p>
      </div>
    </div>
  );
};

export default AmountPreviewSection;

