/**
 * Single Disbursement Form Component
 * 
 * Form for creating individual payment disbursements. Collects recipient
 * information, amount, payment method, and handles PIN verification for
 * transaction security. Supports Mobile Money and bank transfers.
 */

import React, { useState, useEffect, useMemo } from 'react';
import { createPortal } from 'react-dom';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { LoadingSpinner } from '@/shared/components';
import { VerifyPinModal, SetPinPromptModal } from '@/features/settings/components';
import DisbursementPreviewModal from './DisbursementPreviewModal';
import ProgressIndicator from './ProgressIndicator';
import { countries } from '@/shared/utils/constants/countries-with-flags.js';
import { mapFieldErrors } from '@/shared/utils/validation/helpers.js';
import { getChannelFromPaymentMethod } from '@/features/disbursements/utils/helpers.js';
import { logger } from '@/shared/utils/logger.js';

// Hooks
import { useSingleDisbursementForm } from '@/features/disbursements/hooks/useSingleDisbursementForm.js';
import { useAccountValidation } from '@/shared/hooks/use-account-validation.js';
import { useFeeCalculation } from '@/features/disbursements/hooks/useFeeCalculation.js';
import { useTransferFeeCalculation } from '@/features/wallet/hooks/useTransferFeeCalculation.js';
import { useDisbursementServices } from '@/features/disbursements/hooks/useDisbursementServices.js';
import { useDisbursementSubmission } from '@/features/disbursements/hooks/useDisbursementSubmission.js';

// Form Sections
import SourceAccountSection from './formSections/SourceAccountSection';
import DestinationAccountSection from './formSections/DestinationAccountSection';
import PaymentDetailsSection from './formSections/PaymentDetailsSection';
import PurposeSection from './formSections/PurposeSection';
import AmountPreviewSection from './formSections/AmountPreviewSection';
import DisbursementFormStyles from './formSections/DisbursementFormStyles';

const SingleDisbursementForm = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();
  const [showAmountPreview, setShowAmountPreview] = useState(false);
  const [selectedWalletRecipient, setSelectedWalletRecipient] = useState(null); // Store selected recipient for wallet payments
  const [windowWidth, setWindowWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 1024);
  const isMobile = windowWidth <= 768;

  // Form state management
  const {
    payoutData,
    setPayoutData,
    sourceAccount,
    setSourceAccount,
    formErrors,
    setFormErrors,
    useDifferentNumber,
    setUseDifferentNumber,
    accountDetailsFetched,
    setAccountDetailsFetched,
    validationSchema,
    handleInputChange,
    resetForm,
  } = useSingleDisbursementForm();

  // Progress flow state
  const [currentStep, setCurrentStep] = useState('amount');
  const [completedSteps, setCompletedSteps] = useState([]);

  // Update progress based on form completion
  useEffect(() => {
    const newCompleted = [];
    const isWalletPayment = payoutData.paymentMethod === 'Wallet' || payoutData.paymentMethod === 'WALLET';

    if (payoutData.amount && parseFloat(payoutData.amount) > 0) {
      newCompleted.push('amount');
      if (payoutData.paymentMethod &&
        ((payoutData.paymentMethod === 'Wallet' && payoutData.recipientId) ||
          (payoutData.paymentMethod !== 'Wallet' && payoutData.phoneNumber))) {
        newCompleted.push('destination');

        // Check if purpose is completed (only for non-wallet payments)
        if (isWalletPayment || payoutData.purpose) {
          newCompleted.push('purpose');
          setCurrentStep('review');
        } else {
          setCurrentStep('purpose');
        }
      } else {
        setCurrentStep('destination');
      }
    } else {
      setCurrentStep('amount');
    }
    setCompletedSteps(newCompleted);
  }, [payoutData.amount, payoutData.paymentMethod, payoutData.phoneNumber, payoutData.recipientId, payoutData.purpose]);

  // Account validation
  const {
    isValidatingAccount,
    accountDetailsFetched: accountFetched,
    setAccountDetailsFetched: setAccountFetched,
    fetchMobileMoneyAccountDetails,
    fetchBankAccountDetails,
  } = useAccountValidation(
    payoutData,
    payoutData.paymentMethod,
    setPayoutData,
    setFormErrors,
    showError,
    success,
    t
  );

  // Sync account fetched state
  useEffect(() => {
    if (accountFetched) {
      logger.info('Syncing accountFetched STATE: TRUE', { paymentMethod: payoutData.paymentMethod });
    }
    setAccountDetailsFetched(accountFetched);
  }, [accountFetched, setAccountDetailsFetched, payoutData.paymentMethod]);

  // Services
  const { disbursementServiceId } = useDisbursementServices();

  // Fee calculation
  const { feeData, setFeeData, isCheckingFee, checkFee } = useFeeCalculation(disbursementServiceId);
  const { feeData: walletFeeData, isCheckingFee: isCheckingWalletFee } = useTransferFeeCalculation(
    payoutData.amount,
    disbursementServiceId
  );

  // Fee calculation effect
  useEffect(() => {
    if (showAmountPreview && payoutData.amount) {
      const channel = getChannelFromPaymentMethod(payoutData.paymentMethod);
      if (channel !== 'WALLET' && disbursementServiceId) {
        checkFee(payoutData.amount, channel);
      } else if (channel === 'WALLET') {
        setFeeData(walletFeeData || null);
      }
    } else if (!showAmountPreview) {
      setFeeData(null);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showAmountPreview, payoutData.amount, payoutData.paymentMethod, disbursementServiceId, walletFeeData]);

  const isWalletPayment = payoutData.paymentMethod === 'Wallet' || payoutData.paymentMethod === 'WALLET';
  const effectiveFeeData = isWalletPayment ? walletFeeData : feeData;
  const effectiveIsCheckingFee = isWalletPayment ? isCheckingWalletFee : isCheckingFee;

  // Submission logic
  const {
    isLoading,
    pinModalOpen,
    setPinModalOpen,
    setPinPromptOpen,
    checkingPin,
    handleProceedFromPreview,
    confirmSubmitAfterPin,
  } = useDisbursementSubmission({
    payoutData,
    useDifferentNumber,
    sourceAccount,
    feeData: effectiveFeeData,
    resetForm,
    setShowAmountPreview,
    showAmountPreview,
    isCheckingFee: effectiveIsCheckingFee,
    disbursementServiceId,
    selectedRecipient: selectedWalletRecipient, // Pass selected recipient for wallet payments
  });

  // Country selection
  const selectedCountry = countries.find(c => c.dialCode === payoutData.countryCode) || countries.find(c => c.code === 'GH');

  // Reset selected recipient when payment method changes
  useEffect(() => {
    if (payoutData.paymentMethod !== 'Wallet' && payoutData.paymentMethod !== 'WALLET') {
      setSelectedWalletRecipient(null);
    }
  }, [payoutData.paymentMethod]);

  // Track window width for responsive button styling
  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();

    logger.info('Submitting single disbursement form', { payoutData });
    const result = validationSchema.safeParse(payoutData);

    if (!result.success) {
      const errors = mapFieldErrors(result.error);
      logger.warn('Validation failed for single disbursement', { errors, payoutData });
      setFormErrors(errors);
      
      // Handle missing names specifically for better UX
      if (errors.firstName || errors.surname) {
        showError(t('verifyAccountDetailsFirst', { 
          ns: 'disbursements', 
          defaultValue: 'Please verify account details to fill in recipient names.' 
        }));
      } else {
        const firstError = Object.values(errors)[0];
        showError(firstError || t('fillAllFields', { ns: 'disbursements' }));
      }
      return;
    }

    setFormErrors({});
    const parsedValues = result.data;
    setPayoutData((prev) => ({
      ...prev,
      ...parsedValues,
      amount: parsedValues.amount.toString(),
    }));
    setShowAmountPreview(true);
  };

  return (
    <>
      <DisbursementFormStyles />
      <form onSubmit={handleSubmit}>
        <div className="disbursement-form-container" style={{
          display: 'flex',
          flexDirection: 'column',
          gap: '24px',
          width: '100%',
          maxWidth: '100%',
          boxSizing: 'border-box',
          padding: '0'
        }}>
          {/* Wallet Source Indicator - Refined and Elegant */}
          <div style={{
            display: 'flex',
            alignItems: 'center',
            padding: '12px 24px',
            backgroundColor: 'var(--card)',
            borderRadius: 'var(--radius-lg)',
            border: '1px solid var(--border-secondary)',
            gap: '12px',
            marginBottom: '8px',
            boxShadow: 'var(--shadow-sm)'
          }}>
            <div style={{
              width: '32px',
              height: '32px',
              borderRadius: '8px',
              backgroundColor: 'var(--accent-light, rgba(0, 123, 255, 0.08))',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              color: 'var(--accent)'
            }}>
              <span className="material-symbols-outlined" style={{ fontSize: '18px' }}>account_balance_wallet</span>
            </div>
            <div style={{ fontSize: '13px', fontWeight: '500', color: 'var(--text-secondary)' }}>
              {t('payingFromWallet', { ns: 'disbursements', defaultValue: 'Paying from your wallet' })}
            </div>
          </div>

          {formErrors._form && (
            <div
              style={{
                padding: '16px',
                borderRadius: 'var(--radius-lg)',
                border: '1px solid var(--error)',
                backgroundColor: 'var(--error-bg, rgba(220, 53, 69, 0.05))',
                color: 'var(--error)',
                fontSize: '13px',
                display: 'flex',
                alignItems: 'center',
                gap: '10px'
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '20px' }}>error</span>
              {formErrors._form}
            </div>
          )}

          {/* Payment Details Section - Amount */}
          <div style={{
            backgroundColor: 'var(--card)',
            borderRadius: 'var(--radius-xl)',
            border: currentStep === 'amount' ? '1px solid var(--accent)' : '1px solid var(--border-primary)',
            transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
            boxShadow: currentStep === 'amount' ? '0 10px 30px rgba(0, 123, 255, 0.08)' : 'var(--shadow-sm)',
            transform: currentStep === 'amount' ? 'translateY(-2px)' : 'none',
            overflow: 'hidden'
          }}>
            <div style={{ padding: '32px' }}>
              <ProgressIndicator
                stepNumber={1}
                isActive={currentStep === 'amount'}
                isCompleted={completedSteps.includes('amount')}
                label={t('enterAmount', { ns: 'disbursements', defaultValue: 'Enter Amount' })}
              />
              <div style={{ marginTop: '24px' }}>
                <PaymentDetailsSection
                  payoutData={payoutData}
                  handleInputChange={handleInputChange}
                  formErrors={formErrors}
                />
              </div>
            </div>
          </div>

          {/* Destination Account Section */}
          <div style={{
            backgroundColor: 'var(--card)',
            borderRadius: 'var(--radius-xl)',
            border: currentStep === 'destination' ? '1px solid var(--accent)' : '1px solid var(--border-primary)',
            transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
            boxShadow: currentStep === 'destination' ? '0 10px 30px rgba(0, 123, 255, 0.08)' : 'var(--shadow-sm)',
            transform: currentStep === 'destination' ? 'translateY(-2px)' : 'none',
            overflow: 'hidden'
          }}>
            <div style={{ padding: '32px' }}>
              <ProgressIndicator
                stepNumber={2}
                isActive={currentStep === 'destination'}
                isCompleted={completedSteps.includes('destination')}
                label={t('addRecipient', { ns: 'disbursements', defaultValue: 'Add Recipient' })}
              />
              <div style={{ marginTop: '24px' }}>
                <DestinationAccountSection
                  payoutData={payoutData}
                  handleInputChange={handleInputChange}
                  formErrors={formErrors}
                  isValidatingAccount={isValidatingAccount}
                  accountDetailsFetched={accountDetailsFetched}
                  selectedCountry={selectedCountry}
                  onFetchMobileMoneyAccountDetails={fetchMobileMoneyAccountDetails}
                  onFetchBankAccountDetails={fetchBankAccountDetails}
                  setPayoutData={setPayoutData}
                  setFormErrors={setFormErrors}
                  onWalletRecipientSelected={setSelectedWalletRecipient}
                />
              </div>
            </div>
          </div>

          {/* Purpose Section - Only shown for non-wallet payments */}
          {!isWalletPayment && (
            <div style={{
              backgroundColor: 'var(--card)',
              borderRadius: 'var(--radius-xl)',
              border: currentStep === 'purpose' ? '1px solid var(--accent)' : '1px solid var(--border-primary)',
              transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
              boxShadow: currentStep === 'purpose' ? '0 10px 30px rgba(0, 123, 255, 0.08)' : 'var(--shadow-sm)',
              transform: currentStep === 'purpose' ? 'translateY(-2px)' : 'none',
              overflow: 'hidden'
            }}>
              <div style={{ padding: '32px' }}>
                <ProgressIndicator
                  stepNumber={3}
                  isActive={currentStep === 'purpose'}
                  isCompleted={completedSteps.includes('purpose')}
                  label={t('purpose', { ns: 'disbursements', defaultValue: 'Purpose' })}
                />
                <div style={{ marginTop: '24px' }}>
                  <PurposeSection
                    payoutData={payoutData}
                    handleInputChange={handleInputChange}
                    formErrors={formErrors}
                  />
                </div>
              </div>
            </div>
          )}

          {/* Amount Preview - Only show when amount is entered */}
          {payoutData.amount && parseFloat(payoutData.amount) > 0 && (
            <div style={{
              backgroundColor: 'var(--card)',
              borderRadius: 'var(--radius-xl)',
              border: currentStep === 'review' ? '1px solid var(--accent)' : '1px solid var(--border-primary)',
              transition: 'all 0.4s cubic-bezier(0.4, 0, 0.2, 1)',
              boxShadow: currentStep === 'review' ? '0 10px 30px rgba(0, 123, 255, 0.08)' : 'var(--shadow-sm)',
              transform: currentStep === 'review' ? 'translateY(-2px)' : 'none',
              overflow: 'hidden'
            }}>
              <div style={{ padding: '32px' }}>
                <ProgressIndicator
                  stepNumber={isWalletPayment ? 3 : 4}
                  isActive={currentStep === 'review'}
                  isCompleted={false}
                  label={t('reviewPayment', { ns: 'disbursements', defaultValue: 'Review Payment' })}
                />
                <div style={{ marginTop: '24px' }}>
                  <AmountPreviewSection amount={payoutData.amount} />
                </div>
              </div>
            </div>
          )}

          {/* Submit Button - Premium Refined */}
          <div style={{
            display: 'flex',
            justifyContent: 'center',
            paddingTop: '16px',
            paddingBottom: '32px'
          }}>
            <button
              type="submit"
              disabled={!payoutData.amount || parseFloat(payoutData.amount) <= 0 || !payoutData.paymentMethod}
              style={{
                padding: '18px 64px',
                backgroundColor: (!payoutData.amount || parseFloat(payoutData.amount) <= 0 || !payoutData.paymentMethod)
                  ? 'var(--bg-secondary)'
                  : 'var(--accent)',
                color: 'var(--text-inverse)',
                border: 'none',
                borderRadius: 'var(--radius-lg)',
                cursor: (!payoutData.amount || parseFloat(payoutData.amount) <= 0 || !payoutData.paymentMethod)
                  ? 'not-allowed'
                  : 'pointer',
                fontSize: '16px',
                fontWeight: '600',
                transition: 'all 0.3s cubic-bezier(0.4, 0, 0.2, 1)',
                display: 'inline-flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: '12px',
                width: isMobile ? '100%' : 'auto',
                opacity: (!payoutData.amount || parseFloat(payoutData.amount) <= 0 || !payoutData.paymentMethod) ? 0.6 : 1,
                boxShadow: (!payoutData.amount || parseFloat(payoutData.amount) <= 0 || !payoutData.paymentMethod)
                  ? 'none'
                  : '0 8px 24px rgba(0, 123, 255, 0.25)'
              }}
              onMouseEnter={(e) => {
                if (payoutData.amount && parseFloat(payoutData.amount) > 0 && payoutData.paymentMethod) {
                  e.currentTarget.style.transform = 'translateY(-2px)';
                  e.currentTarget.style.boxShadow = '0 12px 30px rgba(0, 123, 255, 0.35)';
                }
              }}
              onMouseLeave={(e) => {
                if (payoutData.amount && parseFloat(payoutData.amount) > 0 && payoutData.paymentMethod) {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 8px 24px rgba(0, 123, 255, 0.25)';
                }
              }}
            >
              <span className="material-symbols-outlined" style={{ fontSize: '22px' }}>
                {completedSteps.includes('destination') ? 'verified' : 'arrow_forward'}
              </span>
              {completedSteps.includes('destination')
                ? t('reviewPayment', { ns: 'disbursements', defaultValue: 'Review Payment' })
                : t('continue', { ns: 'disbursements', defaultValue: 'Continue' })
              }
            </button>
          </div>
        </div>
      </form>

      {/* Modals */}
      {pinModalOpen && (
        <VerifyPinModal
          open={pinModalOpen}
          onClose={() => setPinModalOpen(false)}
          onVerified={confirmSubmitAfterPin}
        />
      )}

      {setPinPromptOpen && (
        <SetPinPromptModal
          open={setPinPromptOpen}
          onClose={() => setPinPromptOpen(false)}
        />
      )}

      {/* <DisbursementPreviewModal
        open={showAmountPreview}
        onClose={() => setShowAmountPreview(false)}
        payoutData={payoutData}
        useDifferentNumber={useDifferentNumber}
        onSubmit={handleProceedFromPreview}
        feeData={feeData}
        isCheckingFee={isCheckingFee}
      /> */}


  <DisbursementPreviewModal
    open={showAmountPreview}
    onClose={() => setShowAmountPreview(false)}
    payoutData={payoutData}
    useDifferentNumber={useDifferentNumber}
    onSubmit={handleProceedFromPreview}
    feeData={effectiveFeeData}
    isCheckingFee={effectiveIsCheckingFee}
/>

      {/* Loading Overlay */}
      {isLoading && createPortal(
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'rgba(0, 0, 0, 0.5)',
          backdropFilter: 'blur(4px)',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 10003
        }}>
          <div style={{
            backgroundColor: 'var(--card)',
            borderRadius: 'var(--radius-lg)',
            padding: '48px',
            boxShadow: 'var(--shadow-xl)',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
            minWidth: '120px',
            minHeight: '120px'
          }}>
            <LoadingSpinner size="large" />
          </div>
        </div>,
        document.body
      )}
    </>
  );
};

export default SingleDisbursementForm;
