/**
 * Custom Hook for Bulk Disbursement Logic
 * 
 * Manages state and business logic for bulk disbursement operations,
 * including file upload, CSV parsing, fee calculation, and submission.
 */

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { disbursementService } from '@/features/disbursements/services';
import { securityService } from '@/features/settings/services';
import { parseBulkDisbursementCSV, generateCSVTemplate } from '@/features/disbursements/utils/parseBulkDisbursementCSV.js';
import { useDisbursementServices } from '@/features/disbursements/hooks/useDisbursementServices.js';
import logger from '@/shared/utils/logger.js';

export const useBulkDisbursement = () => {
  const { t } = useTranslation();
  const { success, error: showError } = useToast();

  // State
  const [uploadedFile, setUploadedFile] = useState(null);
  const [parsedRecords, setParsedRecords] = useState([]);
  const [filePreview, setFilePreview] = useState(null);
  const [isUploading, setIsUploading] = useState(false);
  const [isProcessingBulk, setIsProcessingBulk] = useState(false);
  const [bulkPinModalOpen, setBulkPinModalOpen] = useState(false);
  const [checkingPin, setCheckingPin] = useState(false);
  const [setPinPromptOpen, setSetPinPromptOpen] = useState(false);
  const [batchNumber, setBatchNumber] = useState('');
  const [isCalculatingFees, setIsCalculatingFees] = useState(false);
  const [bulkPreviewPage, setBulkPreviewPage] = useState(1);
  const [bulkPreviewItemsPerPage] = useState(10);

  // Use the same service ID fetching as single disbursement
  const { disbursementServiceId } = useDisbursementServices();

  // Calculate fee for a single record
  const calculateFeeForRecord = async (amount, channel) => {
    if (!amount || !disbursementServiceId) {
      return null;
    }

    try {
      // For bulk disbursement, always use 'WALLET' channel for fee checking
      const response = await disbursementService.checkFullPayable({
        amount: amount.toString(),
        channel: 'WALLET',
        serviceId: disbursementServiceId
      });

      if (response.code === '00' && response.data) {
        // Normalize the response to handle both formats
        const data = response.data;
        const feeValue = data.feeApplied || data.fee || '0';
        const baseAmountValue = data.baseAmount || parseFloat(amount);
        const totalValue = data.total || parseFloat(amount);

        return {
          feeApplied: typeof feeValue === 'string' ? parseFloat(feeValue) : feeValue,
          baseAmount: typeof baseAmountValue === 'string' ? parseFloat(baseAmountValue) : baseAmountValue,
          total: typeof totalValue === 'string' ? parseFloat(totalValue) : totalValue,
          feeType: data.feeType || null,
          feeSource: data.feeSource || 'general',
          channel: data.channel || 'WALLET'
        };
      }
    } catch (error) {
      logger.error('Failed to calculate fee:', { error });
    }
    return null;
  };

  // Calculate fees for all records
  const calculateFeesForRecords = async (records) => {
    if (!disbursementServiceId || records.length === 0) {
      return records;
    }

    setIsCalculatingFees(true);
    try {
      const recordsWithFees = await Promise.all(
        records.map(async (record) => {
          const feeData = await calculateFeeForRecord(record.amount, record.channel);
          return {
            ...record,
            feeData
          };
        })
      );
      return recordsWithFees;
    } catch (error) {
      logger.error('Error calculating fees:', { error });
      return records;
    } finally {
      setIsCalculatingFees(false);
    }
  };

  // Download CSV template
  const handleDownloadTemplate = () => {
    const csvContent = generateCSVTemplate();
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', 'bulk_disbursement_template.csv');
    // Position the link off-screen to prevent visual issues
    link.style.position = 'absolute';
    link.style.left = '-9999px';
    link.style.top = '-9999px';
    link.style.opacity = '0';
    link.style.visibility = 'hidden';
    link.style.pointerEvents = 'none';
    document.body.appendChild(link);
    link.click();
    // Clean up after a short delay
    setTimeout(() => {
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
    }, 100);
    success(t('templateDownloaded', { ns: 'disbursements', defaultValue: 'Template downloaded successfully!' }));
  };

  // Handle file upload
  const handleFileUpload = async (event) => {
    const file = event.target.files?.[0] || (event.dataTransfer?.files?.[0]);

    if (!file) { return; }

    // Validate file type
    const allowedTypes = [
      'text/csv',
      'application/vnd.ms-excel',
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    ];

    if (!allowedTypes.includes(file.type) && !file.name.match(/\.(csv|xlsx|xls)$/i)) {
      showError(t('invalidFileType', { ns: 'disbursements' }));
      return;
    }

    const maxSize = 10 * 1024 * 1024;
    if (file.size > maxSize) {
      showError(t('fileSizeExceedsLimit', { ns: 'disbursements' }));
      return;
    }

    setIsUploading(true);
    setUploadedFile(file);

    try {
      const text = await file.text();
      const records = parseBulkDisbursementCSV(text, showError, t);

      // Calculate fees for all records
      const recordsWithFees = await calculateFeesForRecords(records);

      setParsedRecords(recordsWithFees);
      const totalAmount = recordsWithFees.reduce((sum, record) => sum + record.amount, 0);
      const totalFees = recordsWithFees.reduce((sum, record) => sum + (parseFloat(record.feeData?.feeApplied || 0)), 0);
      const totalPayable = recordsWithFees.reduce((sum, record) => sum + (parseFloat(record.feeData?.total || record.amount)), 0);

      setFilePreview({
        filename: file.name,
        size: (file.size / 1024).toFixed(2) + ' KB',
        recordCount: recordsWithFees.length,
        totalAmount,
        totalFees,
        totalPayable,
        currency: recordsWithFees[0]?.currency || 'GHS'
      });

      success(t('fileUploadedSuccessfully', { ns: 'disbursements', count: recordsWithFees.length }));
    } catch (error) {
      logger.error('Error parsing file:', { error });
      showError(error.message || t('errorParsingFile', { ns: 'disbursements' }));
      setUploadedFile(null);
      setParsedRecords([]);
      setFilePreview(null);
    } finally {
      setIsUploading(false);
    }
  };

  // Handle bulk submission
  const handleBulkSubmit = async () => {
    if (parsedRecords.length === 0) {
      showError(t('pleaseUploadFile', { ns: 'disbursements' }));
      return;
    }

    // Validate batch number - must be provided by user
    const finalBatchNumber = batchNumber.trim();
    if (!finalBatchNumber || finalBatchNumber === '') {
      showError('Batch number is required. Please enter a batch number before submitting.');
      return;
    }

    // Check if PIN is set before opening verify PIN modal
    setCheckingPin(true);
    try {
      const resp = await securityService.getAccountSecurity();
      const sec = resp?.data || {};
      const isPinSet = !!(sec.pinSet || sec.hasPin || sec.has_pin || (sec.pin && sec.pin !== null && sec.pin !== 'null'));

      if (!isPinSet) {
        setSetPinPromptOpen(true);
        return;
      }

      // PIN is set, open verify PIN modal
      setBulkPinModalOpen(true);
    } catch (error) {
      logger.error('Error checking PIN status:', { error });
      showError(t('unableToVerifyPin', { ns: 'disbursements' }));
    } finally {
      setCheckingPin(false);
    }
  };

  // Confirm bulk submission after PIN verification
  const confirmBulkSubmitAfterPin = async () => {
    try {
      setIsProcessingBulk(true);
      setBulkPinModalOpen(false);

      // Validate batch number - must be provided by user
      const finalBatchNumber = batchNumber.trim();
      if (!finalBatchNumber || finalBatchNumber === '') {
        throw new Error('Batch number is required. Please enter a batch number before submitting.');
      }

      // Calculate total payable amount (including fees) for display
      const totalPayable = parsedRecords.reduce((sum, record) => {
        return sum + (parseFloat(record.feeData?.total || record.amount));
      }, 0);
      const totalAmount = parsedRecords.reduce((sum, record) => sum + record.amount, 0);

      // Clean records to ensure no unwanted fields are included
      const cleanedRecords = parsedRecords.map(record => {
        const { feeData, ...cleanRecord } = record;

        // Ensure paymentDetails is correctly structured based on channel
        if (cleanRecord.channel === 'BANK') {
          // Preserve bank details
          cleanRecord.paymentDetails = {
            accountNumber: record.paymentDetails?.accountNumber,
            accountName: record.paymentDetails?.accountName,
            paymentMode: record.paymentDetails?.paymentMode,
            bankCode: record.paymentDetails?.bankCode,
            bankbranchCode: record.paymentDetails?.bankbranchCode || record.paymentDetails?.bankBranchCode || ''
          };
        } else {
          // Mobile Money details
          const paymentDetails = {
            momoNumber: record.paymentDetails?.momoNumber || record.paymentDetails?.phone
          };
          // Always add country field for Mobile Money (default to GHA)
          paymentDetails.country = record.paymentDetails?.country || 'GHA';
          cleanRecord.paymentDetails = paymentDetails;
        }
        // Ensure amount is always a valid number
        const originalAmount = record.amount;
        if (originalAmount == null || isNaN(originalAmount) || originalAmount <= 0) {
          throw new Error(`Invalid amount in record with reference: ${record.reference || cleanRecord.reference || 'unknown'}. Amount must be a positive number. Got: ${originalAmount}`);
        }
        cleanRecord.amount = Number(originalAmount);
        cleanRecord.source = 'dashboard'; // Add source field to each record
        return cleanRecord;
      });

      const bulkPayload = {
        batchNumber: finalBatchNumber,
        totalAmount: totalAmount.toString(),
        records: cleanedRecords
      };

      logger.debug('Bulk disbursement payload:', { bulkPayload });

      // Call the bulk disbursement API
      const response = await disbursementService.createBulkDisbursement(bulkPayload, disbursementServiceId);

      logger.debug('Bulk disbursement response:', { response });

      // Check batch status and failed references
      const batchStatus = response?.data?.batch?.status;
      const failedCount = response?.data?.batch?.failedCount || 0;
      const successCount = response?.data?.batch?.successCount || 0;
      const failedReferences = response?.data?.failedReferences || [];

      if (batchStatus === 'FAILED' || failedCount > 0) {
        // Find if any failure was due to insufficient balance (Code 07)
        // Note: The bulk API response might contain errorCode/errorMessage in the record or batch level
        const errorCode = response?.code || response?.data?.batch?.errorCode;
        const responseMessage = (response?.message || response?.data?.batch?.errorMessage || '').toLowerCase();

        const isInsufficientBalance =
          errorCode === '07' ||
          responseMessage.includes('insufficient wallet balance') ||
          responseMessage.includes('insufficient balance');

        if (isInsufficientBalance) {
          throw new Error(t('insufficientBalance', { ns: 'wallet', defaultValue: 'Insufficient wallet balance' }));
        }

        const errorMessage = failedCount === parsedRecords.length
          ? `All ${failedCount} record(s) failed. Failed references: ${failedReferences.join(', ')}. Please check: 1) Mobile Money number format (should be 9 to 15 digits starting with 233), 2) Provider matches the Mobile Money number, 3) Sufficient wallet balance, 4) Valid phone number format.`
          : `${failedCount} of ${parsedRecords.length} record(s) failed. Failed references: ${failedReferences.join(', ')}. Please check the console for details.`;

        throw new Error(errorMessage);
      }

      const totalFees = parsedRecords.reduce((sum, record) => {
        return sum + (parseFloat(record.feeData?.feeApplied || 0));
      }, 0);
      success(t('bulkDisbursementSubmitted', { ns: 'disbursements', batch: finalBatchNumber, count: parsedRecords.length, currency: parsedRecords[0]?.currency || 'GHS', amount: totalPayable.toLocaleString() }) + ` (Amount: ${totalAmount.toLocaleString()}, Fees: ${totalFees.toLocaleString()})`);

      // Reset bulk upload state
      handleCancelBulkUpload();
    } catch (error) {
      // Extract specific error message if available in the error object (e.g., from mutation or API client)
      let specificMessage = error?.response?.data?.message || error?.data?.message || error?.message;
      
      // Improve error message for duplicate batch number
      if (specificMessage && (specificMessage.toLowerCase().includes('duplicate') || specificMessage.toLowerCase().includes('batch number already exists'))) {
        specificMessage = 'The batch number you entered already exists. Please use a unique batch number for this disbursement.';
      }
      
      showError(specificMessage || 'Failed to submit bulk disbursement. Please try again.');
    } finally {
      setIsProcessingBulk(false);
    }
  };

  // Cancel bulk upload
  const handleCancelBulkUpload = () => {
    setUploadedFile(null);
    setParsedRecords([]);
    setFilePreview(null);
    setBatchNumber('');
    setBulkPreviewPage(1);
  };

  // Pagination handlers
  const handleBulkPreviewPageChange = (page) => {
    setBulkPreviewPage(page);
  };

  return {
    // State
    uploadedFile,
    parsedRecords,
    filePreview,
    isUploading,
    isProcessingBulk,
    bulkPinModalOpen,
    checkingPin,
    setPinPromptOpen,
    disbursementServiceId,
    batchNumber,
    setBatchNumber,
    isCalculatingFees,
    bulkPreviewPage,
    bulkPreviewItemsPerPage,

    // Actions
    handleDownloadTemplate,
    handleFileUpload,
    handleBulkSubmit,
    confirmBulkSubmitAfterPin,
    handleCancelBulkUpload,
    handleBulkPreviewPageChange,

    // Modal controls
    setBulkPinModalOpen,
    setSetPinPromptOpen
  };
};

