import { z } from 'zod';
import {
  trimAndRequire,
  numericString,
  phoneNumberSchema,
} from './helpers';
import {
  createNarrationSchema,
  createAmountPatternSchema,
  createCurrencySchema,
  createReferenceSchema,
} from './commonSchemas';

/**
 * Factory for the single disbursement form validation schema so translations can be injected.
 *
 * @param {import("react-i18next").TFunction} t - i18n translation function scoped to disbursements namespace.
 */
export const createSingleDisbursementSchema = (t) =>
  z
    .object({
      // Name fields - conditionally required based on payment method
      firstName: z.string().optional(),
      surname: z.string().optional(),
      fullName: z.string().optional(),
      countryCode: trimAndRequire(
        t('countryCodeRequired', { ns: 'disbursements', defaultValue: 'Country code is required' })
      ),
      phoneNumber: phoneNumberSchema(
        t('phoneNumberInvalid', { ns: 'disbursements', defaultValue: 'Enter a valid phone number' }),
        t('phoneNumberLength', {
          ns: 'disbursements',
          defaultValue: 'Phone number must be between 7 and 15 digits',
        })
      ),
      amount: createAmountPatternSchema(t, {
        namespace: 'disbursements',
        min: 0,
        max: 1_000_000_000,
        allowZero: false,
      }),
      paymentMethod: z.enum(['Mobile Money', 'Wallet', 'MOMO', 'WALLET', 'Bank', 'BANK'], {
        errorMap: () => ({
          message: t('paymentMethodRequired', {
            ns: 'disbursements',
            defaultValue: 'Select a valid payment method',
          }),
        }),
      }),
      purpose: z.string().optional(), // Made optional, will be conditionally required
      provider: z.string().optional(),
      bankName: z.string().optional(),
      differentMomoNumber: z.string().optional(),
      differentMomoCountryCode: z.string().optional(),
      // Bank fields
      accountNumber: z.string().optional(),
      accountName: z.string().optional(),
      bankCode: z.string().optional(),
      bankbranchCode: z.string().optional(),
    })
    .superRefine((data, ctx) => {
      const { paymentMethod, provider, firstName, surname, fullName, purpose, accountNumber, accountName, bankName, bankCode } = data;
      const isWallet = paymentMethod === 'Wallet' || paymentMethod === 'WALLET';
      const isMobileMoney = paymentMethod === 'Mobile Money' || paymentMethod === 'MOMO';
      const isBank = paymentMethod === 'Bank' || paymentMethod === 'BANK';

      // For wallet payments: fullName is optional
      if (isWallet && fullName?.trim().length > 100) {
        ctx.addIssue({
          path: ['fullName'],
          code: z.ZodIssueCode.custom,
          message: t('fullNameTooLong', {
            ns: 'disbursements',
            defaultValue: 'Full name cannot exceed 100 characters',
          }),
        });
      }

      // For mobile money payments: require firstName and surname
      if (isMobileMoney) {
        if (!firstName || !firstName.trim()) {
          ctx.addIssue({
            path: ['firstName'],
            code: z.ZodIssueCode.custom,
            message: t('firstNameRequired', {
              ns: 'disbursements',
              defaultValue: 'First name is required',
            }),
          });
        } else if (firstName.trim().length > 50) {
          ctx.addIssue({
            path: ['firstName'],
            code: z.ZodIssueCode.custom,
            message: t('firstNameTooLong', {
              ns: 'disbursements',
              defaultValue: 'First name cannot exceed 50 characters',
            }),
          });
        }

        if (!surname || !surname.trim()) {
          ctx.addIssue({
            path: ['surname'],
            code: z.ZodIssueCode.custom,
            message: t('surnameRequired', {
              ns: 'disbursements',
              defaultValue: 'Surname is required',
            }),
          });
        } else if (surname.trim().length > 50) {
          ctx.addIssue({
            path: ['surname'],
            code: z.ZodIssueCode.custom,
            message: t('surnameTooLong', {
              ns: 'disbursements',
              defaultValue: 'Surname cannot exceed 50 characters',
            }),
          });
        }

        if (!provider?.trim()) {
          ctx.addIssue({
            path: ['provider'],
            code: z.ZodIssueCode.custom,
            message: t('selectProvider', { ns: 'disbursements' }),
          });
        }

        // Purpose is required for mobile money payments
        if (!purpose?.trim()) {
          ctx.addIssue({
            path: ['purpose'],
            code: z.ZodIssueCode.custom,
            message: t('purposeRequired', {
              ns: 'disbursements',
              defaultValue: 'Purpose/narration is required',
            }),
          });
        } else if (purpose.trim().length > 500) {
          ctx.addIssue({
            path: ['purpose'],
            code: z.ZodIssueCode.custom,
            message: t('purposeTooLong', {
              ns: 'disbursements',
              defaultValue: 'Purpose/narration cannot exceed 500 characters',
            }),
          });
        }
      }

      // Purpose is NOT required for wallet payments (same as TransferFundsModal)
      // Wallet transfers don't use purpose/narration field

      // For bank payments: require accountNumber, accountName, bankName, firstName, surname, and purpose
      if (isBank) {
        if (!firstName || !firstName.trim()) {
          ctx.addIssue({
            path: ['firstName'],
            code: z.ZodIssueCode.custom,
            message: t('firstNameRequired', {
              ns: 'disbursements',
              defaultValue: 'First name is required',
            }),
          });
        } else if (firstName.trim().length > 50) {
          ctx.addIssue({
            path: ['firstName'],
            code: z.ZodIssueCode.custom,
            message: t('firstNameTooLong', {
              ns: 'disbursements',
              defaultValue: 'First name cannot exceed 50 characters',
            }),
          });
        }

        if (!surname || !surname.trim()) {
          ctx.addIssue({
            path: ['surname'],
            code: z.ZodIssueCode.custom,
            message: t('surnameRequired', {
              ns: 'disbursements',
              defaultValue: 'Surname is required',
            }),
          });
        } else if (surname.trim().length > 50) {
          ctx.addIssue({
            path: ['surname'],
            code: z.ZodIssueCode.custom,
            message: t('surnameTooLong', {
              ns: 'disbursements',
              defaultValue: 'Surname cannot exceed 50 characters',
            }),
          });
        }

        if (!accountNumber || !accountNumber.trim()) {
          ctx.addIssue({
            path: ['accountNumber'],
            code: z.ZodIssueCode.custom,
            message: t('accountNumberRequired', {
              ns: 'disbursements',
              defaultValue: 'Account number is required',
            }),
          });
        }

        if (!accountName || !accountName.trim()) {
          ctx.addIssue({
            path: ['accountName'],
            code: z.ZodIssueCode.custom,
            message: t('accountNameRequired', {
              ns: 'disbursements',
              defaultValue: 'Account name is required',
            }),
          });
        }

        if (!bankName || !bankName.trim()) {
          ctx.addIssue({
            path: ['bankName'],
            code: z.ZodIssueCode.custom,
            message: t('bankNameRequired', {
              ns: 'disbursements',
              defaultValue: 'Bank name is required',
            }),
          });
        }

        if (!bankCode || !bankCode.trim()) {
          ctx.addIssue({
            path: ['bankCode'],
            code: z.ZodIssueCode.custom,
            message: t('bankCodeRequired', {
              ns: 'disbursements',
              defaultValue: 'Bank code is required',
            }),
          });
        }

        // Purpose is required for bank payments
        if (!purpose?.trim()) {
          ctx.addIssue({
            path: ['purpose'],
            code: z.ZodIssueCode.custom,
            message: t('purposeRequired', {
              ns: 'disbursements',
              defaultValue: 'Purpose/narration is required',
            }),
          });
        } else if (purpose.trim().length > 500) {
          ctx.addIssue({
            path: ['purpose'],
            code: z.ZodIssueCode.custom,
            message: t('purposeTooLong', {
              ns: 'disbursements',
              defaultValue: 'Purpose/narration cannot exceed 500 characters',
            }),
          });
        }
      }
    });


