/**
 * Disbursements Page
 * 
 * Handles both single and bulk payment disbursements. Supports file upload
 * for bulk payments, validates transactions, and processes payments through
 * Mobile Money. Includes PIN verification for security and transaction history.
 */

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { createPortal } from 'react-dom';
import { useNavigate } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { FaArrowUp } from 'react-icons/fa';
import { useToast } from '@/app/providers/ToastContext.jsx';
import { LoadingSpinner, Pagination } from '@/shared/components';
import CustomSelect from '@/shared/components/CustomSelect.jsx';
import '/styles/index.css';
import { DisbursementTabs, SingleDisbursementForm } from '@/features/disbursements/components';
import DisbursementDetailsModal from '@/features/disbursements/components/DisbursementDetailsModal.jsx';
import { VerifyPinModal, SetPinPromptModal } from '@/features/settings/components';
import { useSearch } from '@/app/providers/SearchContext.jsx';
import { logger } from '@/shared/utils/logger.js';
import { useTheme } from '@/app/providers/ThemeContext.jsx';
import { useBulkDisbursement } from '@/features/disbursements/hooks/useBulkDisbursement.js';
import BulkDisbursementUploadSection from '@/features/disbursements/components/BulkDisbursementUploadSection.jsx';
import BulkDisbursementPreviewSection from '@/features/disbursements/components/BulkDisbursementPreviewSection.jsx';
import BulkDisbursementBatchInput from '@/features/disbursements/components/BulkDisbursementBatchInput.jsx';
import BulkDisbursementActions from '@/features/disbursements/components/BulkDisbursementActions.jsx';
import { useQuery } from '@/shared/hooks';
import { queryKeys } from '@/shared/utils/queryKeys.js';
import { disbursementService } from '@/features/disbursements/services';
import { securityService } from '@/features/settings/services';

export default function Disbursements() {
  const { t } = useTranslation();
  const navigate = useNavigate();
  const { success, error: showError } = useToast();
  const { effectiveTheme } = useTheme();
  const [currentPage, setCurrentPage] = useState(1);
  const [statusFilter, setStatusFilter] = useState('');
  const [itemsPerPage] = useState(20); // matches API default limit
  const { searchTerm, updateSearch } = useSearch();
  const [activeTab, setActiveTab] = useState('single');
  const [windowWidth, setWindowWidth] = useState(typeof window !== 'undefined' ? window.innerWidth : 1024);
  const isMobile = windowWidth <= 768;
  const isTablet = windowWidth > 768 && windowWidth <= 1024;

  // Set default date range to last 3 months
  const [startDate, setStartDate] = useState(() => {
    const d = new Date();
    d.setMonth(d.getMonth() - 3);
    return d.toISOString().split('T')[0];
  });
  const [endDate, setEndDate] = useState(() => {
    return new Date().toISOString().split('T')[0];
  });

  const [isCheckingPin, setIsCheckingPin] = useState(true);
  const [showSetPinPrompt, setShowSetPinPrompt] = useState(false);
  const [selectedPayout, setSelectedPayout] = useState(null);
  const [detailsOpen, setDetailsOpen] = useState(false);

  // Use bulk disbursement hook
  const bulkDisbursement = useBulkDisbursement();

  const shortenId = (value) => {
    if (!value) { return '—'; }
    const str = String(value);
    if (str.length <= 14) { return str; }
    return `${str.slice(0, 8)}…${str.slice(-4)}`;
  };


  useEffect(() => {
    let resizeTimer = null;
    const handleResize = () => {
      // Debounce resize events to prevent excessive re-renders
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
      resizeTimer = setTimeout(() => {
        setWindowWidth(window.innerWidth);
      }, 100);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
      if (resizeTimer) {
        clearTimeout(resizeTimer);
      }
    };
  }, []);

  // Check PIN status on mount
  useEffect(() => {
    // Safety: clear any stale isLoggingOut flag that would block all API calls
    if (typeof localStorage !== 'undefined' && localStorage.getItem('isLoggingOut') === 'true') {
      logger.warn('[Disbursements] Stale isLoggingOut flag detected — clearing it so queries can fire');
      localStorage.removeItem('isLoggingOut');
    }

    const checkPinStatus = async () => {
      // Check cache first
      const cachedPinStatus = sessionStorage.getItem('hasPinSet');
      if (cachedPinStatus === 'true') {
        setIsCheckingPin(false);
        return;
      }

      try {
        const resp = await securityService.getAccountSecurity();
        const sec = resp?.data || resp || {};
        const isPinSet = !!(
          sec.pinSet ||
          sec.hasPin ||
          sec.has_pin ||
          (sec.pin && sec.pin !== null && sec.pin !== 'null')
        );

        if (!isPinSet) {
          setShowSetPinPrompt(true);
        } else {
          // Cache successful PIN setup state
          sessionStorage.setItem('hasPinSet', 'true');
        }
      } catch (err) {
        logger.error('Failed to check PIN status', { error: err });
        // Optional: show error toast or just allow access if check fails (fail open vs fail closed)
        // For now, we'll log it and allow access so we don't block users due to API errors
      } finally {
        setIsCheckingPin(false);
      }
    };

    checkPinStatus();
  }, []);

  // Use React Query to fetch disbursements from auth service
  // Endpoint: /auth/get-disbursements?start_date=YYYY-MM-DD&end_date=YYYY-MM-DD&page=N
  const { data: paymentsData, isLoading: isLoadingPayments } = useQuery({
    queryKey: [...queryKeys.disbursements.list(startDate, endDate), currentPage],
    endpoint: `/auth/get-disbursements?start_date=${startDate}&end_date=${endDate}&page=${currentPage}`,
    enabled: true,
    staleTime: 30 * 1000,
    refetchOnWindowFocus: false,
  });

  // Debug: Log the date range being used
  logger.debug('Disbursements API call with date range:', { startDate, endDate, page: currentPage });

  // Server-side pagination metadata from API response
  // Response shape: { code, data: { data: [...], pagination: { page, limit, total, totalPages, hasMore } } }
  const serverPagination = paymentsData?.data?.pagination || null;
  const totalServerPages = serverPagination?.totalPages || 1;
  const totalServerItems = serverPagination?.total || 0;

  // Log raw response to debug table not filling
  useEffect(() => {
    if (paymentsData) {
      logger.debug('[Disbursements] Raw API response:', { paymentsData });
      console.log('[Disbursements] Raw API response:', paymentsData);
    }
  }, [paymentsData]);

  // Transform API response to match table structure
  const payoutHistory = useMemo(() => {
    // New response shape: data.data is the array
    const rawData = Array.isArray(paymentsData?.data?.data)
      ? paymentsData.data.data
      : (Array.isArray(paymentsData?.data) ? paymentsData.data : []);

    if (!Array.isArray(rawData) || rawData.length === 0) {
      logger.debug('payoutHistory: no data', { paymentsData });
      return [];
    }

    logger.debug(`Processing ${rawData.length} transactions from API`);

    return rawData.map((item) => {
      const rawDate = item.created_at || item.createdAt;
      const date = rawDate
        ? new Date(rawDate).toLocaleDateString('en-US', {
            year: 'numeric', month: 'short', day: 'numeric',
          })
        : '';

      const formattedAmount = item.amount
        ? `${item.currency || 'GHS'} ${parseFloat(item.amount).toFixed(2)}`
        : '';

      const rawStatus = (item.status || '').toLowerCase();
      const statusMap = {
        success: 'success', succeeded: 'success',
        failed: 'failed', error: 'failed', cancelled: 'failed', rejected: 'failed',
        pending: 'pending', processing: 'pending', sent: 'pending',
      };
      const status = statusMap[rawStatus] || rawStatus;

      // New API uses service_type (disbursement, collection, wallet_transfer)
      // and transaction_type (CREDIT, DEBIT)
      const serviceType = (item.service_type || '').toLowerCase();
      const transactionType = (item.transaction_type || '').toUpperCase();

      // Map service_type to a display channel type
      const channel = (item.channel || '').toUpperCase() || '—';

      // Use description as narration (new field name)
      const narration = item.description || item.narration || '—';

      return {
        id: item.id,
        reference: item.reference || item.system_reference || '—',
        transactionId: item.system_reference || item.id,
        customerId: item.customer_id || null,
        userType: item.user_type || null,
        amount: formattedAmount,
        rawAmount: item.amount,
        currency: item.currency || 'GHS',
        date,
        status,
        channel,
        serviceType,
        transactionType,
        narration,
        itemType: serviceType,
        createdAt: rawDate,
        updatedAt: item.updated_at || item.updatedAt,
        source: item.source || null,
        balanceBefore: item.balance_before || null,
        balanceAfter: item.balance_after || null,
        settlementStatus: item.settlement_status || null,
        serviceName: item.services?.name || serviceType,
        walletAddress: item.wallet_address || null,
      };
    });
  }, [paymentsData]);

  const filteredPayouts = useMemo(() => {
    let list = payoutHistory;

    if (statusFilter) {
      list = list.filter((payout) => payout.status === statusFilter);
    }

    if (!searchTerm.trim()) {
      return list;
    }

    const term = searchTerm.toLowerCase();
    return list.filter(payout =>
      payout.reference?.toLowerCase().includes(term) ||
      payout.narration?.toLowerCase().includes(term) ||
      payout.transactionId?.toLowerCase().includes(term) ||
      (payout.customerId ? String(payout.customerId).toLowerCase().includes(term) : false) ||
      String(payout.rawAmount || '').toLowerCase().includes(term) ||
      payout.status?.toLowerCase().includes(term) ||
      payout.channel?.toLowerCase().includes(term) ||
      payout.serviceType?.toLowerCase().includes(term) ||
      String(payout.date || '').toLowerCase().includes(term)
    );
  }, [payoutHistory, searchTerm, statusFilter]);

  // Pagination is server-driven — use metadata from API response
  // currentPayouts is the full page returned by the server (already paginated)
  const currentPayouts = filteredPayouts;


  const handleOpenDetails = useCallback((payout) => {
    if (!payout) { return; }
    setSelectedPayout(payout);
    setDetailsOpen(true);
  }, []);

  const handleCloseDetails = useCallback(() => {
    setDetailsOpen(false);
    setSelectedPayout(null);
  }, []);

  const handleTabChange = useCallback((tab) => {
    if (tab === activeTab) { return; }
    setActiveTab(tab);
  }, [activeTab]);

  const handleDateRangeChange = useCallback((type, value) => {
    if (type === 'start') {
      setStartDate(value);
    } else {
      setEndDate(value);
    }
  }, []);

  // Reset to first page when date range, search or status filter changes
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter, startDate, endDate]);

  const handlePageChange = useCallback((page) => {
    setCurrentPage(page);
  }, []);

  // Pagination logic for bulk disbursement preview
  const bulkPreviewStartIndex = (bulkDisbursement.bulkPreviewPage - 1) * bulkDisbursement.bulkPreviewItemsPerPage;
  const bulkPreviewEndIndex = bulkPreviewStartIndex + bulkDisbursement.bulkPreviewItemsPerPage;
  const paginatedParsedRecords = bulkDisbursement.parsedRecords.slice(bulkPreviewStartIndex, bulkPreviewEndIndex);

  return (
    <div className="stack-vertical">
      {/* Tabs for Single vs Bulk */}
      <div className="invoices-card form-card" style={{
        maxWidth: isMobile ? '100%' : isTablet ? '95%' : '900px',
        width: '100%',
        margin: '0 auto',
        padding: isMobile ? '16px' : '24px'
      }}>
        <div style={{
          marginBottom: isMobile ? '16px' : '24px',
          paddingBottom: isMobile ? '12px' : '16px',
          borderBottom: '1px solid var(--border-primary)'
        }} data-tour="disbursements-tabs">
          <DisbursementTabs activeTab={activeTab} setActiveTab={handleTabChange} />
          <h3 style={{
            fontSize: isMobile ? '18px' : '20px',
            marginTop: isMobile ? '12px' : '16px'
          }}>
            {activeTab === 'single' ? t('initiateSinglePayout', { ns: 'disbursements' }) : t('bulkDisbursement', { ns: 'disbursements' })}
          </h3>
          {activeTab === 'bulk' && (
            <p style={{
              color: 'var(--text-muted)',
              marginTop: '8px',
              fontSize: isMobile ? '12px' : '14px',
              lineHeight: '1.5'
            }}>
              {t('bulkDisbursementDescription', { ns: 'disbursements' })}
            </p>
          )}
        </div>

        {/* Single Disbursement Form */}
        {activeTab === 'single' && (
          <div data-tour="disbursements-form">
            <SingleDisbursementForm />
          </div>
        )}

        {/* Bulk Disbursement Section */}
        {activeTab === 'bulk' && (
          <div style={{ padding: isMobile ? '0' : '24px 0' }} data-tour="disbursements-form">
            {!bulkDisbursement.filePreview ? (
              <BulkDisbursementUploadSection
                isUploading={bulkDisbursement.isUploading}
                onFileUpload={bulkDisbursement.handleFileUpload}
                onDownloadTemplate={bulkDisbursement.handleDownloadTemplate}
                isMobile={isMobile}
                isTablet={isTablet}
              />
            ) : (
              <>
                <BulkDisbursementPreviewSection
                  filePreview={bulkDisbursement.filePreview}
                  isCalculatingFees={bulkDisbursement.isCalculatingFees}
                  onRemoveFile={bulkDisbursement.handleCancelBulkUpload}
                  parsedRecords={bulkDisbursement.parsedRecords}
                  paginatedParsedRecords={paginatedParsedRecords}
                  bulkPreviewStartIndex={bulkPreviewStartIndex}
                  bulkPreviewPage={bulkDisbursement.bulkPreviewPage}
                  bulkPreviewItemsPerPage={bulkDisbursement.bulkPreviewItemsPerPage}
                  onPageChange={bulkDisbursement.handleBulkPreviewPageChange}
                  isMobile={isMobile}
                  isTablet={isTablet}
                />

                {bulkDisbursement.parsedRecords.length > 0 && (
                  <BulkDisbursementBatchInput
                    batchNumber={bulkDisbursement.batchNumber}
                    onBatchNumberChange={bulkDisbursement.setBatchNumber}
                    isMobile={isMobile}
                  />
                )}

                <BulkDisbursementActions
                  onCancel={bulkDisbursement.handleCancelBulkUpload}
                  onSubmit={bulkDisbursement.handleBulkSubmit}
                  isProcessing={bulkDisbursement.isProcessingBulk}
                  isDisabled={bulkDisbursement.isProcessingBulk || bulkDisbursement.parsedRecords.length === 0 || bulkDisbursement.isCalculatingFees || !bulkDisbursement.batchNumber.trim()}
                  isMobile={isMobile}
                />

                {/* Bulk PIN Modal */}
                {bulkDisbursement.bulkPinModalOpen && (
                  <VerifyPinModal
                    open={bulkDisbursement.bulkPinModalOpen}
                    onClose={() => bulkDisbursement.setBulkPinModalOpen(false)}
                    onVerified={bulkDisbursement.confirmBulkSubmitAfterPin}
                  />
                )}

                {/* Set PIN Prompt Modal */}
                {bulkDisbursement.setPinPromptOpen && (
                  <SetPinPromptModal
                    open={bulkDisbursement.setPinPromptOpen}
                    onClose={() => bulkDisbursement.setSetPinPromptOpen(false)}
                  />
                )}

                {/* Bulk Processing Loading Overlay - Rendered via Portal */}
                {bulkDisbursement.isProcessingBulk && createPortal(
                  <div
                    style={{
                      position: 'fixed',
                      top: 0,
                      left: 0,
                      right: 0,
                      bottom: 0,
                      width: '100vw',
                      height: '100vh',
                      backgroundColor: effectiveTheme === 'dark'
                        ? 'rgba(0, 0, 0, 0.85)'
                        : 'rgba(0, 0, 0, 0.5)',
                      backdropFilter: 'blur(4px)',
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      zIndex: 99999,
                      margin: 0,
                      padding: 0,
                    }}
                  >
                    <div
                      style={{
                        backgroundColor: effectiveTheme === 'dark'
                          ? '#141414'
                          : 'var(--card)',
                        borderRadius: '16px',
                        padding: '48px',
                        boxShadow: 'var(--shadow-xl)',
                        border: '1px solid var(--border-primary)',
                        display: 'flex',
                        flexDirection: 'column',
                        alignItems: 'center',
                        justifyContent: 'center',
                        minWidth: '120px',
                        minHeight: '120px',
                      }}
                    >
                      <LoadingSpinner size="large" />
                      <p style={{ marginTop: '16px', color: 'var(--text-primary)', fontSize: '16px', fontWeight: '600' }}>
                        Processing bulk disbursement...
                      </p>
                    </div>
                  </div>,
                  document.body
                )}
              </>
            )}
          </div>
        )}
      </div>

      {/* Payout History */}
      <div className="invoices-card" data-tour="disbursements-list">
        <div className="card-head">
          <h3>{t('payoutHistoryAndApprovals', { ns: 'disbursements' })}</h3>
          <div className="head-actions" style={{
            display: 'flex',
            gap: '8px',
            flexWrap: isMobile ? 'wrap' : 'nowrap',
            alignItems: 'center'
          }}>
            <div style={{
              display: 'flex',
              flexDirection: isMobile ? 'column' : 'row',
              justifyContent: 'space-between',
              alignItems: isMobile ? 'stretch' : 'center',
              marginBottom: '20px',
              gap: '16px'
            }}>
              <h2 style={{
                margin: 0,
                fontSize: '1.25rem',
                fontWeight: '600',
                color: 'var(--text-primary)'
              }}>
                {t('payoutHistory', { ns: 'disbursements', defaultValue: 'Payout History' })}
              </h2>

              <div style={{
                display: 'flex',
                gap: '12px',
                flexWrap: isMobile ? 'wrap' : 'nowrap',
                alignItems: 'center'
              }}>
                {/* Date Range Filters - Default 2 weeks */}
                <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                  <input
                    type="date"
                    value={startDate}
                    onChange={(e) => handleDateRangeChange('start', e.target.value)}
                    style={{
                      fontSize: '0.9rem',
                      padding: '10px 12px',
                      border: '1px solid var(--border-primary)',
                      borderRadius: '6px',
                      backgroundColor: 'var(--card)',
                      color: 'var(--text-primary)'
                    }}
                  />
                  <span style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>to</span>
                  <input
                    type="date"
                    value={endDate}
                    onChange={(e) => handleDateRangeChange('end', e.target.value)}
                    style={{
                      fontSize: '0.9rem',
                      padding: '10px 12px',
                      border: '1px solid var(--border-primary)',
                      borderRadius: '6px',
                      backgroundColor: 'var(--card)',
                      color: 'var(--text-primary)'
                    }}
                  />
                </div>

                <CustomSelect
                  name="statusFilter"
                  value={statusFilter}
                  onChange={(e) => setStatusFilter(e.target.value)}
                  options={[
                    { value: '', label: t('allStatus', { ns: 'disbursements' }) },
                    { value: 'success', label: t('success', { ns: 'disbursements', defaultValue: 'Success' }) },
                    { value: 'pending', label: t('pending', { ns: 'disbursements', defaultValue: 'Pending' }) },
                    { value: 'failed', label: t('failed', { ns: 'disbursements', defaultValue: 'Failed' }) }
                  ]}
                  style={{ fontSize: '0.9rem', minWidth: '150px' }}
                />
                <input
                  className="small-search"
                  placeholder={t('searchPayouts', { ns: 'disbursements' })}
                  style={{ fontSize: '0.9rem', padding: '10px 12px' }}
                  value={searchTerm}
                  onChange={(e) => updateSearch(e.target.value)}
                />
              </div>
            </div>
          </div>
        </div>

        {isLoadingPayments ? (
          <div style={{
            padding: '48px 24px',
            textAlign: 'center',
            color: 'var(--text-muted)'
          }}>
            <LoadingSpinner />
            <p style={{ fontSize: '16px', margin: '16px 0 0 0' }}>
              {t('loading', { ns: 'common', defaultValue: 'Loading...' })}
            </p>
          </div>
        ) : currentPayouts.length === 0 ? (
          <div style={{
            padding: '48px 24px',
            textAlign: 'center',
            color: 'var(--text-muted)'
          }}>
            <p style={{ fontSize: '16px', margin: 0 }}>
              {t('noPayoutsFound', { ns: 'disbursements', defaultValue: 'No payout history found' })}
            </p>
          </div>
        ) : (
          <div className="invoices-table-wrapper">
            <table className="invoices-table" key={`page-${currentPage}`}>
              <thead>
                <tr>
                  <th>{t('reference', { ns: 'disbursements', defaultValue: 'Reference' })}</th>
                  <th>{t('narration', { ns: 'disbursements', defaultValue: 'Narration' })}</th>
                  <th>{t('channel', { ns: 'disbursements', defaultValue: 'Channel' })}</th>
                  <th>{t('amount', { ns: 'disbursements' })}</th>
                  <th>{t('date', { ns: 'disbursements' })}</th>
                  <th>{t('status', { ns: 'disbursements' })}</th>
                </tr>
              </thead>
              <tbody>
                {currentPayouts.map((payout) => (
                  <tr
                    key={payout.id}
                    onClick={() => handleOpenDetails(payout)}
                    style={{ cursor: 'pointer' }}
                    tabIndex={0}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault();
                        handleOpenDetails(payout);
                      }
                    }}
                  >
                    <td className="table-strong" data-label={t('reference', { ns: 'disbursements', defaultValue: 'Reference' })}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                        <span className="tx-flow-icon tx-flow-icon--out tx-flow-icon--sm" title="Money Out" aria-label="Money Out">
                          <FaArrowUp aria-hidden="true" />
                        </span>
                        <span style={{ fontSize: '0.875rem', fontWeight: '500' }}>{payout.reference}</span>
                      </div>
                    </td>
                    <td data-label={t('narration', { ns: 'disbursements', defaultValue: 'Narration' })}>
                      <div style={{ fontSize: '0.875rem', color: 'var(--text-primary)', maxWidth: '160px', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }} title={payout.narration}>
                        {payout.narration}
                      </div>
                    </td>
                    <td data-label={t('channel', { ns: 'disbursements', defaultValue: 'Channel' })}>
                      {(() => {
                        const ch = (payout.channel || '').toUpperCase();
                        const serviceType = (payout.serviceType || '').toLowerCase();
                        const isDark = effectiveTheme === 'dark';

                        const styleMap = {
                          MOBILE_MONEY: {
                            bg: isDark ? 'rgba(245, 158, 11, 0.15)' : 'rgba(245, 158, 11, 0.10)',
                            color: isDark ? '#fbbf24' : '#92400e',
                            border: isDark ? 'rgba(245, 158, 11, 0.35)' : 'rgba(245, 158, 11, 0.40)',
                            label: 'Mobile Money',
                            dotColor: '#f59e0b',
                          },
                          WALLET: {
                            bg: isDark ? 'rgba(59, 130, 246, 0.15)' : 'rgba(59, 130, 246, 0.10)',
                            color: isDark ? '#93c5fd' : '#1e40af',
                            border: isDark ? 'rgba(59, 130, 246, 0.35)' : 'rgba(59, 130, 246, 0.40)',
                            label: 'Wallet',
                            dotColor: '#3b82f6',
                          },
                          BANK: {
                            bg: isDark ? 'rgba(16, 185, 129, 0.15)' : 'rgba(16, 185, 129, 0.10)',
                            color: isDark ? '#6ee7b7' : '#065f46',
                            border: isDark ? 'rgba(16, 185, 129, 0.35)' : 'rgba(16, 185, 129, 0.40)',
                            label: 'Bank Transfer',
                            dotColor: '#10b981',
                          },
                          UTILITY: {
                            bg: isDark ? 'rgba(249, 115, 22, 0.15)' : 'rgba(249, 115, 22, 0.10)',
                            color: isDark ? '#fdba74' : '#9a3412',
                            border: isDark ? 'rgba(249, 115, 22, 0.35)' : 'rgba(249, 115, 22, 0.40)',
                            label: 'Utility',
                            dotColor: '#f97316',
                          },
                          COLLECTION: {
                            bg: isDark ? 'rgba(139, 92, 246, 0.15)' : 'rgba(139, 92, 246, 0.10)',
                            color: isDark ? '#c4b5fd' : '#5b21b6',
                            border: isDark ? 'rgba(139, 92, 246, 0.35)' : 'rgba(139, 92, 246, 0.40)',
                            label: 'Collection',
                            dotColor: '#8b5cf6',
                          },
                        };

                        // Prefer channel for display, fall back to service_type
                        const lookupKey = ch || (serviceType === 'wallet_transfer' ? 'WALLET' : serviceType.toUpperCase());
                        const cfg = styleMap[lookupKey] || {
                          bg: isDark ? 'rgba(148, 163, 184, 0.12)' : 'rgba(100, 116, 139, 0.08)',
                          color: isDark ? '#94a3b8' : '#475569',
                          border: isDark ? 'rgba(148, 163, 184, 0.25)' : 'rgba(100, 116, 139, 0.25)',
                          label: ch ? ch.replace(/_/g, ' ') : (serviceType.replace(/_/g, ' ') || '—'),
                          dotColor: isDark ? '#64748b' : '#94a3b8',
                        };

                        return (
                          <span style={{
                            display: 'inline-flex',
                            alignItems: 'center',
                            gap: '6px',
                            padding: '3px 10px',
                            borderRadius: '9999px',
                            fontSize: '0.72rem',
                            fontWeight: '600',
                            background: cfg.bg,
                            color: cfg.color,
                            border: `1px solid ${cfg.border}`,
                            letterSpacing: '0.02em',
                            whiteSpace: 'nowrap',
                            lineHeight: '1.6',
                          }}>
                            <span style={{
                              width: '6px',
                              height: '6px',
                              borderRadius: '50%',
                              backgroundColor: cfg.dotColor,
                              flexShrink: 0,
                            }} />
                            {cfg.label}
                          </span>
                        );
                      })()}
                    </td>
                    <td className="table-amount" data-label={t('amount', { ns: 'disbursements' })}>
                      <span style={{ fontSize: '0.875rem', fontWeight: '600' }}>{payout.amount}</span>
                    </td>
                    <td data-label={t('date', { ns: 'disbursements' })}>
                      <span style={{ fontSize: '0.875rem', color: 'var(--text-primary)' }}>{payout.date}</span>
                    </td>
                    <td data-label={t('status', { ns: 'disbursements' })}>
                      {(() => {
                        // Normalize status to lowercase for consistent matching
                        const normalizedStatus = (payout.status || '').toLowerCase();

                        // Only support success, pending, and failed statuses
                        const statusConfig = {
                          success: { class: 'paid', label: t('success', { ns: 'disbursements', defaultValue: 'Success' }) },
                          failed: { class: 'overdue', label: t('failed', { ns: 'disbursements', defaultValue: 'Failed' }) },
                          pending: { class: 'sent', label: t('pending', { ns: 'disbursements', defaultValue: 'Pending' }) }
                        };

                        // Map other statuses to the three supported ones
                        const statusMapping = {
                          'success': 'success',
                          'succeeded': 'success',
                          'failed': 'failed',
                          'error': 'failed',
                          'cancelled': 'failed',
                          'rejected': 'failed',
                          'pending': 'pending',
                          'processing': 'pending',
                          'sent': 'pending',
                          'unknown': 'pending'
                        };

                        // Map the status to one of the supported ones
                        const mappedStatus = statusMapping[normalizedStatus] || normalizedStatus;
                        const config = statusConfig[mappedStatus] || statusConfig.pending;

                        return (
                          <span
                            className={`chip ${config.class}`}
                            style={{ fontSize: '0.85rem', padding: '6px 12px' }}
                          >
                            {config.label}
                          </span>
                        );
                      })()}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}

        {/* Pagination Component — server-driven */}
        {totalServerItems > 0 && (
          <Pagination
            currentPage={currentPage}
            totalItems={totalServerItems}
            itemsPerPage={itemsPerPage}
            onPageChange={handlePageChange}
            showInfo={true}
          />
        )}
      </div>

      {/* Set PIN Prompt Modal - Page Level */}
      {showSetPinPrompt && (
        <SetPinPromptModal
          open={showSetPinPrompt}
          onClose={() => {
            setShowSetPinPrompt(false);
            navigate('/dashboard'); // Redirect to dashboard if they refuse to set PIN
          }}
        />
      )}

      {/* Loading Overlay for PIN Check */}
      {isCheckingPin && createPortal(
        <div style={{
          position: 'fixed',
          top: 0,
          left: 0,
          right: 0,
          bottom: 0,
          backgroundColor: 'var(--bg-primary)', // Opaque background to hide content while checking
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          zIndex: 10003
        }}>
          <div style={{
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            justifyContent: 'center',
          }}>
            <LoadingSpinner size="large" />
            <p style={{ marginTop: '16px', color: 'var(--text-muted)' }}>
              {t('verifyingSecurity', { ns: 'common', defaultValue: 'Verifying security settings...' })}
            </p>
          </div>
        </div>,
        document.body
      )}

      {/* View more modal for payout history */}
      <DisbursementDetailsModal
        open={detailsOpen}
        onClose={handleCloseDetails}
        payout={selectedPayout}
      />
    </div>
  );
}
